import "@mormlayer/components/ui/basetoast.css";

import ToastLoadingIcon from "@mormlayer/components/ui/ToastLoadingIcon";

import { ComponentDocPage } from "../layout/ComponentDocPage";
import { DocSection } from "../layout/DocSection";
import { PreviewCanvas } from "../layout/PreviewCanvas";
import { VariantGrid, VariantTile } from "../layout/VariantGrid";

const SCALE_VARIANTS = [
  { label: "Default (18px)", scale: 1 },
  { label: "1.33× (24px)", scale: 1.33 },
  { label: "1.78× (32px)", scale: 1.78 },
  { label: "2.67× (48px)", scale: 2.67 },
] as const;

export function ToastLoadingIconPage(): JSX.Element {
  return (
    <ComponentDocPage
      title="Toast loading icon"
      description="Animated Morpheum logo fill used in toast loading states. Ghost layer plus clip-path fill animation."
    >
      <DocSection
        title="Default"
        description="Animated loading logo at toast size."
      >
        <PreviewCanvas minHeight={120}>
          <ToastLoadingIcon />
        </PreviewCanvas>
      </DocSection>

      <DocSection
        title="Animation"
        description="Fill sweeps bottom-to-top on a 1.2s loop with brand glow. Respects prefers-reduced-motion."
      >
        <PreviewCanvas minHeight={160}>
          <div style={{ display: "flex", gap: 24, alignItems: "center" }}>
            <ToastLoadingIcon />
            <ToastLoadingIcon />
            <ToastLoadingIcon />
          </div>
        </PreviewCanvas>
      </DocSection>

      <DocSection title="Scaled variants" description="Scale the fixed 18px toast logo for larger surfaces.">
        <VariantGrid columns={4}>
          {SCALE_VARIANTS.map((variant) => (
            <VariantTile key={variant.label} label={variant.label}>
              <div
                style={{
                  transform: variant.scale === 1 ? undefined : `scale(${variant.scale})`,
                  transformOrigin: "center",
                }}
              >
                <ToastLoadingIcon />
              </div>
            </VariantTile>
          ))}
        </VariantGrid>
      </DocSection>
    </ComponentDocPage>
  );
}
