import React, { Fragment } from "react";
import { Link } from "react-router-dom";

import "./TerminalBreadcrumb.css";

export interface TerminalBreadcrumbSegment {
  label: string;
  to?: string;
  title?: string;
  mono?: boolean;
}

export interface TerminalBreadcrumbProps {
  segments: TerminalBreadcrumbSegment[];
  className?: string;
}

function TerminalBreadcrumb({
  segments,
  className,
}: TerminalBreadcrumbProps): JSX.Element {
  return (
    <p
      className={className ? `terminal-breadcrumb ${className}` : "terminal-breadcrumb"}
      aria-label="Breadcrumb"
    >
      {segments.map((segment, index) => (
        <Fragment key={`${segment.label}-${index}`}>
          {index > 0 ? " › " : null}
          {segment.to ? (
            <Link to={segment.to} title={segment.title}>
              {segment.label}
            </Link>
          ) : segment.mono ? (
            <span className="terminal-breadcrumb-mono" title={segment.title}>
              {segment.label}
            </span>
          ) : segment.title ? (
            <span title={segment.title}>{segment.label}</span>
          ) : (
            segment.label
          )}
        </Fragment>
      ))}
    </p>
  );
}

export default React.memo(TerminalBreadcrumb);
