import type { PropertyIndexProfile, PropertyIndexRow } from "./types";
import {
  mockIndexProfiles,
  mockIndexRows,
} from "./indexProfiles";

export const INDEX_BASE_ASSET_SLUGS = {
  MAEXGEN: "maex-genesis",
  MAEXALP: "maex-alpha",
  MAEXSOC: "maex-social",
} as const;

export type IndexBaseAssetSlug = keyof typeof INDEX_BASE_ASSET_SLUGS;

const ROW_ID_TO_BASE_ASSET = Object.fromEntries(
  Object.entries(INDEX_BASE_ASSET_SLUGS).map(([baseAsset, rowId]) => [
    rowId,
    baseAsset,
  ]),
) as Record<string, IndexBaseAssetSlug>;

export function normalizeIndexSlug(slug: string): string {
  return slug.trim().toUpperCase();
}

export function rowIdToSlug(rowId: string): IndexBaseAssetSlug | undefined {
  return ROW_ID_TO_BASE_ASSET[rowId] as IndexBaseAssetSlug | undefined;
}

export function indexDetailPath(baseAsset: string): string {
  return `/cindex/${normalizeIndexSlug(baseAsset)}`;
}

export function getIndexRowBySlug(slug: string): PropertyIndexRow | undefined {
  const normalized = normalizeIndexSlug(slug);
  const rowId = INDEX_BASE_ASSET_SLUGS[normalized as IndexBaseAssetSlug];
  if (!rowId) return undefined;
  return mockIndexRows.find((row) => row.id === rowId);
}

export function getIndexProfileBySlug(
  slug: string,
): PropertyIndexProfile | undefined {
  const normalized = normalizeIndexSlug(slug);
  return mockIndexProfiles[normalized as IndexBaseAssetSlug];
}

export function isKnownIndexSlug(slug: string): boolean {
  const normalized = normalizeIndexSlug(slug);
  return normalized in INDEX_BASE_ASSET_SLUGS;
}
