import React, {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useRef,
  useState,
  type ReactNode,
} from "react";
import { toast } from "sonner";
import { isDesktopTourBreakpoint } from "./constants";
import type { WelcomeTourTabId } from "./welcomeTourSteps";
import { useOptionalDepositTour } from "../deposit-tour/DepositTourContext";
import { useOptionalCopyTour } from "../copy-tour/CopyTourContext";
import { useOptionalVaultTour } from "../vault-tour/VaultTourContext";
import { useOptionalCreateVaultTour } from "../create-vault-tour/CreateVaultTourContext";
import { inferTourBreakpointFromWidth } from "../deposit-tour/depositTourFlowSync";

// Registration APIs are stable useCallback([]); consumers must not depend on whole context in useEffect deps.

export type WelcomeHubMode = "default" | "postTour";

export interface OpenWelcomeHubOptions {
  mode?: WelcomeHubMode;
  highlightDeepDive?: boolean;
}

export interface WelcomeTourContextValue {
  showWelcomeModal: boolean;
  runTour: boolean;
  currentBreakpoint: string;
  welcomeHubMode: WelcomeHubMode;
  highlightDeepDive: boolean;
  openWelcomeModal: () => void;
  openWelcomeHub: (options?: OpenWelcomeHubOptions) => void;
  dismissWelcome: () => void;
  startGuidedTour: () => void;
  closeWelcomeModal: () => void;
  stopTour: () => void;
  onTourComplete: () => void;
  switchTourTab: (tabId: WelcomeTourTabId) => void;
  registerTabController: (
    onTabChange: (tabId: WelcomeTourTabId) => void,
  ) => () => void;
  registerLayoutReady: (getter: () => boolean) => () => void;
  registerBreakpoint: (getter: () => string) => () => void;
  isTradeUiReady: boolean;
  notifyTradeUiReady: () => void;
}

const WelcomeTourContext = createContext<WelcomeTourContextValue | undefined>(
  undefined,
);

export interface WelcomeTourProviderProps {
  children: ReactNode;
  onWelcomeSeen?: () => void;
}

export function WelcomeTourProvider({
  children,
  onWelcomeSeen,
}: WelcomeTourProviderProps): JSX.Element {
  const depositTour = useOptionalDepositTour();
  const copyTour = useOptionalCopyTour();
  const vaultTour = useOptionalVaultTour();
  const createVaultTour = useOptionalCreateVaultTour();
  const [showWelcomeModal, setShowWelcomeModal] = useState(false);
  const [runTour, setRunTour] = useState(false);
  const [currentBreakpoint, setCurrentBreakpointState] = useState("lg");
  const [tradeUiReady, setTradeUiReady] = useState(false);
  const [welcomeHubMode, setWelcomeHubMode] = useState<WelcomeHubMode>("default");
  const [highlightDeepDive, setHighlightDeepDive] = useState(false);

  const tabControllerRef = useRef<((tabId: WelcomeTourTabId) => void) | null>(
    null,
  );
  const layoutReadyRef = useRef<(() => boolean) | null>(null);
  const breakpointRef = useRef<(() => string) | null>(null);

  const openWelcomeHub = useCallback((options?: OpenWelcomeHubOptions) => {
    setWelcomeHubMode(options?.mode ?? "default");
    setHighlightDeepDive(options?.highlightDeepDive ?? false);
    setShowWelcomeModal(true);
  }, []);

  const openWelcomeModal = useCallback(() => {
    openWelcomeHub({ mode: "default", highlightDeepDive: false });
  }, [openWelcomeHub]);

  const closeWelcomeModal = useCallback(() => {
    setShowWelcomeModal(false);
    setWelcomeHubMode("default");
    setHighlightDeepDive(false);
  }, []);

  const dismissWelcome = useCallback(() => {
    closeWelcomeModal();
    onWelcomeSeen?.();
  }, [closeWelcomeModal, onWelcomeSeen]);

  const stopTour = useCallback(() => {
    setRunTour(false);
  }, []);

  const onTourComplete = useCallback(() => {
    setRunTour(false);
    onWelcomeSeen?.();
    openWelcomeHub({ mode: "postTour", highlightDeepDive: true });
  }, [onWelcomeSeen, openWelcomeHub]);

  const startGuidedTour = useCallback(() => {
    depositTour?.stopTour();
    copyTour?.stopTour();
    vaultTour?.stopTour();
    createVaultTour?.stopTour();
    setShowWelcomeModal(false);
    setWelcomeHubMode("default");
    setHighlightDeepDive(false);
    const breakpoint = breakpointRef.current?.() ?? currentBreakpoint;
    if (!isDesktopTourBreakpoint(breakpoint)) {
      toast.info(
        "Guided tour is available on desktop and tablet view. Widen your window to explore step-by-step.",
      );
      onWelcomeSeen?.();
      return;
    }
    setRunTour(true);
  }, [copyTour, createVaultTour, currentBreakpoint, depositTour, onWelcomeSeen, vaultTour]);

  const switchTourTab = useCallback((tabId: WelcomeTourTabId) => {
    tabControllerRef.current?.(tabId);
  }, []);

  const registerTabController = useCallback(
    (onTabChange: (tabId: WelcomeTourTabId) => void) => {
      tabControllerRef.current = onTabChange;
      return () => {
        if (tabControllerRef.current === onTabChange) {
          tabControllerRef.current = null;
        }
      };
    },
    [],
  );

  const registerLayoutReady = useCallback((getter: () => boolean) => {
    layoutReadyRef.current = getter;
    if (getter()) {
      setTradeUiReady(true);
    }
    return () => {
      if (layoutReadyRef.current === getter) {
        layoutReadyRef.current = null;
      }
    };
  }, []);

  const registerBreakpoint = useCallback((getter: () => string) => {
    breakpointRef.current = getter;
    setCurrentBreakpointState((prev) => {
      const next = getter();
      return prev === next ? prev : next;
    });
    return () => {
      if (breakpointRef.current === getter) {
        breakpointRef.current = null;
      }
    };
  }, []);

  useEffect(() => {
    const syncBreakpoint = () => {
      const bp =
        breakpointRef.current?.() ??
        inferTourBreakpointFromWidth(window.innerWidth);
      setCurrentBreakpointState((prev) => (prev === bp ? prev : bp));
    };
    syncBreakpoint();
    window.addEventListener("resize", syncBreakpoint);
    const interval = window.setInterval(syncBreakpoint, 300);
    return () => {
      window.removeEventListener("resize", syncBreakpoint);
      window.clearInterval(interval);
    };
  }, []);

  const notifyTradeUiReady = useCallback(() => {
    setTradeUiReady(true);
  }, []);

  const isTradeUiReady =
    tradeUiReady || (layoutReadyRef.current?.() ?? false);

  const value = useMemo<WelcomeTourContextValue>(
    () => ({
      showWelcomeModal,
      runTour,
      currentBreakpoint,
      welcomeHubMode,
      highlightDeepDive,
      openWelcomeModal,
      openWelcomeHub,
      dismissWelcome,
      startGuidedTour,
      closeWelcomeModal,
      stopTour,
      onTourComplete,
      switchTourTab,
      registerTabController,
      registerLayoutReady,
      registerBreakpoint,
      isTradeUiReady,
      notifyTradeUiReady,
    }),
    [
      showWelcomeModal,
      runTour,
      currentBreakpoint,
      welcomeHubMode,
      highlightDeepDive,
      openWelcomeModal,
      openWelcomeHub,
      dismissWelcome,
      startGuidedTour,
      closeWelcomeModal,
      stopTour,
      onTourComplete,
      switchTourTab,
      registerTabController,
      registerLayoutReady,
      registerBreakpoint,
      isTradeUiReady,
      notifyTradeUiReady,
    ],
  );

  return (
    <WelcomeTourContext.Provider value={value}>
      {children}
    </WelcomeTourContext.Provider>
  );
}

export function useWelcomeTour(): WelcomeTourContextValue {
  const ctx = useContext(WelcomeTourContext);
  if (!ctx) {
    throw new Error("useWelcomeTour must be used within WelcomeTourProvider");
  }
  return ctx;
}

export function useOptionalWelcomeTour(): WelcomeTourContextValue | undefined {
  return useContext(WelcomeTourContext);
}
