export function getTradeTooltipInventory(
  layout: LayoutStyle,
): TooltipComponentGroup[] {
  if (layout === "layout5") {
    return [...SHARED_TRADE_TOOLTIP_GROUPS, ...PRO_TERMINAL_TRADE_OPERATION_GROUPS];
  }

  const groups: TooltipComponentGroup[] = [
    ...LAYOUT_HEADER_TOOLTIP_GROUPS[layout],
    ...(LAYOUT_SLOT3_TOOLTIP_GROUPS[layout] ?? []),
    ...SHARED_TRADE_TOOLTIP_GROUPS,
  ];

  if (layout === "layout1" || layout === "layout2") {
    groups.push(...PRO_TERMINAL_TRADE_OPERATION_GROUPS);
  } else if (layout === "layout3" || layout === "layout4") {
    groups.push(AGENT_ORDERBOOK_PANEL_GROUP);
  }

  return groups;
}

