function buildTipToGroupsMap(): Map<BubbleTipId, TooltipGroupId[]> {
  const map = new Map<BubbleTipId, TooltipGroupId[]>();
  for (const group of ALL_REGISTRY_TOOLTIP_GROUPS) {
    const groupId = group.component as TooltipGroupId;
    for (const tipId of group.tipIds) {
      const existing = map.get(tipId) ?? [];
      if (!existing.includes(groupId)) {
        existing.push(groupId);
      }
      map.set(tipId, existing);
    }
  }
  return map;
}

const TIP_TO_GROUPS_MAP = buildTipToGroupsMap();

export function isTooltipGroupEnabled(
  prefs: TooltipGroupPrefs,
  groupId: TooltipGroupId,
): boolean {
  return !prefs.disabledGroups.includes(groupId);
}

export function toggleTooltipGroup(
  prefs: TooltipGroupPrefs,
  groupId: TooltipGroupId,
  enabled: boolean,
): TooltipGroupPrefs {
  const disabled = new Set(prefs.disabledGroups);
  if (enabled) {
    disabled.delete(groupId);
  } else {
    disabled.add(groupId);
  }
  return { disabledGroups: [...disabled] };
}

export function resolveTooltipGroupForTip(
  tipId: BubbleTipId,
): TooltipGroupId | null {
  const groups = TIP_TO_GROUPS_MAP.get(tipId);
  if (!groups || groups.length !== 1) {
    return null;
  }
  return groups[0];
}

export interface BubbleTipActiveParams {
  tooltipsEnabled: boolean;
  tooltipGroups: TooltipGroupPrefs;
  tipId: BubbleTipId;
  group?: TooltipGroupId;
}

export function isBubbleTipActive({
  tooltipsEnabled,
  tooltipGroups,
  tipId,
  group,
}: BubbleTipActiveParams): boolean {
  if (!tooltipsEnabled) {
    return false;
  }

  const resolvedGroup = group ?? resolveTooltipGroupForTip(tipId);
  if (!resolvedGroup) {
    return true;
  }

  return isTooltipGroupEnabled(tooltipGroups, resolvedGroup);
}

