export function resolveSettingsPageContext(pathname: string): SettingsPageContext {
  if (pathname === "/trade") return "trade";
  if (pathname === "/copytrade" || pathname === "/") return "copytrade";
  if (pathname === "/portfolio") return "portfolio";
  if (pathname.startsWith("/vault")) return "vault";
  if (pathname.startsWith("/cindex")) return "index";
  if (pathname === APP_ROUTES.myAgents) return "agentRoles";
  if (pathname.startsWith("/agents/compare")) return "agent";
  if (pathname.startsWith("/agents/")) return "agent";
  if (pathname === "/staking") return "staking";
  return "general";
}

export function buildMenuGroups(pageContext: SettingsPageContext): SettingsMenuGroup[] {
  const groups: SettingsMenuGroup[] = [
    { id: "general", label: "General", items: GENERAL_MENU_ITEMS },
  ];

  if (pageContext === "trade") {
    groups.push({ id: "trading", label: "Trading UI", items: TRADING_MENU_ITEMS });
  } else if (pageContext === "copytrade") {
    groups.push({ id: "copytrade", label: "Copytrade UI", items: MARKETS_MENU_ITEMS });
  } else if (pageContext === "index") {
    groups.push({ id: "index", label: "Index UI", items: INDEX_MENU_ITEMS });
  } else if (pageContext === "portfolio") {
    groups.push({ id: "portfolio", label: "Portfolio UI", items: PORTFOLIO_MENU_ITEMS });
  } else if (pageContext === "agentRoles") {
    groups.push({
      id: "agentRoles",
      label: "Agents & Roles UI",
      items: AGENT_ROLES_MENU_ITEMS,
    });
  } else if (pageContext === "agent") {
    groups.push({ id: "agent", label: "Agent UI", items: AGENT_MENU_ITEMS });
  } else if (pageContext === "staking") {
    groups.push({ id: "staking", label: "Staking UI", items: STAKING_MENU_ITEMS });
  } else if (pageContext === "vault") {
    groups.push({ id: "vault", label: "Vault UI", items: VAULT_MENU_ITEMS });
  }

  return groups;
}

