import { create } from "zustand";
import {
  autonomyPolicyForTradingMode,
  cloneAutonomyPolicy,
  MANUAL_AUTONOMY,
  seedAutonomyPolicyForBucketIndex,
  type AutonomyPolicy,
} from "../components/tradeagent/autonomyPolicy";
import type { TradingMode } from "../configs/tradeLayoutMode";
import type { AgentTask } from "./types";

const STORAGE_KEY = "morpheum_bucket_autonomy_policies";

type PolicyMap = Record<string, AutonomyPolicy>;

interface BucketPolicyStoreState {
  policies: PolicyMap;
  syncedBucketKey: string | null;
  getPolicy: (bucketId: string, fallback?: AutonomyPolicy) => AutonomyPolicy;
  setPolicy: (bucketId: string, policy: AutonomyPolicy) => void;
  clearPolicy: (bucketId: string) => void;
  syncBucketIds: (bucketIds: string[]) => void;
  resolvePolicyForTask: (
    task: AgentTask,
    tradingMode?: TradingMode,
  ) => AutonomyPolicy;
}

function loadPoliciesFromStorage(): PolicyMap {
  if (typeof window === "undefined") return {};
  try {
    const raw = window.localStorage.getItem(STORAGE_KEY);
    if (!raw) return {};
    const parsed = JSON.parse(raw) as PolicyMap;
    return parsed && typeof parsed === "object" ? parsed : {};
  } catch {
    return {};
  }
}

function savePoliciesToStorage(policies: PolicyMap): void {
  if (typeof window === "undefined") return;
  try {
    window.localStorage.setItem(STORAGE_KEY, JSON.stringify(policies));
  } catch {
    // ignore quota errors in demo
  }
}

function bucketIdsKey(bucketIds: string[]): string {
  return bucketIds.filter(Boolean).join("|");
}

export const useBucketPolicyStore = create<BucketPolicyStoreState>((set, get) => ({
  policies: loadPoliciesFromStorage(),
  syncedBucketKey: null,

  getPolicy: (bucketId, fallback = MANUAL_AUTONOMY) => {
    const stored = get().policies[bucketId];
    return stored ? cloneAutonomyPolicy(stored) : cloneAutonomyPolicy(fallback);
  },

  setPolicy: (bucketId, policy) => {
    const next = cloneAutonomyPolicy(policy);
    set((state) => {
      const policies = { ...state.policies, [bucketId]: next };
      savePoliciesToStorage(policies);
      return { policies };
    });
  },

  clearPolicy: (bucketId) => {
    set((state) => {
      if (!state.policies[bucketId]) return state;
      const policies = { ...state.policies };
      delete policies[bucketId];
      savePoliciesToStorage(policies);
      return { policies };
    });
  },

  syncBucketIds: (bucketIds) => {
    const key = bucketIdsKey(bucketIds);
    if (!key || get().syncedBucketKey === key) return;

    set((state) => {
      const policies = { ...state.policies };
      let changed = false;

      bucketIds.forEach((bucketId, index) => {
        if (!bucketId || policies[bucketId]) return;
        policies[bucketId] = seedAutonomyPolicyForBucketIndex(index);
        changed = true;
      });

      if (changed) {
        savePoliciesToStorage(policies);
      }

      return {
        policies: changed ? policies : state.policies,
        syncedBucketKey: key,
      };
    });
  },

  resolvePolicyForTask: (task, tradingMode = "highAgency") => {
    const fallback = autonomyPolicyForTradingMode(tradingMode);
    if (!task.bucketId) return cloneAutonomyPolicy(fallback);
    return get().getPolicy(task.bucketId, fallback);
  },
}));

export function createTaskPolicyResolver(
  tradingMode: TradingMode = "highAgency",
): (task: AgentTask) => AutonomyPolicy {
  return (task) =>
    useBucketPolicyStore.getState().resolvePolicyForTask(task, tradingMode);
}
