import { getAgentKpiSummaryByAgentDid as getFromSnapshot } from "./agentKpiManifestSnapshot";
import type { AgentKpiSummary } from "./agentKpiHistory.types";
import { getCatalogSeedByDid, getCatalogSeedById } from "./agentCatalogSeeds";
import { resolveAgentDid, resolveCatalogSeedKey } from "./agentIdentity";

export function getAgentKpiSummaryBySeedKey(seedKey: string): AgentKpiSummary {
  const seed = getCatalogSeedById(seedKey);
  if (!seed) {
    throw new Error("Missing KPI summary for agent seed key: " + seedKey);
  }
  return getFromSnapshot(seed.did);
}

export function getAgentKpiSummaryByAgentDid(agentDid: string): AgentKpiSummary {
  try {
    return getFromSnapshot(agentDid);
  } catch {
    const resolvedDid = resolveAgentDid(agentDid);
    if (resolvedDid) {
      try {
        return getFromSnapshot(resolvedDid);
      } catch {
        const byDid = getCatalogSeedByDid(resolvedDid);
        if (byDid) return getAgentKpiSummaryBySeedKey(byDid.id);
      }
    }

    const seedKey = resolveCatalogSeedKey(agentDid);
    if (seedKey) return getAgentKpiSummaryBySeedKey(seedKey);

    const byId = getCatalogSeedById(agentDid);
    if (byId) return getAgentKpiSummaryBySeedKey(byId.id);

    throw new Error("Missing KPI summary for agent DID: " + agentDid);
  }
}

/** @deprecated Use getAgentKpiSummaryByAgentDid or getAgentKpiSummaryBySeedKey */
export function getAgentKpiSummaryByCatalogId(catalogAgentId: string): AgentKpiSummary {
  return getAgentKpiSummaryByAgentDid(catalogAgentId);
}
