import { useEffect, useState } from "react";

const HACKER_CHARS = "!@#$%^&*()_+{}[]|;:,.<>?/0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ";
const TICK_MS = 50;
const DECRYPT_MS = 3500;
const PAUSE_MS = 2500;
const CYCLE_MS = DECRYPT_MS + PAUSE_MS;

function prefersReducedMotion(): boolean {
  if (typeof window === "undefined") return false;
  return window.matchMedia("(prefers-reduced-motion: reduce)").matches;
}

function isLockableChar(char: string): boolean {
  return /[A-Za-z0-9]/.test(char);
}

function randomHackerChar(): string {
  return HACKER_CHARS[Math.floor(Math.random() * HACKER_CHARS.length)] ?? "?";
}

function scrambleChar(originalChar: string): string {
  if (Math.random() < 0.5) {
    return randomHackerChar();
  }
  return originalChar;
}

function buildMatrixText(text: string, cycleElapsed: number): string {
  const lockableIndices: number[] = [];
  for (let i = 0; i < text.length; i++) {
    if (isLockableChar(text[i] ?? "")) {
      lockableIndices.push(i);
    }
  }

  const lockableCount = lockableIndices.length;
  const progress =
    lockableCount === 0 ? 1 : Math.min(cycleElapsed / DECRYPT_MS, 1);
  const revealedCount = Math.floor(progress * lockableCount);
  const revealedSet = new Set(lockableIndices.slice(0, revealedCount));

  let result = "";
  for (let i = 0; i < text.length; i++) {
    const char = text[i] ?? "";
    if (!isLockableChar(char) || revealedSet.has(i)) {
      result += char;
    } else {
      result += scrambleChar(char);
    }
  }
  return result;
}

export function useMatrixText(text: string, enabled: boolean): string {
  const [displayText, setDisplayText] = useState(text);

  useEffect(() => {
    if (!enabled || prefersReducedMotion()) {
      setDisplayText(text);
      return;
    }

    let cycleStart = Date.now();

    const tick = () => {
      const now = Date.now();
      let cycleElapsed = now - cycleStart;

      if (cycleElapsed >= CYCLE_MS) {
        cycleStart = now;
        cycleElapsed = 0;
      }

      setDisplayText(buildMatrixText(text, cycleElapsed));
    };

    tick();
    const intervalId = setInterval(tick, TICK_MS);

    return () => {
      clearInterval(intervalId);
    };
  }, [text, enabled]);

  return displayText;
}
