import * as Tooltip from "@radix-ui/react-tooltip";
import type { JSX, ReactElement, ReactNode } from "react";
import { useOptionalSettings } from "../../context/SettingsContext";
import {
  isBubbleTipActive,
  type TooltipGroupId,
} from "../../components/preference/settingsRegistry";
import { useDemoGuideActions } from "../demo-guide/DemoGuideActionsContext";
import { getBubbleTipContent } from "./bubbleTipContent";
import type { BubbleTipId } from "./bubbleTipIds";
import type { DemoGuideDeepLinkAction } from "./bubbleTipContent";
import { useOptionalDepositTour } from "../deposit-tour/DepositTourContext";
import { useOptionalWelcomeTour } from "../welcome-tour/WelcomeTourContext";
import { useIsMobileViewport } from "../../hooks/useIsMobileViewport";
import "./BubbleTip.css";

export interface BubbleTipProps {
  id: BubbleTipId;
  children: ReactElement;
  /** Override registry body text */
  content?: string;
  /** Override registry label */
  title?: string;
  side?: "top" | "right" | "bottom" | "left";
  align?: "start" | "center" | "end";
  /** Hide label line even when registry has one */
  hideLabel?: boolean;
  /** Show tooltip even when user disabled hover tooltips in settings */
  forceShow?: boolean;
  /** Component group for per-group tooltip toggles */
  group?: TooltipGroupId;
}

function runDeepLinkAction(
  action: DemoGuideDeepLinkAction,
  demoGuide: ReturnType<typeof useDemoGuideActions>,
): void {
  if (action === "jelly") {
    demoGuide?.startJellyIncident?.();
    return;
  }
  if (action === "networkHealth") {
    demoGuide?.openNetworkHealth?.();
    return;
  }
  demoGuide?.openWelcomeHub?.();
}

export function BubbleTip({
  id,
  children,
  content,
  title,
  side = "top",
  align = "center",
  hideLabel = false,
  forceShow = false,
  group,
}: BubbleTipProps): JSX.Element {
  const welcomeTour = useOptionalWelcomeTour();
  const depositTour = useOptionalDepositTour();
  const settings = useOptionalSettings();
  const demoGuide = useDemoGuideActions();
  const isMobile = useIsMobileViewport();
  const entry = getBubbleTipContent(id);
  const label = title ?? entry.label;
  const body = content ?? entry.body;
  const deepLink = entry.deepLink;

  if (welcomeTour?.runTour || depositTour?.runTour) {
    return children;
  }

  if (isMobile) {
    return children;
  }

  if (
    !forceShow &&
    settings &&
    !isBubbleTipActive({
      tooltipsEnabled: settings.settings.tooltipsEnabled,
      tooltipGroups: settings.settings.tooltipGroups,
      tipId: id,
      group,
    })
  ) {
    return children;
  }

  return (
    <Tooltip.Root>
      <Tooltip.Trigger asChild data-bubble-tip-trigger>
        {children}
      </Tooltip.Trigger>
      <Tooltip.Portal>
        <Tooltip.Content
          className="bubble-tip"
          side={side}
          align={align}
          sideOffset={8}
          collisionPadding={12}
        >
          {!hideLabel && label ? (
            <div className="bubble-tip__label">{label}</div>
          ) : null}
          <div className="bubble-tip__body">{body}</div>
          {deepLink ? (
            <button
              type="button"
              className="bubble-tip__deep-link"
              onClick={() => runDeepLinkAction(deepLink.action, demoGuide)}
            >
              {deepLink.label}
            </button>
          ) : null}
          <Tooltip.Arrow className="bubble-tip__arrow" width={12} height={6} />
        </Tooltip.Content>
      </Tooltip.Portal>
    </Tooltip.Root>
  );
}

export interface BubbleTipInlineProps {
  id: BubbleTipId;
  trigger: ReactNode;
  content?: string;
  title?: string;
  side?: "top" | "right" | "bottom" | "left";
  align?: "start" | "center" | "end";
  hideLabel?: boolean;
  className?: string;
  forceShow?: boolean;
  group?: TooltipGroupId;
}

/** Wraps arbitrary trigger content in a span when asChild cannot be used. */
export function BubbleTipInline({
  id,
  trigger,
  content,
  title,
  side = "top",
  align = "center",
  hideLabel = false,
  className,
  forceShow = false,
  group,
}: BubbleTipInlineProps): JSX.Element {
  return (
    <BubbleTip
      id={id}
      content={content}
      title={title}
      side={side}
      align={align}
      hideLabel={hideLabel}
      forceShow={forceShow}
      group={group}
    >
      <span className={className ? `bubble-tip-trigger ${className}` : "bubble-tip-trigger"}>
        {trigger}
      </span>
    </BubbleTip>
  );
}
