import type {
  FleetTradeAction,
  FleetTradeEvent,
} from "../../offline/mock_data/fleetTradeHistory.types";
import {
  ORDER_SIDE_COLOR_BUY_LONG,
  ORDER_SIDE_COLOR_SELL_SHORT,
} from "../constants";
import { formatPnL, formatPrice, formatSize } from "../sdk/utils/display";
import type { AgentAssetAllocationRange } from "./agentAssetHoldings";
import { AGENT_ASSET_ALLOCATION_RANGE_OPTIONS } from "./agentAssetHoldings";

export { AGENT_ASSET_ALLOCATION_RANGE_OPTIONS };

export type FleetActivityLogTone = "long" | "short";

export type FleetActivityLogNarrativeSegment =
  | { kind: "text"; text: string }
  | { kind: "symbol"; text: string }
  | { kind: "value"; text: string }
  | { kind: "pnlValue"; text: string; tone: FleetActivityLogTone };

export type FleetActivityLogEntry = {
  id: string;
  timestamp: string;
  badgeLabel: string;
  tone: FleetActivityLogTone;
  marketId: string;
  symbolLabel: string;
  narrativeSegments: FleetActivityLogNarrativeSegment[];
  /** Full sentence for screen readers and tests. */
  narrative: string;
  pnlColor?: string;
};

const SATOSHI = 100_000_000;

const RANGE_MS: Record<AgentAssetAllocationRange, number> = {
  "7d": 7 * 24 * 60 * 60 * 1000,
  "30d": 30 * 24 * 60 * 60 * 1000,
  "90d": 90 * 24 * 60 * 60 * 1000,
  "180d": 180 * 24 * 60 * 60 * 1000,
  "365d": 365 * 24 * 60 * 60 * 1000,
};

function fromSatoshi(value: string | number | undefined): number {
  if (value == null) return 0;
  const numeric = typeof value === "number" ? value : Number(value);
  if (!Number.isFinite(numeric)) return 0;
  return numeric / SATOSHI;
}

function isEntryAction(action: FleetTradeAction): boolean {
  return action === "BUY" || action === "SNIPE";
}

export function resolveFleetActivityLogAnchorMs(
  trades: FleetTradeEvent[],
  fallbackMs = Date.now(),
): number {
  if (trades.length === 0) return fallbackMs;
  let latest = Number.NEGATIVE_INFINITY;
  for (const trade of trades) {
    const ts = Date.parse(trade.timestamp);
    if (Number.isFinite(ts) && ts > latest) {
      latest = ts;
    }
  }
  return Number.isFinite(latest) ? latest : fallbackMs;
}

export function resolveFleetActivityLogRangeBounds(
  range: AgentAssetAllocationRange,
  anchorMs: number,
): { startMs: number; endMs: number } {
  const endMs = anchorMs;
  const startMs = endMs - RANGE_MS[range];
  return { startMs, endMs };
}

export function formatFleetActivityLogRangeLabel(
  range: AgentAssetAllocationRange,
  anchorMs: number,
): string {
  const { startMs, endMs } = resolveFleetActivityLogRangeBounds(range, anchorMs);
  const format = (ms: number) => {
    const date = new Date(ms);
    if (Number.isNaN(date.getTime())) return "—";
    return date.toISOString().slice(0, 10);
  };
  return `${format(startMs)} -> ${format(endMs)}`;
}

export function filterFleetTradesByRange(
  trades: FleetTradeEvent[],
  range: AgentAssetAllocationRange,
  anchorMs: number,
): FleetTradeEvent[] {
  const { startMs, endMs } = resolveFleetActivityLogRangeBounds(range, anchorMs);
  return trades.filter((trade) => {
    const ts = Date.parse(trade.timestamp);
    return Number.isFinite(ts) && ts >= startMs && ts <= endMs;
  });
}

export function formatFleetActivityLogTimestamp(iso: string): string {
  const date = new Date(iso);
  if (Number.isNaN(date.getTime())) return "—";
  const month = String(date.getUTCMonth() + 1).padStart(2, "0");
  const day = String(date.getUTCDate()).padStart(2, "0");
  const hours = String(date.getUTCHours()).padStart(2, "0");
  const minutes = String(date.getUTCMinutes()).padStart(2, "0");
  const seconds = String(date.getUTCSeconds()).padStart(2, "0");
  return `${month}-${day}, ${hours}:${minutes}:${seconds}`;
}

export function resolveFleetActivityLogBadge(
  action: FleetTradeAction,
): { label: string; tone: FleetActivityLogTone } {
  if (isEntryAction(action)) {
    return { label: "Open Long", tone: "long" };
  }
  return { label: "Close Long", tone: "short" };
}

export function buildFleetActivityLogNarrative(event: FleetTradeEvent): string {
  return buildFleetActivityLogNarrativeSegments(event)
    .map((segment) => segment.text)
    .join("");
}

export function buildFleetActivityLogNarrativeSegments(
  event: FleetTradeEvent,
): FleetActivityLogNarrativeSegment[] {
  const price = fromSatoshi(event.price);
  const size = fromSatoshi(event.quantity);
  const symbolLabel = `${event.coin.toUpperCase()}USDT Perpetual`;
  const coin = event.coin.toUpperCase();
  const { label: badgeLabel } = resolveFleetActivityLogBadge(event.action);
  const verb = badgeLabel.startsWith("Open") ? "Open" : "Close";
  const side = badgeLabel.endsWith("Short") ? "Short" : "Long";
  const priceText = formatPrice(price);
  const sizeText = formatSize(size);
  const totalText = formatPrice(event.amountUsd);

  const segments: FleetActivityLogNarrativeSegment[] = [
    { kind: "text", text: `${verb} a ${side} position of ` },
    { kind: "symbol", text: symbolLabel },
    { kind: "text", text: " at a price of " },
    { kind: "value", text: priceText },
    { kind: "text", text: " USDT, amount of " },
    { kind: "value", text: sizeText },
    { kind: "text", text: ` ${coin} for a total value of ` },
    { kind: "value", text: totalText },
    { kind: "text", text: " USDT" },
  ];

  if (event.closedPnl != null) {
    const pnlTone: FleetActivityLogTone =
      event.closedPnl >= 0 ? "long" : "short";
    const pnlText =
      event.closedPnl >= 0
        ? `+${formatPnL(event.closedPnl)}`
        : formatPnL(event.closedPnl);
    segments.push(
      { kind: "text", text: ", Realized PNL is " },
      {
        kind: "pnlValue",
        text: pnlText,
        tone: pnlTone,
      },
      { kind: "text", text: " USDT." },
    );
  } else {
    segments.push({ kind: "text", text: "." });
  }

  return segments;
}

export function buildFleetActivityLogEntry(
  event: FleetTradeEvent,
): FleetActivityLogEntry {
  const { label: badgeLabel, tone } = resolveFleetActivityLogBadge(event.action);
  const narrativeSegments = buildFleetActivityLogNarrativeSegments(event);
  const symbolSegment = narrativeSegments.find((segment) => segment.kind === "symbol");
  const pnlColor =
    event.closedPnl == null
      ? undefined
      : event.closedPnl >= 0
        ? ORDER_SIDE_COLOR_BUY_LONG
        : ORDER_SIDE_COLOR_SELL_SHORT;

  return {
    id: event.id,
    timestamp: event.timestamp,
    badgeLabel,
    tone,
    marketId: event.marketId,
    symbolLabel: symbolSegment?.text ?? `${event.coin.toUpperCase()}USDT Perpetual`,
    narrativeSegments,
    narrative: buildFleetActivityLogNarrative(event),
    pnlColor,
  };
}

export function buildFleetActivityLogEntries(
  trades: FleetTradeEvent[],
): FleetActivityLogEntry[] {
  return [...trades]
    .sort((a, b) => b.timestamp.localeCompare(a.timestamp))
    .map(buildFleetActivityLogEntry);
}
