import React, {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useRef,
  useState,
  type ReactNode,
} from "react";
import { useLocation, useNavigate } from "react-router-dom";
import { toast } from "sonner";

import { getAppRoute } from "../../routes";
import { isDesktopTourBreakpoint } from "../welcome-tour/constants";
import {
  inferTourBreakpointFromWidth,
  vaultTourDetailPath,
} from "./vaultTourFlowSync";

export interface StartVaultTourOptions {
  skipWalletCheck?: boolean;
}

export interface VaultTourContextValue {
  runTour: boolean;
  stepIndex: number;
  currentBreakpoint: string;
  pathname: string;
  startVaultTour: (options?: StartVaultTourOptions) => void;
  stopTour: () => void;
  onTourComplete: () => void;
  setStepIndex: (index: number | ((prev: number) => number)) => void;
  registerTourMutex: (fn: () => void) => () => void;
  registerBreakpoint: (getter: () => string) => () => void;
  registerWallet: (getter: () => string | null) => () => void;
  registerEnsureBucketsTab: (fn: () => void) => () => void;
  registerStartCreateVaultTour: (fn: () => void) => () => void;
}

const VaultTourContext = createContext<VaultTourContextValue | undefined>(
  undefined,
);

export interface VaultTourProviderProps {
  children: ReactNode;
  onVaultTourSeen?: () => void;
}

export function VaultTourProvider({
  children,
  onVaultTourSeen,
}: VaultTourProviderProps): JSX.Element {
  const navigate = useNavigate();
  const location = useLocation();
  const [runTour, setRunTour] = useState(false);
  const [stepIndex, setStepIndex] = useState(0);
  const [currentBreakpoint, setCurrentBreakpointState] = useState("lg");

  const tourMutexRef = useRef<(() => void) | null>(null);
  const breakpointRef = useRef<(() => string) | null>(null);
  const walletGetterRef = useRef<(() => string | null) | null>(null);
  const ensureBucketsTabRef = useRef<(() => void) | null>(null);
  const startCreateVaultTourRef = useRef<(() => void) | null>(null);

  const stopTour = useCallback(() => {
    setRunTour(false);
    setStepIndex(0);
  }, []);

  const onTourComplete = useCallback(() => {
    setRunTour(false);
    setStepIndex(0);
    onVaultTourSeen?.();
    toast.success("Vault tour complete", {
      description: "Next: create your own vault in the listing wizard.",
      action: {
        label: "Create vault tour",
        onClick: () => startCreateVaultTourRef.current?.(),
      },
      duration: 12000,
    });
  }, [onVaultTourSeen]);

  const startVaultTour = useCallback(
    (options?: StartVaultTourOptions) => {
      const wallet = walletGetterRef.current?.()?.trim();
      if (!options?.skipWalletCheck && !wallet) {
        toast.error("Connect wallet first", {
          description: "Connect your wallet before starting the vault tour.",
        });
        return;
      }

      const breakpoint =
        breakpointRef.current?.() ??
        (typeof window !== "undefined"
          ? inferTourBreakpointFromWidth(window.innerWidth)
          : currentBreakpoint);

      if (!isDesktopTourBreakpoint(breakpoint)) {
        toast.info(
          "Vault tour is available on desktop and tablet view. Widen your window to explore step-by-step.",
        );
        return;
      }

      tourMutexRef.current?.();
      setStepIndex(0);
      setRunTour(true);
      navigate(getAppRoute("vault"));
    },
    [currentBreakpoint, navigate],
  );

  const registerTourMutex = useCallback((fn: () => void) => {
    tourMutexRef.current = fn;
    return () => {
      if (tourMutexRef.current === fn) {
        tourMutexRef.current = null;
      }
    };
  }, []);

  const registerBreakpoint = useCallback((getter: () => string) => {
    breakpointRef.current = getter;
    setCurrentBreakpointState(getter());
    return () => {
      if (breakpointRef.current === getter) {
        breakpointRef.current = null;
      }
    };
  }, []);

  const registerWallet = useCallback((getter: () => string | null) => {
    walletGetterRef.current = getter;
    return () => {
      if (walletGetterRef.current === getter) {
        walletGetterRef.current = null;
      }
    };
  }, []);

  const registerEnsureBucketsTab = useCallback((fn: () => void) => {
    ensureBucketsTabRef.current = fn;
    return () => {
      if (ensureBucketsTabRef.current === fn) {
        ensureBucketsTabRef.current = null;
      }
    };
  }, []);

  const registerStartCreateVaultTour = useCallback((fn: () => void) => {
    startCreateVaultTourRef.current = fn;
    return () => {
      if (startCreateVaultTourRef.current === fn) {
        startCreateVaultTourRef.current = null;
      }
    };
  }, []);

  useEffect(() => {
    if (!runTour) return;
    if (location.pathname === vaultTourDetailPath()) {
      ensureBucketsTabRef.current?.();
    }
  }, [runTour, location.pathname]);

  const value = useMemo(
    (): VaultTourContextValue => ({
      runTour,
      stepIndex,
      currentBreakpoint,
      pathname: location.pathname,
      startVaultTour,
      stopTour,
      onTourComplete,
      setStepIndex,
      registerTourMutex,
      registerBreakpoint,
      registerWallet,
      registerEnsureBucketsTab,
      registerStartCreateVaultTour,
    }),
    [
      runTour,
      stepIndex,
      currentBreakpoint,
      location.pathname,
      startVaultTour,
      stopTour,
      onTourComplete,
      registerTourMutex,
      registerBreakpoint,
      registerWallet,
      registerEnsureBucketsTab,
      registerStartCreateVaultTour,
    ],
  );

  return (
    <VaultTourContext.Provider value={value}>{children}</VaultTourContext.Provider>
  );
}

export function useVaultTour(): VaultTourContextValue {
  const ctx = useContext(VaultTourContext);
  if (!ctx) {
    throw new Error("useVaultTour must be used within VaultTourProvider");
  }
  return ctx;
}

export function useOptionalVaultTour(): VaultTourContextValue | undefined {
  return useContext(VaultTourContext);
}
