import {
  buildReplayLeaderEvent,
  COPY_MIRROR_REPLAY_INTERVAL_MS,
  getReplayStepCount,
  startCopyMirrorReplay,
  stopCopyMirrorReplay,
  storeReplayLeaderEvent,
} from "../../offline/mock_data/copyMirrorReplay";
import type { CopyRelation } from "../../offline/mock_data/fleetCopyRelations";
import { getTaskReportingMeta, isGatedTier } from "../components/tradeagent/reportTier";
import { buildMirrorTaskFromFleetEvent } from "../utils/buildMirrorTaskFromFleetEvent";
import { executeCopyMirrorFill } from "../utils/executeCopyMirrorFill";
import { useAgentTaskStore } from "../store/agentTaskStore";
import { useBucketPolicyStore } from "../store/bucketPolicyStore";
import { useTradingAgentStore } from "../store/tradingAgentStore";

type ActiveReplay = {
  relation: CopyRelation;
  profileName: string;
  stepIndex: number;
  baseTimeMs: number;
  timerId: ReturnType<typeof setTimeout> | null;
  intervalMs: number;
  maxSteps: number;
};

export type CopyMirrorReplayOptions = {
  intervalMs?: number;
  maxSteps?: number;
};

function effectiveStepCount(replay: ActiveReplay): number {
  return Math.min(getReplayStepCount(), replay.maxSteps);
}

const activeReplays = new Map<string, ActiveReplay>();
let taskUnsubscribe: (() => void) | null = null;
let previousTaskSnapshot = useAgentTaskStore.getState().tasks;

function resolveProfileName(agentDid: string): string {
  return agentDid.trim();
}

function emitReplayStep(replay: ActiveReplay): void {
  const { relation, stepIndex, baseTimeMs, profileName } = replay;
  const stepLimit = effectiveStepCount(replay);
  if (stepIndex >= stepLimit) {
    stopCopyMirrorReplaySession(relation.id);
    return;
  }

  const event = buildReplayLeaderEvent(relation, stepIndex, baseTimeMs);
  storeReplayLeaderEvent(relation.id, event);

  const agentId = useTradingAgentStore.getState().resolveDefaultAgentId();
  const taskInput = buildMirrorTaskFromFleetEvent({
    event,
    relation,
    agentId,
    profileName,
  });

  const task = useAgentTaskStore.getState().addTask(taskInput, {
    navigate: false,
    appendMemory: true,
  });

  const policy = useBucketPolicyStore.getState().resolvePolicyForTask(task);
  const tier = getTaskReportingMeta(task, policy).reportTier;
  const preset = relation.copySettings.autonomyPreset;

  if (preset === "highAgency" && !isGatedTier(tier)) {
    useAgentTaskStore.getState().forceExecute(task.id);
  }

  replay.stepIndex += 1;

  if (replay.stepIndex < stepLimit) {
    replay.timerId = setTimeout(() => {
      emitReplayStep(replay);
    }, replay.intervalMs);
  } else {
    stopCopyMirrorReplay(relation.id);
    activeReplays.delete(relation.id);
  }
}

export function scheduleCopyMirrorReplay(
  relation: CopyRelation,
  profileName?: string,
  options?: CopyMirrorReplayOptions,
): void {
  stopCopyMirrorReplaySession(relation.id);
  startCopyMirrorReplay(relation);

  const intervalMs = options?.intervalMs ?? COPY_MIRROR_REPLAY_INTERVAL_MS;
  const maxSteps = options?.maxSteps ?? getReplayStepCount();

  const replay: ActiveReplay = {
    relation,
    profileName: profileName ?? resolveProfileName(relation.targetAgentDid),
    stepIndex: 0,
    baseTimeMs: Date.now(),
    timerId: null,
    intervalMs,
    maxSteps,
  };
  activeReplays.set(relation.id, replay);

  replay.timerId = setTimeout(() => {
    emitReplayStep(replay);
  }, intervalMs);
}

export function stopCopyMirrorReplaySession(relationId: string): void {
  const replay = activeReplays.get(relationId);
  if (replay?.timerId) {
    clearTimeout(replay.timerId);
  }
  activeReplays.delete(relationId);
  stopCopyMirrorReplay(relationId);
}

function handleTaskTransitions(tasks: typeof previousTaskSnapshot): void {
  for (const task of tasks) {
    if (!task.leaderTradeId) continue;
    const prev = previousTaskSnapshot.find((entry) => entry.id === task.id);
    if (task.status === "executing" && prev?.status !== "executing") {
      executeCopyMirrorFill(task.id);
    }
  }
  previousTaskSnapshot = tasks;
}

export function initCopyMirrorOrchestrator(): () => void {
  if (taskUnsubscribe) {
    return taskUnsubscribe;
  }

  taskUnsubscribe = useAgentTaskStore.subscribe((state) => {
    handleTaskTransitions(state.tasks);
  });

  previousTaskSnapshot = useAgentTaskStore.getState().tasks;

  return () => {
    taskUnsubscribe?.();
    taskUnsubscribe = null;
    for (const relationId of activeReplays.keys()) {
      stopCopyMirrorReplaySession(relationId);
    }
  };
}
