/** @deprecated Use AGENT_KPI_SUMMARY_BY_SEED_KEY */
export const AGENT_KPI_SUMMARY_BY_ID = AGENT_KPI_SUMMARY_BY_SEED_KEY;

export function getAgentKpiSummaryByAgentDid(agentDid: string): AgentKpiSummary {
  const summary = AGENT_KPI_SUMMARY_BY_DID[agentDid.trim()];
  if (!summary) {
    throw new Error("Missing KPI summary for agent DID: " + agentDid);
  }
  return summary;
}

export function getAgentKpiSummaryBySeedKey(seedKey: string): AgentKpiSummary {
  const normalized = seedKey.trim().toLowerCase();
  const summary = AGENT_KPI_SUMMARY_BY_SEED_KEY[normalized];
  if (!summary) {
    throw new Error("Missing KPI summary for agent seed key: " + seedKey);
  }
  return summary;
}

/** @deprecated Use getAgentKpiSummaryByAgentDid or getAgentKpiSummaryBySeedKey */
export function getAgentKpiSummaryByCatalogId(catalogAgentId: string): AgentKpiSummary {
  return getAgentKpiSummaryBySeedKey(catalogAgentId);
}
