import { mockHashId } from "./mockHashId";
import {
  ALL_CATALOG_AGENT_SEEDS,
  catalogSeedToFleetMinimal,
} from "./agentCatalogSeeds";
import { agentDidToStorageKey } from "./agentIdentity";
import { deriveCopyCountFromReputation, isPopularCopyCount } from "./agentCopyCount";
import { getAgentKpiSummaryByAgentDid } from "./agentKpiLookup";

export type FleetBehaviorProfile =
  | "high_freq_aggressive"
  | "steady_yield"
  | "sniper"
  | "grid_range"
  | "macro_dislocation";

export type FleetAgentRecord = {
  agentDid: string;
  seedKey: string;
  agentWallet: string;
  masterWallet: string;
  tokenAddress: string;
  deployer: string;
  /** ISO 8601 — deterministic agent contract deployment date. */
  agentDeployedAt: string;
  behaviorProfile: FleetBehaviorProfile;
  behaviorSeed: string;
  copyCount: number;
  winRatePct: number;
  tvlManagedSim: number;
  isPopular: boolean;
};

/** Fleet trade snapshot anchor — aligns with emit-fleet-trade-history.ts. */
export const FLEET_SNAPSHOT_ANCHOR_MS = Date.parse("2026-05-20T00:00:00.000Z");

const AGENT_DEPLOYED_MIN_DAYS_BEFORE_ANCHOR = 45;
const AGENT_DEPLOYED_MAX_DAYS_BEFORE_ANCHOR = 210;

/** Minimal catalog seed — derived from unified agent catalog seeds + KPI snapshot. */
const FLEET_CATALOG_SEEDS = ALL_CATALOG_AGENT_SEEDS.map((seed) => {
  const summary = getAgentKpiSummaryByAgentDid(seed.did);
  return catalogSeedToFleetMinimal(
    seed,
    summary.winRatePct,
    summary.aumUsd / 1_000_000,
  );
});

const SATOSHI = 100_000_000;

/** Deterministic 0x-prefixed EVM address (40 hex chars) from a seed string. */
export function mockEvmAddress(seed: string): string {
  const lo = mockHashId(`evm:${seed}:lo`).slice(0, 24);
  const hi = mockHashId(`evm:${seed}:hi`).slice(0, 16);
  return `0x${lo}${hi}`.toLowerCase();
}

function strategyToBehavior(strategy: string): FleetBehaviorProfile {
  const normalized = strategy.toLowerCase();
  if (normalized.includes("grid")) return "grid_range";
  if (normalized.includes("macro")) return "macro_dislocation";
  if (
    normalized.includes("meme") ||
    normalized.includes("momentum") ||
    normalized.includes("volatility") ||
    normalized.includes("quant") ||
    normalized.includes("order flow")
  ) {
    return "high_freq_aggressive";
  }
  if (
    normalized.includes("arb") ||
    normalized.includes("spread") ||
    normalized.includes("sniper")
  ) {
    return "sniper";
  }
  return "steady_yield";
}

/** Deterministic agent deployment date (45–210 days before fleet snapshot anchor). */
export function deterministicAgentDeployedAt(seedKey: string): string {
  const hash = mockHashId(`fleet:deployed-at:${seedKey}`);
  const daySpan =
    AGENT_DEPLOYED_MAX_DAYS_BEFORE_ANCHOR - AGENT_DEPLOYED_MIN_DAYS_BEFORE_ANCHOR;
  const dayOffset =
    AGENT_DEPLOYED_MIN_DAYS_BEFORE_ANCHOR
    + (Number.parseInt(hash.slice(0, 6), 16) % (daySpan + 1));
  const deployedMs = FLEET_SNAPSHOT_ANCHOR_MS - dayOffset * 24 * 60 * 60 * 1000;
  return new Date(deployedMs).toISOString();
}

function buildFleetRecord(
  seed: (typeof FLEET_CATALOG_SEEDS)[number],
  index: number,
): FleetAgentRecord {
  const seedKey = seed.seedKey;
  const summary = getAgentKpiSummaryByAgentDid(seed.did);
  const agentWallet = mockEvmAddress(`fleet:agent-wallet:${seedKey}`);
  const masterWallet = mockEvmAddress(`fleet:master-wallet:${seedKey}`);
  const tokenAddress = mockEvmAddress(`fleet:token:${seedKey}`);
  const copyCount = deriveCopyCountFromReputation(summary, seedKey);

  return {
    agentDid: seed.did,
    seedKey,
    agentWallet,
    masterWallet,
    tokenAddress,
    deployer: agentWallet,
    agentDeployedAt: deterministicAgentDeployedAt(seedKey),
    behaviorProfile: strategyToBehavior(seed.strategy),
    behaviorSeed: mockHashId(`fleet:behavior:${seedKey}`),
    copyCount,
    winRatePct: seed.winRatePct,
    tvlManagedSim: seed.aumM * 1_000_000,
    isPopular: isPopularCopyCount(copyCount, summary.riskLabel),
  };
}

export const FLEET_AGENTS: FleetAgentRecord[] = FLEET_CATALOG_SEEDS.map(
  (seed, index) => buildFleetRecord(seed, index),
);

const fleetByDid = new Map(
  FLEET_AGENTS.map((record) => [record.agentDid, record]),
);
const fleetBySeedKey = new Map(
  FLEET_AGENTS.map((record) => [record.seedKey.toLowerCase(), record]),
);
const fleetByStorageKey = new Map(
  FLEET_AGENTS.map((record) => [agentDidToStorageKey(record.agentDid), record]),
);

const fleetByAgentWallet = new Map(
  FLEET_AGENTS.map((record) => [record.agentWallet.toLowerCase(), record]),
);

export function getFleetAgentByDid(did: string): FleetAgentRecord | undefined {
  const trimmed = did.trim();
  return fleetByDid.get(trimmed)
    ?? fleetByStorageKey.get(trimmed.toLowerCase())
    ?? fleetBySeedKey.get(trimmed.toLowerCase());
}

/** @deprecated Use getFleetAgentByDid */
export function getFleetAgentByCatalogId(id: string): FleetAgentRecord | undefined {
  return getFleetAgentByDid(id);
}

export function getFleetAgentByWallet(address: string): FleetAgentRecord | undefined {
  return fleetByAgentWallet.get(address.trim().toLowerCase());
}

export function getFleetDeployerForAgentDid(agentDid: string): string {
  return getFleetAgentByDid(agentDid)?.deployer ?? "mxm";
}

/** @deprecated Use getFleetDeployerForAgentDid */
export function getFleetDeployerForCatalogId(catalogAgentId: string): string {
  return getFleetDeployerForAgentDid(catalogAgentId);
}

export function toSatoshiStr(value: number): string {
  return String(Math.round(value * SATOSHI));
}

export const FLEET_LP_COUNTERPARTY = mockEvmAddress("fleet:lp:counterparty");

export const FLEET_CATALOG_AGENT_DIDS = FLEET_CATALOG_SEEDS.map((seed) => seed.did);

/** @deprecated Use FLEET_CATALOG_AGENT_DIDS */
export const FLEET_CATALOG_AGENT_IDS = FLEET_CATALOG_SEEDS.map((seed) => seed.seedKey);
