import { useEffect, useLayoutEffect, useMemo, useRef, useState, type CSSProperties } from "react";
import { scheduleOverlayPanelOpen } from "./overlayPanelEnter";
import { OVERLAY_TIMING, resolveUnmountMs } from "./overlayTiming";

export type UseStaggeredOverlayOptions = {
  isOpen: boolean;
  panelDurationMs: number;
  backdropFadeMs?: number;
  enableBackdrop?: boolean;
  staggerBackdrop?: boolean;
  onAfterUnmount?: () => void;
  /** Drop portal from DOM immediately on close (skip exit timer). */
  unmountOnCloseImmediately?: boolean;
};

export type UseStaggeredOverlayResult = {
  mounted: boolean;
  panelOpen: boolean;
  backdropVisible: boolean;
  backdropStyle: CSSProperties;
};

export function useStaggeredOverlay({
  isOpen,
  panelDurationMs,
  backdropFadeMs = OVERLAY_TIMING.backdropFadeMs,
  enableBackdrop = true,
  staggerBackdrop = true,
  onAfterUnmount,
  unmountOnCloseImmediately = false,
}: UseStaggeredOverlayOptions): UseStaggeredOverlayResult {
  const [mounted, setMounted] = useState(isOpen);
  const [panelOpen, setPanelOpen] = useState(false);
  const [backdropVisible, setBackdropVisible] = useState(false);
  const onAfterUnmountRef = useRef(onAfterUnmount);
  const isOpenRef = useRef(isOpen);
  const mountedRef = useRef(mounted);

  isOpenRef.current = isOpen;
  mountedRef.current = mounted;

  useEffect(() => {
    onAfterUnmountRef.current = onAfterUnmount;
  }, [onAfterUnmount]);

  // Route changes can unmount the owner mid-exit; clear latched content immediately.
  useEffect(() => {
    return () => {
      if (mountedRef.current) {
        onAfterUnmountRef.current?.();
      }
    };
  }, []);

  const effectiveBackdropMs = enableBackdrop ? backdropFadeMs : 0;

  const backdropStyle = useMemo<CSSProperties>(
    () =>
      ({
        "--overlay-backdrop-duration": `${effectiveBackdropMs}ms`,
      }) as CSSProperties,
    [effectiveBackdropMs],
  );

  // Apply close state before paint so the backdrop never captures clicks after close.
  useLayoutEffect(() => {
    if (isOpen) return;
    setPanelOpen(false);
    setBackdropVisible(false);
    if (unmountOnCloseImmediately && mountedRef.current) {
      setMounted(false);
      onAfterUnmountRef.current?.();
    }
  }, [isOpen, unmountOnCloseImmediately]);

  // Mount portal and apply closed panel styles before first paint.
  useLayoutEffect(() => {
    if (!isOpen) return;

    setMounted(true);
    setPanelOpen(false);
    setBackdropVisible(false);

    if (panelDurationMs === 0) {
      setPanelOpen(true);
      if (enableBackdrop && !staggerBackdrop) {
        setBackdropVisible(true);
      }
    }
  }, [isOpen, panelDurationMs, enableBackdrop, staggerBackdrop]);

  // After closed panel is painted, flush layout then add .is-open (Firefox cold mount).
  useEffect(() => {
    if (!isOpen || panelDurationMs === 0) return undefined;

    return scheduleOverlayPanelOpen(() => {
      if (isOpenRef.current) setPanelOpen(true);
    });
  }, [isOpen, panelDurationMs]);

  useEffect(() => {
    if (!isOpen || !panelOpen || !enableBackdrop || !staggerBackdrop) return;

    const timer = window.setTimeout(() => setBackdropVisible(true), panelDurationMs);
    return () => window.clearTimeout(timer);
  }, [isOpen, panelOpen, panelDurationMs, enableBackdrop, staggerBackdrop]);

  useEffect(() => {
    if (!isOpen || !panelOpen || !enableBackdrop || staggerBackdrop) return;

    setBackdropVisible(true);
  }, [isOpen, panelOpen, enableBackdrop, staggerBackdrop]);

  useEffect(() => {
    if (isOpen || !mounted || unmountOnCloseImmediately) return;

    const duration = resolveUnmountMs(panelDurationMs, effectiveBackdropMs);
    const timer = window.setTimeout(() => {
      setMounted(false);
      onAfterUnmountRef.current?.();
    }, duration);

    return () => window.clearTimeout(timer);
  }, [isOpen, mounted, panelDurationMs, effectiveBackdropMs, unmountOnCloseImmediately]);

  return {
    mounted,
    panelOpen,
    backdropVisible: enableBackdrop && backdropVisible,
    backdropStyle,
  };
}

export function useCenteredStaggeredOverlay(
  isOpen: boolean,
  options?: Pick<
    UseStaggeredOverlayOptions,
    | "onAfterUnmount"
    | "backdropFadeMs"
    | "enableBackdrop"
    | "unmountOnCloseImmediately"
  >,
): UseStaggeredOverlayResult {
  return useStaggeredOverlay({
    isOpen,
    panelDurationMs: OVERLAY_TIMING.desktopScaleMs,
    ...options,
  });
}
