import React, { useMemo } from "react";
import {
  getHeaderNavDisplayOrder,
  HEADER_NAV_CATALOG,
  HEADER_NAV_OPTIONAL,
  HEADER_NAV_PINNED,
  moveHeaderNavItem,
  toggleHeaderNavItem,
  type HeaderNavItemId,
  type HeaderNavPrefs,
} from "./headerNavPrefs";

export interface HeaderNavSettingsProps {
  prefs: HeaderNavPrefs;
  onChange: (prefs: HeaderNavPrefs) => void;
}

function HeaderNavSettings({
  prefs,
  onChange,
}: HeaderNavSettingsProps): JSX.Element {
  const visibleItems = prefs.visibleItems;

  const displayOrder = useMemo(
    () => getHeaderNavDisplayOrder(visibleItems),
    [visibleItems],
  );

  const setVisibleItems = (next: HeaderNavItemId[]) => {
    onChange({ visibleItems: next });
  };

  const pinnedId = HEADER_NAV_PINNED[0]!;
  const pinnedLabel = HEADER_NAV_CATALOG[pinnedId].label;

  return (
    <div className="hil-safety-tabs-settings">
      <p className="settings-chart-overlay-hint hil-safety-tabs-settings-intro">
        Applies to the top navigation bar and mobile menu.
      </p>

      <div className="hil-safety-tabs-settings-section">
        <p className="hil-safety-tabs-settings-section-label">Always shown</p>
        <label className="settings-toggle hil-safety-tabs-row hil-safety-tabs-row--pinned">
          <input type="checkbox" checked disabled readOnly />
          <span>{pinnedLabel}</span>
        </label>
      </div>

      <div className="hil-safety-tabs-settings-section">
        <p className="hil-safety-tabs-settings-section-label">Optional pages</p>
        {displayOrder.map((itemId) => {
          if (HEADER_NAV_PINNED.includes(itemId)) return null;

          const isVisible = visibleItems.includes(itemId);
          const visibleIndex = visibleItems.indexOf(itemId);
          const itemLabel = HEADER_NAV_CATALOG[itemId].label;

          return (
            <div
              key={itemId}
              className={`hil-safety-tabs-row${isVisible ? " is-visible" : ""}`}
            >
              <label className="settings-toggle hil-safety-tabs-row-check">
                <input
                  type="checkbox"
                  checked={isVisible}
                  onChange={(e) =>
                    setVisibleItems(
                      toggleHeaderNavItem(
                        visibleItems,
                        itemId,
                        e.target.checked,
                      ),
                    )
                  }
                />
                <span>{itemLabel}</span>
              </label>
              <div className="hil-safety-tabs-row-actions">
                <button
                  type="button"
                  className="hil-safety-tabs-move-btn"
                  aria-label={`Move ${itemLabel} up`}
                  disabled={!isVisible || visibleIndex <= 0}
                  onClick={() =>
                    setVisibleItems(
                      moveHeaderNavItem(visibleItems, itemId, "up"),
                    )
                  }
                >
                  ↑
                </button>
                <button
                  type="button"
                  className="hil-safety-tabs-move-btn"
                  aria-label={`Move ${itemLabel} down`}
                  disabled={
                    !isVisible || visibleIndex >= visibleItems.length - 1
                  }
                  onClick={() =>
                    setVisibleItems(
                      moveHeaderNavItem(visibleItems, itemId, "down"),
                    )
                  }
                >
                  ↓
                </button>
              </div>
            </div>
          );
        })}
        <p className="settings-chart-overlay-hint">
          Hidden:{" "}
          {HEADER_NAV_OPTIONAL.length -
            HEADER_NAV_OPTIONAL.filter((id) => visibleItems.includes(id)).length}{" "}
          of {HEADER_NAV_OPTIONAL.length} optional pages.
        </p>
      </div>
    </div>
  );
}

export default React.memo(HeaderNavSettings);
