/** Satoshi-scaled string (1e8), matching live API position responses. */
function toSatoshiStr(value: number): string {
  return String(Math.round(value * SATOSHI));
}

export type MockPosition = {
  positionId: string;
  bucketId: string;
  marketIndex: string;
  address: string;
  symbol: string;
  /** Satoshi-scaled string (1e8). */
  size: string;
  side: "SIDE_BUY" | "SIDE_SELL";
  averageEntryPrice: string;
  markPrice: string;
  leverage: string;
  unrealizedProfit: string;
  unrealizedLoss: string;
  mmr: string;
  marginBalance: string;
  status: string;
  createdAt: string;
  updatedAt: string;
  liquidationPrice?: string;
  marginMode?: string;
  marginType?: string;
  /** Links to AgentTask.id (hash) when position is agent-managed. */
  agentTaskId?: string | null;
};

