import React, { useRef, useEffect, useLayoutEffect, useCallback } from "react";
import { BubbleTip, type BubbleTipId } from "../../tutorials/bubble-tip";
import { TabHeaderLabel } from "./tab-header-label";
import "./layout.css";

type TabIndicatorState = {
  left: number;
  width: number;
  ready: boolean;
};

export interface TabLayoutHeaderToolBarTab {
  id: string;
  label: string;
  /** Compact single-line label when the tab strip is narrow. Auto-derived when omitted. */
  shortLabel?: string;
  badgeCount?: number;
  badgePulse?: boolean;
  bubbleTipId?: BubbleTipId;
}

export interface TabLayoutHeaderToolBarProps {
  tabs: TabLayoutHeaderToolBarTab[];
  activeTabId: string;
  onTabChange: (id: string) => void;
  /** When true, scrolls the active tab button into view (e.g. horizontal tab bar on phone). */
  scrollActiveTabIntoView?: boolean;
  /** Optional leading control (e.g. mobile chart/tables scroll toggle on trade). */
  leading?: React.ReactNode;
  children?: React.ReactNode;
}

/**
 * Tab section header toolbar – same layout as LayoutHeader (for alignment).
 * Renders tab buttons on the left and actions on the right; all layout lives here.
 */
export function TabLayoutHeaderToolBar({
  tabs,
  activeTabId,
  onTabChange,
  scrollActiveTabIntoView = false,
  leading,
  children,
}: TabLayoutHeaderToolBarProps): JSX.Element {
  const tabRefs = useRef<Map<string, HTMLButtonElement>>(new Map());
  const tabsContainerRef = useRef<HTMLDivElement>(null);
  const indicatorElRef = useRef<HTMLSpanElement>(null);
  const indicatorRef = useRef<TabIndicatorState>({ left: 0, width: 0, ready: false });

  const updateIndicator = useCallback(() => {
    const container = tabsContainerRef.current;
    const activeTab = tabRefs.current.get(activeTabId);
    const indicatorEl = indicatorElRef.current;
    if (!container || !activeTab || !indicatorEl) {
      indicatorRef.current = { left: 0, width: 0, ready: false };
      return;
    }
    const containerRect = container.getBoundingClientRect();
    const tabRect = activeTab.getBoundingClientRect();
    indicatorRef.current = {
      left: tabRect.left - containerRect.left + container.scrollLeft,
      width: tabRect.width,
      ready: true,
    };
    indicatorEl.style.transform = `translateX(${indicatorRef.current.left}px)`;
    indicatorEl.style.width = `${indicatorRef.current.width}px`;
    indicatorEl.style.opacity = indicatorRef.current.ready ? "1" : "0";
  }, [activeTabId]);

  useLayoutEffect(() => {
    updateIndicator();
  }, [updateIndicator, tabs.length]);

  useEffect(() => {
    const container = tabsContainerRef.current;
    if (!container) return;

    const resizeObserver = new ResizeObserver(() => updateIndicator());
    resizeObserver.observe(container);

    container.addEventListener("scroll", updateIndicator, { passive: true });
    window.addEventListener("resize", updateIndicator, { passive: true });

    return () => {
      resizeObserver.disconnect();
      container.removeEventListener("scroll", updateIndicator);
      window.removeEventListener("resize", updateIndicator);
    };
  }, [updateIndicator]);

  useEffect(() => {
    if (!scrollActiveTabIntoView) return;
    tabRefs.current
      .get(activeTabId)
      ?.scrollIntoView({ block: "nearest", inline: "nearest", behavior: "smooth" });
  }, [activeTabId, scrollActiveTabIntoView, tabs.length]);

  return (
    <div className="layout-header tab-section-header">
      {leading ? (
        <div className="tab-section-toolbar-leading">{leading}</div>
      ) : null}
      <div className="tab-section-tabs tab-section-tabs--animated" ref={tabsContainerRef}>
        {tabs.map((tab) => {
          const tabButton = (
            <button
              ref={(el) => {
                if (el) tabRefs.current.set(tab.id, el);
                else tabRefs.current.delete(tab.id);
              }}
              type="button"
              className={`btn-tab terminal-tab ${activeTabId === tab.id ? "active terminal-tab-active" : ""}`}
              onClick={() => onTabChange(tab.id)}
            >
              <TabHeaderLabel full={tab.label} short={tab.shortLabel} />
              {tab.badgeCount != null && tab.badgeCount > 0 ? (
                <span
                  className={`tab-badge${tab.badgePulse ? " tab-badge--pulse" : ""}`}
                >
                  • {tab.badgeCount}
                </span>
              ) : null}
            </button>
          );

          return tab.bubbleTipId ? (
            <BubbleTip key={tab.id} id={tab.bubbleTipId}>
              {tabButton}
            </BubbleTip>
          ) : (
            <React.Fragment key={tab.id}>{tabButton}</React.Fragment>
          );
        })}
        <span ref={indicatorElRef} className="tab-section-tabs-indicator" aria-hidden="true" />
      </div>
      {children && <div className="layout-header-actions">{children}</div>}
    </div>
  );
}
