export type TabLabelKey = keyof typeof TAB_LABELS;

export type TabLabelDef = {
  full: string;
  short?: string;
};

export function getTabLabel(key: TabLabelKey): TabLabelDef {
  return TAB_LABELS[key];
}

export interface ResolveTabLabelsOptions {
  count?: number;
  showCount?: boolean;
}

export interface TabHeaderLabelPair {
  label: string;
  shortLabel?: string;
}

/** Strip trailing inline count suffix: `Positions (42)` → `Positions`. */
export function stripInlineTabCount(label: string): string {
  return label.replace(/\s\(\d+\)$/, "");
}

/**
 * Resolve display labels from the registry. Inline `(N)` counts apply to the full label only.
 */
export function resolveTabLabels(
  key: TabLabelKey,
  options?: ResolveTabLabelsOptions,
): TabHeaderLabelPair {
  const def = TAB_LABELS[key];
  const short = "short" in def ? def.short : undefined;
  const label =
    options?.showCount && options.count != null
      ? `${def.full} (${options.count})`
      : def.full;

  if (!short || short === def.full) {
    return { label };
  }

  return { label, shortLabel: short };
}

/** Display label for terminal tab ids (settings panels, tab order UI). */
export function getTerminalTabLabel(
  id: string,
  options?: { hilMemoryAudit?: boolean },
): string {
  if (id === "memoryAudit" && options?.hilMemoryAudit) {
    return TAB_LABELS.memoryAuditHil.full;
  }
  if (id in TAB_LABELS) {
    return TAB_LABELS[id as TabLabelKey].full;
  }
  return id;
}
