export type AgentAvatarSvgFile = (typeof AGENT_AVATAR_SVG_FILES)[number];

function fnv1a32(input: string): number {
  let hash = 2166136261;
  for (let i = 0; i < input.length; i += 1) {
    hash ^= input.charCodeAt(i);
    hash = Math.imul(hash, 16777619);
  }
  return hash >>> 0;
}

/** Strip optional 0x prefix and lowercase for stable hash evaluation. */
export function normalizeHashForAvatar(hash: string): string {
  return hash.trim().replace(/^0x/i, "").toLowerCase();
}

/**
 * Maps any hash or seed string to a stable index in the avatar SVG catalog.
 * Hex ids use bigint modulo; other strings fall back to FNV-1a.
 */
export function hashToAgentAvatarIndex(
  hash: string,
  catalog: readonly string[] = AGENT_AVATAR_SVG_FILES,
): number {
  if (catalog.length === 0) return 0;

  const normalized = normalizeHashForAvatar(hash);
  if (!normalized) return 0;

  if (/^[0-9a-f]+$/.test(normalized)) {
    const slice = normalized.slice(0, 16);
    let value = 0n;
    for (const ch of slice) {
      value = (value << 4n) | BigInt(parseInt(ch, 16));
    }
    return Number(value % BigInt(catalog.length));
  }

  return fnv1a32(normalized) % catalog.length;
}

/** Resolves a hash to one SVG filename from the agent avatar catalog. */
export function resolveAgentAvatarSvg(
  hash: string,
  catalog: readonly string[] = AGENT_AVATAR_SVG_FILES,
): string {
  const index = hashToAgentAvatarIndex(hash, catalog);
  return catalog[index] ?? catalog[0] ?? "";
}

/** Resolves a hash to a browser-ready public URL for the assigned avatar SVG. */
export function resolveAgentAvatarSvgUrl(
  hash: string,
  basePath: string = AGENT_AVATAR_SVG_BASE_PATH,
  catalog: readonly string[] = AGENT_AVATAR_SVG_FILES,
): string {
  const filename = resolveAgentAvatarSvg(hash, catalog);
  const trimmedBase = basePath.replace(/\/+$/, "");
  return `${trimmedBase}/${filename}`;
}

/**
 * Stable avatar hash seed for any agent identity input (DID, storage/route key,
 * or legacy hex id). Canonical agents always resolve through DID → route param.
 */
export function resolveAgentAvatarSeed(identity: string): string {
  const trimmed = identity.trim();
  if (!trimmed) return "";

  const did = resolveAgentDid(trimmed);
  if (did) return agentDidToRouteParam(did);

  return normalizeHashForAvatar(trimmed);
}

/** Resolves any agent identity input to a browser-ready avatar SVG URL. */
export function resolveAgentAvatarSvgUrlFromIdentity(
  identity: string,
  basePath: string = AGENT_AVATAR_SVG_BASE_PATH,
  catalog: readonly string[] = AGENT_AVATAR_SVG_FILES,
): string {
  return resolveAgentAvatarSvgUrl(
    resolveAgentAvatarSeed(identity),
    basePath,
    catalog,
  );
}
