export type Platform = "macos" | "windows" | "linux";

function isMacPlatform(platform: string): boolean {
  return /Mac|iPhone|iPad|iPod/.test(platform);
}

function isWindowsPlatform(platform: string): boolean {
  return /Win/.test(platform);
}

function isLinuxUserAgent(userAgent: string): boolean {
  return /Linux|X11/.test(userAgent) && !/Android/.test(userAgent);
}

export function detectPlatform(): Platform {
  if (typeof navigator === "undefined") return "macos";

  const uaDataPlatform = (
    navigator as Navigator & { userAgentData?: { platform?: string } }
  ).userAgentData?.platform;

  if (uaDataPlatform) {
    const normalized = uaDataPlatform.toLowerCase();
    if (normalized.includes("mac")) return "macos";
    if (normalized.includes("win")) return "windows";
    if (normalized.includes("linux")) return "linux";
  }

  const platform = navigator.platform ?? "";
  if (isMacPlatform(platform)) return "macos";
  if (isWindowsPlatform(platform)) return "windows";
  if (isLinuxUserAgent(navigator.userAgent)) return "linux";

  return "windows";
}

export function getPrimaryModLabel(platform: Platform = detectPlatform()): string {
  if (platform === "macos") return "⌘";
  return "Ctrl";
}

export function getPlatformHint(platform: Platform = detectPlatform()): string {
  switch (platform) {
    case "macos":
      return "On macOS, ⌘ maps to Command and ⌃ to Control. Fn cannot be bound in the browser.";
    case "windows":
      return "On Windows, Win maps to the Meta key. Fn cannot be bound in the browser.";
    case "linux":
      return "On Linux, Super maps to the Meta key. Defaults match Windows; rebind any modifier combo.";
  }
}
