export type FleetNetworkBackgroundPattern =
  | "circle"
  | "square"
  | "grid"
  | "grid-check";

export type FleetNetworkBackgroundSize = "sm" | "md" | "lg";

export interface AgentRolesPrefs {
  networkBackgroundPattern: FleetNetworkBackgroundPattern;
  networkBackgroundSize: FleetNetworkBackgroundSize;
}

export const DEFAULT_AGENT_ROLES_PREFS: AgentRolesPrefs = {
  networkBackgroundPattern: "square",
  networkBackgroundSize: "md",
};

export const FLEET_NETWORK_BACKGROUND_OPTIONS = [
  { value: "circle", label: "Circle" },
  { value: "square", label: "Square" },
  { value: "grid", label: "Grid" },
  { value: "grid-check", label: "Grid check" },
] as const;

export const FLEET_NETWORK_BACKGROUND_SIZE_OPTIONS = [
  { value: "sm", label: "Small" },
  { value: "md", label: "Medium" },
  { value: "lg", label: "Large" },
] as const;

const VALID_PATTERNS = new Set<FleetNetworkBackgroundPattern>([
  "circle",
  "square",
  "grid",
  "grid-check",
]);

const VALID_SIZES = new Set<FleetNetworkBackgroundSize>(["sm", "md", "lg"]);

export function normalizeAgentRolesPrefs(
  prefs?: Partial<AgentRolesPrefs> | null,
): AgentRolesPrefs {
  if (!prefs) return DEFAULT_AGENT_ROLES_PREFS;

  return {
    networkBackgroundPattern: VALID_PATTERNS.has(
      prefs.networkBackgroundPattern as FleetNetworkBackgroundPattern,
    )
      ? (prefs.networkBackgroundPattern as FleetNetworkBackgroundPattern)
      : DEFAULT_AGENT_ROLES_PREFS.networkBackgroundPattern,
    networkBackgroundSize: VALID_SIZES.has(
      prefs.networkBackgroundSize as FleetNetworkBackgroundSize,
    )
      ? (prefs.networkBackgroundSize as FleetNetworkBackgroundSize)
      : DEFAULT_AGENT_ROLES_PREFS.networkBackgroundSize,
  };
}
