/**
 * Display formatting utilities for numbers, prices, quantities, etc.
 * Provides consistent formatting across all components.
 */

import { fromSatoshi } from "./math";

// Re-export normalizeTimestamp from time.ts for backward compatibility
export { normalizeTimestamp } from "./time";

/**
 * Format a number with specified decimal places
 * @param value - The number to format
 * @param minDecimals - Minimum decimal places (default: 2)
 * @param maxDecimals - Maximum decimal places (default: 2)
 * @param fallback - Value to return if value is invalid (default: "0.00")
 * @returns Formatted string
 */
export function formatNumber(
  value: number | undefined | null,
  minDecimals: number = 2,
  maxDecimals: number = 2,
  fallback: string = "0.00",
): string {
  if (value === undefined || value === null || isNaN(value)) return fallback;
  return value.toLocaleString("en-US", {
    minimumFractionDigits: minDecimals,
    maximumFractionDigits: maxDecimals,
  });
}

function getPriceFractionDigits(price: number): { min: number; max: number } {
  if (price >= 1000) return { min: 0, max: 0 };
  return { min: 2, max: 2 };
}

/**
 * Format a price value (0 decimals when >= 1000, otherwise 2; shows "--" for invalid)
 * @param price - The price to format
 * @returns Formatted price string
 */
export function formatPrice(price: number | undefined | null): string {
  if (price === undefined || price === null || isNaN(price)) return "--";
  const { min, max } = getPriceFractionDigits(price);
  return formatNumber(price, min, max, "--");
}

/**
 * Format orderbook price with tiered precision (low-priced perps need more decimals).
 * e.g. JELLY ~0.008 → at least 4 decimals; sub-cent → up to 8; >= 1000 → no decimals.
 */
export function formatOrderbookPrice(price: number | undefined | null): string {
  if (price === undefined || price === null || isNaN(price)) return "--";
  if (price >= 1000) return formatNumber(price, 0, 0, "--");
  if (price < 0.01) return formatNumber(price, 6, 8, "--");
  if (price < 1) return formatNumber(price, 4, 8, "--");
  return formatNumber(price, 2, 2, "--");
}

/**
 * Format a price with flexible decimal places (0 when >= 1000, otherwise 2-8)
 * @param price - The price to format
 * @returns Formatted price string
 */
export function formatPriceFlexible(price: number | undefined | null): string {
  if (price === undefined || price === null || isNaN(price)) return "--";
  if (price >= 1000) return formatNumber(price, 0, 0, "--");
  return formatNumber(price, 2, 8, "--");
}

/**
 * Format a size/quantity value (3 decimal places)
 * @param size - The size to format
 * @returns Formatted size string
 */
export function formatSize(size: number | undefined | null): string {
  if (size === undefined || size === null || isNaN(size)) return "0.000";
  return formatNumber(size, 3, 3, "0.000");
}

/**
 * Format a quantity value (3-8 decimal places)
 * @param quantity - The quantity to format
 * @returns Formatted quantity string
 */
export function formatQuantity(quantity: number | undefined | null): string {
  if (quantity === undefined || quantity === null || isNaN(quantity))
    return "0";
  return formatNumber(quantity, 3, 8, "0");
}

/**
 * Format a margin value (2 decimal places)
 * @param margin - The margin to format
 * @returns Formatted margin string
 */
export function formatMargin(margin: number | undefined | null): string {
  if (margin === undefined || margin === null || isNaN(margin)) return "0.00";
  return formatNumber(margin, 2, 2, "0.00");
}

/**
 * Format a P/L (Profit/Loss) value (2 decimal places)
 * @param pnl - The P/L to format
 * @returns Formatted P/L string
 */
export function formatPnL(pnl: number | undefined | null): string {
  if (pnl === undefined || pnl === null || isNaN(pnl)) return "0.00";
  return formatNumber(pnl, 2, 2, "0.00");
}

/**
 * Format a currency value (2 decimal places)
 * Alias for formatMargin, but semantically clearer for currency values
 * @param value - The currency value to format
 * @returns Formatted currency string
 */
export function formatCurrency(value: number | undefined | null): string {
  if (value === undefined || value === null || isNaN(value)) return "0.00";
  return formatNumber(value, 2, 2, "0.00");
}

/**
 * Format a percentage value (multiplies by 100, shows 2 decimal places)
 * @param value - The ratio value (0.75 for 75%)
 * @returns Formatted percentage string (e.g., "75.00%")
 */
export function formatPercentage(value: number | undefined | null): string {
  if (value === undefined || value === null || isNaN(value)) return "0%";
  return `${(value * 100).toFixed(2)}%`;
}

/**
 * Format a Satoshi-like number (convert from satoshi scale, format with 8 decimals, trim trailing zeros)
 * Used for blockchain-based values that are stored in smallest units
 * Uses fromSatoshi from math.ts for consistent conversion with BigInt precision
 * @param value - The Satoshi value to format (number or string)
 * @returns Formatted decimal string
 */
export function formatSatoshiNumber(
  value: number | string | undefined | null,
): string {
  if (value === undefined || value === null) return "0";

  // Handle string values that might be invalid
  if (typeof value === "string") {
    const trimmed = value.trim();
    if (trimmed === "" || isNaN(Number(trimmed))) {
      return "0";
    }
    // Ensure it's a valid integer string for BigInt (no decimal points)
    // If it has decimals, round it (satoshi values should be integers)
    const intValue = trimmed.includes(".")
      ? Math.floor(Number(trimmed)).toString()
      : trimmed;
    
    try {
      const decimal = fromSatoshi(intValue);
      // Format with 8 decimals, then trim trailing zeros and decimal point if needed
      return decimal.toFixed(8).replace(/\.?0+$/, "");
    } catch (error) {
      // Fallback for invalid values (e.g., invalid BigInt syntax)
      return "0";
    }
  }

  // Handle number values - convert to integer string (satoshi should be integer)
  if (typeof value === "number") {
    if (isNaN(value) || !isFinite(value)) {
      return "0";
    }
    // Convert to integer string (satoshi values should be whole numbers)
    const intValue = Math.floor(value).toString();
    
    try {
      const decimal = fromSatoshi(intValue);
      // Format with 8 decimals, then trim trailing zeros and decimal point if needed
      return decimal.toFixed(8).replace(/\.?0+$/, "");
    } catch (error) {
      // Fallback for invalid values
      return "0";
    }
  }

  return "0";
}

/**
 * Format a price from Satoshi format (convert from satoshi scale, add thousands separators)
 * Uses fromSatoshi from math.ts for consistent conversion
 * @param price - The Satoshi price value (number or string)
 * @returns Formatted price string with thousands separators
 */
export function formatPriceFromSatoshi(
  price: number | string | undefined | null,
): string {
  if (price === undefined || price === null) return "--";

  // Handle string values that might be invalid
  if (
    typeof price === "string" &&
    (price.trim() === "" || isNaN(Number(price)))
  ) {
    return "--";
  }

  try {
    const formatted = formatSatoshiNumber(price);
    // Add thousands separators for readability
    const parts = formatted.split(".");
    parts[0] = parts[0].replace(/\B(?=(\d{3})+(?!\d))/g, ",");
    return parts.join(".");
  } catch (error) {
    return "--";
  }
}

/**
 * Format a quantity from Satoshi format (convert from satoshi scale)
 * Uses fromSatoshi from math.ts for consistent conversion
 * @param quantity - The Satoshi quantity value (number or string)
 * @returns Formatted quantity string
 */
export function formatQuantityFromSatoshi(
  quantity: number | string | undefined | null,
): string {
  if (quantity === undefined || quantity === null) return "0";

  // Handle string values that might be invalid
  if (
    typeof quantity === "string" &&
    (quantity.trim() === "" || isNaN(Number(quantity)))
  ) {
    return "0";
  }

  try {
    return formatSatoshiNumber(quantity);
  } catch (error) {
    return "0";
  }
}

/**
 * Format leverage from satoshi to decimal with appropriate precision
 * Leverage is typically shown as whole numbers or 1-2 decimal places (e.g., "10x", "1.5x")
 * @param leverage - The leverage value in satoshi format (number or string)
 * @param fallback - Value to return if leverage is invalid (default: "--")
 * @returns Formatted leverage string (without trailing zeros)
 */
export function formatLeverage(
  leverage: number | string | undefined | null,
  fallback: string = "--",
): string {
  if (leverage === undefined || leverage === null) return fallback;

  try {
    // Convert from satoshi to decimal
    const decimal =
      typeof leverage === "string" || typeof leverage === "number"
        ? fromSatoshi(typeof leverage === "string" ? leverage : String(leverage))
        : 0;

    // Format with up to 2 decimal places, remove trailing zeros
    return decimal.toFixed(2).replace(/\.?0+$/, "");
  } catch (error) {
    return fallback;
  }
}

/**
 * Format a percentage value from Satoshi format
 * Converts from satoshi scale first, then formats as percentage (multiplies by 100, shows 2 decimal places)
 * Uses fromSatoshi from math.ts for consistent conversion with BigInt precision
 * @param value - The Satoshi value to format (number or string)
 * @param fallback - Value to return if value is invalid (default: "0%")
 * @returns Formatted percentage string (e.g., "75.00%")
 * 
 * @example
 * formatSatoshiPercent("1000000") // "0.01%" (0.0001 * 100)
 * formatSatoshiPercent("100000000") // "1.00%" (0.01 * 100)
 * formatSatoshiPercent(150000000) // "1.50%" (0.015 * 100)
 */
export function formatSatoshiPercent(
  value: number | string | undefined | null,
  fallback: string = "0%",
): string {
  if (value === undefined || value === null) return fallback;

  // Handle string values that might be invalid
  if (typeof value === "string") {
    const trimmed = value.trim();
    if (trimmed === "" || isNaN(Number(trimmed))) {
      return fallback;
    }
    // Ensure it's a valid integer string for BigInt (no decimal points)
    // If it has decimals, we'll round it (satoshi values should be integers)
    const intValue = trimmed.includes(".")
      ? Math.floor(Number(trimmed)).toString()
      : trimmed;
    
    try {
      const decimal = fromSatoshi(intValue);
      return formatPercentage(decimal);
    } catch (error) {
      return fallback;
    }
  }

  // Handle number values - convert to integer string (satoshi should be integer)
  if (typeof value === "number") {
    if (isNaN(value) || !isFinite(value)) {
      return fallback;
    }
    // Convert to integer string (satoshi values should be whole numbers)
    const intValue = Math.floor(value).toString();
    
    try {
      const decimal = fromSatoshi(intValue);
      return formatPercentage(decimal);
    } catch (error) {
      return fallback;
    }
  }

  return fallback;
}

/**
 * Format large numbers with K (thousands) and M (millions) suffixes
 * @param value - The number to format
 * @returns Formatted string (e.g., "3.2M", "1.5K", "123.45")
 */
export function formatLargeNumber(value: number): string {
  if (isNaN(value)) return "0";
  if (value >= 1000000) {
    return `${(value / 1000000).toFixed(1)}M`;
  }
  if (value >= 1000) {
    return `${(value / 1000).toFixed(1)}K`;
  }
  return value.toFixed(2);
}

/**
 * Shorten an ID or address for display purposes
 * Shows first N characters and last M characters with ellipsis in between
 * @param id - The ID or address to shorten
 * @param startChars - Number of characters to show at the start (default: 6)
 * @param endChars - Number of characters to show at the end (default: 4)
 * @param fallback - Value to return if id is invalid (default: "--")
 * @returns Shortened ID string (e.g., "abc123...xyz789")
 */
export function shortenId(
  id: string | undefined | null,
  startChars: number = 6,
  endChars: number = 4,
  fallback: string = "--",
): string {
  if (!id || typeof id !== "string") return fallback;
  
  // If the ID is short enough, return it as-is
  if (id.length <= startChars + endChars) return id;
  
  // Return shortened version: first N chars + "..." + last M chars
  return `${id.slice(0, startChars)}...${id.slice(-endChars)}`;
}

const DEPLOYER_LABEL_MAX_LEN = 8;

/**
 * Compact deployer label for ticker selection pills (max 8 chars, e.g. "morpheum").
 * Long EVM addresses are truncated to the first 8 characters; short brand labels pass through.
 */
export function formatDeployerLabel(deployer: string): string {
  if (!deployer) return deployer;
  if (deployer.startsWith("0x") && deployer.length > DEPLOYER_LABEL_MAX_LEN) {
    return deployer.slice(0, DEPLOYER_LABEL_MAX_LEN);
  }
  return deployer;
}
