import { detectPlatform, type Platform } from "./platform";
import type { KeyboardBinding, KeyboardShortcutPrefs, ShortcutActionId } from "./types";

function primaryModBinding(
  key: string,
  platform: Platform,
  options?: { excludeShift?: boolean },
): KeyboardBinding {
  const useMeta = platform === "macos";
  return {
    key,
    meta: useMeta,
    ctrl: !useMeta,
    alt: false,
    shift: false,
    ...options,
  };
}

export function getDefaultKeyboardShortcuts(
  platform: Platform = detectPlatform(),
): KeyboardShortcutPrefs {
  return {
    toggleTickerSelection: primaryModBinding("k", platform),
    toggleAgentConsole: primaryModBinding("s", platform, { excludeShift: true }),
    openIntentComposer: primaryModBinding("e", platform),
    switchLayoutClassic: primaryModBinding("1", platform),
    switchLayoutCompact: primaryModBinding("2", platform),
    switchLayoutHighAgency: primaryModBinding("3", platform),
    switchLayoutHumanInLoop: primaryModBinding("4", platform),
    intentSubmitValidate: primaryModBinding("enter", platform),
    openWalletMenu: primaryModBinding("j", platform),
  };
}

export function getDefaultBindingForAction(
  actionId: ShortcutActionId,
  platform: Platform = detectPlatform(),
): KeyboardBinding {
  return { ...getDefaultKeyboardShortcuts(platform)[actionId] };
}

export function isKeyboardBinding(value: unknown): value is KeyboardBinding {
  if (!value || typeof value !== "object") return false;
  const binding = value as Partial<KeyboardBinding>;
  return (
    typeof binding.key === "string" &&
    binding.key.length > 0 &&
    typeof binding.meta === "boolean" &&
    typeof binding.ctrl === "boolean" &&
    typeof binding.alt === "boolean" &&
    typeof binding.shift === "boolean"
  );
}

function isLegacyOpenIntentComposerBinding(binding: KeyboardBinding): boolean {
  return (
    binding.key === "a" &&
    !binding.shift &&
    !binding.alt &&
    (binding.meta || binding.ctrl)
  );
}

export function mergeKeyboardShortcuts(
  parsed: Partial<Record<ShortcutActionId, unknown>>,
  platform: Platform = detectPlatform(),
): KeyboardShortcutPrefs {
  const defaults = getDefaultKeyboardShortcuts(platform);
  const merged = { ...defaults };

  for (const actionId of Object.keys(defaults) as ShortcutActionId[]) {
    const candidate = parsed[actionId];
    if (isKeyboardBinding(candidate)) {
      merged[actionId] = {
        ...candidate,
        key: candidate.key.toLowerCase(),
      };
    }
  }

  // Intent composer moved from Mod+A → Mod+E; upgrade persisted old defaults.
  if (isLegacyOpenIntentComposerBinding(merged.openIntentComposer)) {
    merged.openIntentComposer = defaults.openIntentComposer;
  }

  return merged;
}
