// ============================================================================
// TYPE DECLARATION BREAKDOWN
// ============================================================================

/**
 * LayoutConfigLest (Note: Likely typo - should be "LayoutConfigList")
 *
 * Type Structure:
 *   Array<[number, number, number, number]>
 *
 * Breakdown:
 *   1. Array - A JavaScript/TypeScript array type
 *   2. [number, number, number, number] - A tuple type with exactly 4 elements
 *      - All elements must be of type `number`
 *      - The tuple has a fixed length of 4 (not variable)
 *      - Order matters: [x, y, w, h]
 *
 * Tuple Element Meanings:
 *   [0] - x: number  → Horizontal position (column index, 0-based)
 *   [1] - y: number  → Vertical position (row index, 0-based)
 *   [2] - w: number  → Width (number of columns the item spans)
 *   [3] - h: number  → Height (number of rows the item spans)
 *
 * Example:
 *   [0, 0, 8, 16] means:
 *     - Start at column 0, row 0
 *     - Span 8 columns wide
 *     - Span 16 rows tall
 *
 * Type Safety:
 *   - TypeScript enforces that each array element is a tuple of exactly 4 numbers
 *   - Prevents: wrong length, wrong types, missing elements
 *   - Allows: any number of tuples in the array
 */
export type LayoutDefinition = [number, number, number, number];
export type LayoutConfigLest = Array<LayoutDefinition>;

