/** Phone breakpoints where trading widgets are hidden */
export const MOBILE_BREAKPOINTS = ["xs", "xxs"] as const;

/** Tablet breakpoints — iPad landscape (md) and portrait (sm) */
export const TABLET_BREAKPOINTS = ["md", "sm"] as const;

export function isTabletBreakpoint(breakpoint: string): boolean {
  return (TABLET_BREAKPOINTS as readonly string[]).includes(breakpoint);
}

export function isMobileBreakpoint(breakpoint: string): boolean {
  return (MOBILE_BREAKPOINTS as readonly string[]).includes(breakpoint);
}

/** Breakpoints where bucket row double-click extract panel is enabled */
export const BUCKET_EXTRACT_ENABLED_BREAKPOINTS = ["lg", "md"] as const;

export function isBucketExtractEnabled(
  isMobile: boolean,
  layoutBreakpoint: string,
): boolean {
  if (isMobile) return false;
  return (BUCKET_EXTRACT_ENABLED_BREAKPOINTS as readonly string[]).includes(
    layoutBreakpoint,
  );
}

/** Orderbook, TradePrice, TradeOperation, and unused placeholder slots — hidden on MOBILE_BREAKPOINTS */
export const MOBILE_HIDDEN_SLOTS = [2, 3, 4, 6, 7, 8] as const;

export function isSlotVisible(breakpoint: string, slotIndex: number): boolean {
  if ((MOBILE_BREAKPOINTS as readonly string[]).includes(breakpoint)) {
    return !(MOBILE_HIDDEN_SLOTS as readonly number[]).includes(slotIndex);
  }
  return true;
}

