/** Classic ticker slot height per breakpoint (matches conflayout slot 0) */
export type LayoutBreakpoint = "lg" | "md" | "sm" | "xs" | "xxs";

export const CLASSIC_TICKER_H: Record<LayoutBreakpoint, number> = {
  lg: 4,
  md: 5,
  sm: 5,
  xs: 3,
  xxs: 3,
};

/** Compact ticker slot height per breakpoint (no favorites bar) */
export const COMPACT_TICKER_H: Record<LayoutBreakpoint, number> = {
  lg: 2,
  md: 3,
  sm: 3,
  xs: 2,
  xxs: 2,
};

/** Compact ticker slot height when the 24px favorites bar is shown */
export const COMPACT_TICKER_H_WITH_FAVORITES: Record<LayoutBreakpoint, number> = {
  lg: COMPACT_TICKER_H.lg + 1,
  md: COMPACT_TICKER_H.md + 1,
  sm: COMPACT_TICKER_H.sm + 1,
  xs: COMPACT_TICKER_H.xs + 1,
  xxs: COMPACT_TICKER_H.xxs + 1,
};

export function getCompactTickerHeight(
  breakpoint: LayoutBreakpoint,
  showFavoritesBar: boolean,
): number {
  return showFavoritesBar
    ? COMPACT_TICKER_H_WITH_FAVORITES[breakpoint]
    : COMPACT_TICKER_H[breakpoint];
}

/** Slots that shift down when the mobile ticker expands (chart + tabs) */
export const MOBILE_TICKER_PUSH_SLOTS = [1, 5] as const;

/**
 * Shrinks ticker slot height in compact layout and shifts items below upward.
 */
export function patchCompactTickerLayout(
  layout: LayoutConfigLest,
  breakpoint: LayoutBreakpoint,
  compact: boolean,
  showFavoritesBar = false,
): LayoutConfigLest {
  if (!compact) return layout;

  const classicH = CLASSIC_TICKER_H[breakpoint];
  const compactH = getCompactTickerHeight(breakpoint, showFavoritesBar);
  const delta = compactH - classicH;
  if (delta === 0) return layout;

  const tickerSlot = layout[TICKER_SLOT_INDEX];
  if (!tickerSlot) return layout;

  const tickerY = tickerSlot[1];
  const tickerEndY = tickerY + classicH;

  return layout.map(([x, y, w, h], i) => {
    if (i === TICKER_SLOT_INDEX) return [x, y, w, compactH];
    if (w === 0 && h === 0) return [x, y, w, h];
    if (y >= tickerEndY) return [x, y + delta, w, h];
    return [x, y, w, h];
  });
}

/**
 * On lg desktop compact layout: ticker spans chart width only; orderbook and
 * trade panels start at y=0. Orderbook height matches chart bottom; trade panel
 * height matches tab section bottom (full right column).
 */
export function patchCompactDesktopColumnLayout(
  layout: LayoutConfigLest,
  breakpoint: LayoutBreakpoint,
  compact: boolean,
  showFavoritesBar = false,
): LayoutConfigLest {
  if (!compact || breakpoint !== "lg") return layout;

  const chartSlot = layout[CHART_SLOT_INDEX];
  if (!chartSlot) return layout;

  const compactH = getCompactTickerHeight(breakpoint, showFavoritesBar);
  const [chartX, chartY, chartW, chartH] = chartSlot;
  const orderbookPanelH = chartY + chartH;

  const tabSlot = layout[4];
  const tradePanelH = tabSlot ? tabSlot[1] + tabSlot[3] : orderbookPanelH;

  return layout.map(([x, y, w, h], i) => {
    if (i === TICKER_SLOT_INDEX) {
      return [chartX, 0, chartW, compactH];
    }
    if (i === COMPACT_DESKTOP_SIDE_SLOTS[0]) {
      if (w === 0 && h === 0) return [x, y, w, h];
      return [x, 0, w, orderbookPanelH];
    }
    if (i === COMPACT_DESKTOP_SIDE_SLOTS[1]) {
      if (w === 0 && h === 0) return [x, y, w, h];
      return [x, 0, w, tradePanelH];
    }
    return [x, y, w, h];
  });
}

/**
 * Patches a collapsed mobile layout tuple list for ticker expand/collapse.
 * Operates on the collapsed base layout; increases slot 0 height and pushes
 * items at or below the ticker downward by the height delta.
 */
export function patchMobileTickerLayout(
  layout: LayoutConfigLest,
  expanded: boolean,
  collapsedH: number = MOBILE_TICKER_COLLAPSED_H,
): LayoutConfigLest {
  const targetH = expanded ? MOBILE_TICKER_EXPANDED_H : collapsedH;
  const delta = targetH - collapsedH;
  const tickerEndY =
    layout[TICKER_SLOT_INDEX][1] + collapsedH;

  return layout.map(([x, y, w, h], i) => {
    if (i === TICKER_SLOT_INDEX) return [x, y, w, targetH];
    if (w === 0 && h === 0) return [x, y, w, h];
    if (y >= tickerEndY) return [x, y + delta, w, h];
    return [x, y, w, h];
  });
}

/**
 * Grows Human-in-Loop SafetyHeader slot 0 when the guarded hero expands;
 * pushes items at or below the header downward by the height delta.
 */
export function patchSafetyHeaderExpandLayout(
  layout: LayoutConfigLest,
  expanded: boolean,
  collapsedH: number = SAFETY_HEADER_COLLAPSED_H,
  expandedH: number = SAFETY_HEADER_EXPANDED_H,
): LayoutConfigLest {
  const targetH = expanded ? expandedH : collapsedH;
  const delta = targetH - collapsedH;
  const headerSlot = layout[TICKER_SLOT_INDEX];
  if (!headerSlot) return layout;

  const headerEndY = headerSlot[1] + collapsedH;

  return layout.map(([x, y, w, h], i) => {
    if (i === TICKER_SLOT_INDEX) return [x, y, w, targetH];
    if (w === 0 && h === 0) return [x, y, w, h];
    if (y >= headerEndY) return [x, y + delta, w, h];
    return [x, y, w, h];
  });
}

/**
 * Grows High-Agency slot 0 when a T4 incident banner is shown;
 * keeps slot 3 flush to the tabs band (deck bottom === tabs start);
 * co-grows slot 6 and repositions slot 3 when escalated spotlight is at y=0;
 * pushes items at or below the header downward by the height delta.
 */
export function patchHighAgencyHeaderExpandLayout(
  layout: LayoutConfigLest,
  expanded: boolean,
  collapsedH: number = HIGH_A_HEADER_COLLAPSED_H,
  expandedH: number = HIGH_A_HEADER_EXPANDED_H,
): LayoutConfigLest {
  const delta = (expanded ? expandedH : collapsedH) - collapsedH;
  const patched = patchSafetyHeaderExpandLayout(
    layout,
    expanded,
    collapsedH,
    expandedH,
  );
  const deckSlot = patched[3];
  const spotlightSlot = patched[6];
  const tabsSlot = patched[4];

  if (!deckSlot || !tabsSlot) return patched;

  const tabsStartY = tabsSlot[1];

  if (
    spotlightSlot &&
    spotlightSlot[1] === 0 &&
    spotlightSlot[2] > 0 &&
    spotlightSlot[3] > 0
  ) {
    const [sx, sy, sw, sh] = spotlightSlot;
    const newSpotlightH = sh + delta;
    const deckY = sy + newSpotlightH;
    return patched.map(([x, y, w, h], i) => {
      if (i === 6) return [sx, sy, sw, newSpotlightH];
      if (i === 3) return [x, deckY, w, tabsStartY - deckY];
      return [x, y, w, h];
    });
  }

  if (deckSlot[1] === 0) {
    return patched.map(([x, y, w, h], i) => {
      if (i === 3) return [x, y, w, tabsStartY - y];
      return [x, y, w, h];
    });
  }

  return patched;
}

