/**
 * Returns the bottom row index (y + h) for non-collapsed layout items.
 * Used to verify react-grid-layout container height matches visible content.
 */
export function getLayoutBottomRow(layout: LayoutConfigLest): number {
  return layout.reduce((max, [x, y, w, h]) => {
    if (w === 0 && h === 0) return max;
    return Math.max(max, y + h);
  }, 0);
}

function isCollapsedLayoutItem([, , w, h]: LayoutDefinition): boolean {
  return w === 0 && h === 0;
}

/**
 * True when two layout tuples occupy overlapping grid cells.
 */
export function layoutItemsCollide(
  a: LayoutDefinition,
  b: LayoutDefinition,
): boolean {
  if (isCollapsedLayoutItem(a) || isCollapsedLayoutItem(b)) return false;
  const [ax, ay, aw, ah] = a;
  const [bx, by, bw, bh] = b;
  if (ax + aw <= bx || bx + bw <= ax) return false;
  if (ay + ah <= by || by + bh <= ay) return false;
  return true;
}

/**
 * Throws when any non-collapsed items in a layout overlap.
 */
export function assertNoLayoutOverlap(
  layout: LayoutConfigLest,
  label = "layout",
): void {
  for (let i = 0; i < layout.length; i++) {
    for (let j = i + 1; j < layout.length; j++) {
      const left = layout[i];
      const right = layout[j];
      if (!left || !right) continue;
      if (layoutItemsCollide(left, right)) {
        throw new Error(
          `${label}: slots ${i} ${JSON.stringify(left)} and ${j} ${JSON.stringify(right)} overlap`,
        );
      }
    }
  }
}

/**
 * Collapses grid slots to [0,0,0,0] so react-grid-layout does not reserve height.
 */
export function patchCollapseSlots(
  layout: LayoutConfigLest,
  slotIndices: readonly number[],
): LayoutConfigLest {
  return layout.map(([x, y, w, h], i) =>
    slotIndices.includes(i) ? [0, 0, 0, 0] : [x, y, w, h],
  );
}

