function applySlotLayoutPatch(
  layout: LayoutConfigLest,
  patches: Partial<Record<number, LayoutDefinition>>,
): LayoutConfigLest {
  return layout.map(([x, y, w, h], i) => {
    const patch = patches[i];
    return patch ?? [x, y, w, h];
  });
}

/**
 * High-Agency Commander layout (layout3): dominant chart, vertical orderbook,
 * narrow AgentCommandDeck in the right column, full-width agent-first tabs.
 */
export function patchHighAgencyLayout(
  layout: LayoutConfigLest,
  breakpoint: LayoutBreakpoint = "lg",
): LayoutConfigLest {
  const patches = HIGH_AGENCY_SLOT_LAYOUTS[breakpoint];
  if (!patches || Object.keys(patches).length === 0) return layout;
  return applySlotLayoutPatch(layout, patches);
}

/**
 * High-Agency escalated layout: mounts ExceptionSpotlight in slot 6 above slot 3
 * in the right column (lg). Calm state collapses slot 6.
 */
export function patchHighAgencyEscalationLayout(
  layout: LayoutConfigLest,
  breakpoint: LayoutBreakpoint = "lg",
  escalated = false,
): LayoutConfigLest {
  if (!escalated) {
    return applySlotLayoutPatch(layout, { 6: [0, 0, 0, 0] });
  }
  const patches = HIGH_AGENCY_ESCALATED_SLOT_LAYOUTS[breakpoint];
  if (!patches || Object.keys(patches).length === 0) return layout;
  return applySlotLayoutPatch(layout, patches);
}

/**
 * Human-in-Loop layout (layout4): safety header band, risk-augmented orderbook,
 * GuardrailCockpit in the right column, safety-first tabs.
 */
export function patchHumanInLoopLayout(
  layout: LayoutConfigLest,
  breakpoint: LayoutBreakpoint = "lg",
): LayoutConfigLest {
  const patches = HUMAN_IN_LOOP_SLOT_LAYOUTS[breakpoint];
  if (!patches || Object.keys(patches).length === 0) return layout;
  return applySlotLayoutPatch(layout, patches);
}

function patchBreakpointLayoutForTradePage(
  breakpoint: LayoutBreakpoint,
  layout: LayoutConfigLest,
  expanded: boolean,
  compactLayout: boolean,
  showCompactFavoritesBar = false,
  tradingMode: TradingMode = "proTerminal",
  safetyHeaderExpanded = false,
  highAgencyHeaderExpanded = false,
  vaultScopeActive = false,
): LayoutConfigLest {
  const showFavoritesBar = compactLayout && showCompactFavoritesBar;
  let patched = patchCompactTickerLayout(
    layout,
    breakpoint,
    compactLayout,
    showFavoritesBar,
  );
  patched = patchCompactDesktopColumnLayout(
    patched,
    breakpoint,
    compactLayout,
    showFavoritesBar,
  );
  if (tradingMode === "humanInLoop") {
    if (breakpoint === "md" || breakpoint === "sm") {
      patched = patchSafetyHeaderExpandLayout(
        patched,
        safetyHeaderExpanded,
        SAFETY_HEADER_COLLAPSED_H,
        SAFETY_HEADER_EXPANDED_H,
      );
    } else if (breakpoint === "xs" || breakpoint === "xxs") {
      patched = patchSafetyHeaderExpandLayout(
        patched,
        safetyHeaderExpanded,
        SAFETY_HEADER_COLLAPSED_H,
        SAFETY_HEADER_EXPANDED_H_MOBILE,
      );
    }
  } else if (tradingMode === "highAgency" && highAgencyHeaderExpanded) {
    patched = patchHighAgencyHeaderExpandLayout(
      patched,
      true,
      HIGH_A_HEADER_COLLAPSED_H,
      HIGH_A_HEADER_EXPANDED_H,
    );
  } else if (breakpoint === "xs" || breakpoint === "xxs") {
    const collapsedH = compactLayout
      ? getCompactTickerHeight(breakpoint, showFavoritesBar)
      : MOBILE_TICKER_COLLAPSED_H;
    patched = patchMobileTickerLayout(patched, expanded, collapsedH);
  }
  return patched;
}

import type { TradingMode } from "./tradeLayoutMode.ts";

/**
 * Builds per-breakpoint layout configs for the trade page, collapsing unused
 * placeholder slots so react-grid-layout height matches visible content only.
 */
export function buildTradeResponsiveLayoutConfig(
  expanded: boolean,
  jellyComparisonActive = false,
  compactLayout = false,
  showCompactFavoritesBar = false,
  tradingMode: TradingMode = "proTerminal",
  safetyHeaderExpanded = false,
  highAgencyEscalated = false,
  highAgencyHeaderExpanded = false,
  vaultScopeActive = false,
): ResponsiveLayoutConfig {
  const isProTerminal = tradingMode === "proTerminal";
  const effectiveCompact = isProTerminal && compactLayout;
  const effectiveJelly = isProTerminal && jellyComparisonActive;

  let lgBase = designatedResponsiveLayouts.lg;
  if (tradingMode === "highAgency") {
    lgBase = patchHighAgencyLayout(lgBase, "lg");
    lgBase = patchHighAgencyEscalationLayout(lgBase, "lg", highAgencyEscalated);
  } else if (tradingMode === "humanInLoop") {
    lgBase = patchHumanInLoopLayout(lgBase, "lg");
  } else {
    lgBase = patchDesktopTradesPanelLayout(lgBase);
    if (effectiveJelly) {
      lgBase = patchJellyDesktopLayout(lgBase);
    }
  }

  let lg = patchBreakpointLayoutForTradePage(
    "lg",
    lgBase,
    expanded,
    effectiveCompact,
    showCompactFavoritesBar,
    tradingMode,
    safetyHeaderExpanded,
    highAgencyHeaderExpanded,
    vaultScopeActive,
  );
  if (!effectiveJelly) {
    const collapseSlots: number[] =
      tradingMode === "highAgency" && highAgencyEscalated
        ? [7, 8]
        : [...DESKTOP_PLACEHOLDER_SLOTS];
    lg = patchCollapseSlots(lg, collapseSlots);
  } else {
    lg = patchCollapseSlots(lg, [8]);
  }

  let mdBase = designatedResponsiveLayouts.md;
  if (tradingMode === "highAgency") {
    mdBase = patchHighAgencyLayout(mdBase, "md");
    mdBase = patchHighAgencyEscalationLayout(mdBase, "md", highAgencyEscalated);
  } else if (tradingMode === "humanInLoop") {
    mdBase = patchHumanInLoopLayout(mdBase, "md");
  }

  let md = patchBreakpointLayoutForTradePage(
    "md",
    mdBase,
    expanded,
    effectiveCompact,
    showCompactFavoritesBar,
    tradingMode,
    safetyHeaderExpanded,
    highAgencyHeaderExpanded,
    vaultScopeActive,
  );
  md = patchCollapseSlots(
    md,
    tradingMode === "highAgency" && highAgencyEscalated
      ? [7, 8]
      : [...DESKTOP_PLACEHOLDER_SLOTS],
  );

  let smBase = designatedResponsiveLayouts.sm;
  if (tradingMode === "highAgency") {
    smBase = patchHighAgencyLayout(smBase, "sm");
    smBase = patchHighAgencyEscalationLayout(smBase, "sm", highAgencyEscalated);
  } else if (tradingMode === "humanInLoop") {
    smBase = patchHumanInLoopLayout(smBase, "sm");
  }

  let sm = patchBreakpointLayoutForTradePage(
    "sm",
    smBase,
    expanded,
    effectiveCompact,
    showCompactFavoritesBar,
    tradingMode,
    safetyHeaderExpanded,
    highAgencyHeaderExpanded,
    vaultScopeActive,
  );
  sm = patchCollapseSlots(sm, DESKTOP_PLACEHOLDER_SLOTS);

  return {
    ...designatedResponsiveLayouts,
    lg,
    md,
    sm,
    xs: patchBreakpointLayoutForTradePage(
      "xs",
      designatedResponsiveLayouts.xs,
      expanded,
      effectiveCompact,
      showCompactFavoritesBar,
      tradingMode,
      safetyHeaderExpanded,
      highAgencyHeaderExpanded,
      vaultScopeActive,
    ),
    xxs: patchBreakpointLayoutForTradePage(
      "xxs",
      designatedResponsiveLayouts.xxs,
      expanded,
      effectiveCompact,
      showCompactFavoritesBar,
      tradingMode,
      safetyHeaderExpanded,
      highAgencyHeaderExpanded,
      vaultScopeActive,
    ),
  };
}

/** Grid slot index for TabSection on xs/xxs (desktop tabs use slot 4). */
export const TRADE_MOBILE_TAB_SLOT_INDEX = 5;

export const TRADE_MENUBAR_HEIGHT = 54;
/** Matches `.App-dex-content--mobile-trade-footer` padding-bottom. */
export const TRADE_MOBILE_FOOTER_PX = 64;
/** Mobile TabSection toolbar strip — peek above fixed trade footer at chart scroll rest. */
export const TRADE_MOBILE_TAB_TOOLBAR_PX = 48;
export const TRADE_VIEWPORT_FUDGE_PX = 4;

export const TRADE_MOBILE_CHART_ROWS_MIN = 12;
export const TRADE_MOBILE_CHART_ROWS_MAX = 40;
export const TRADE_MOBILE_TAB_ROWS_MIN = 12;
export const TRADE_MOBILE_TAB_ROWS_MAX = 35;
/** Extra tab rows so the sentinel can scroll up to the menubar sticky band. */
export const TRADE_MOBILE_SCROLL_SLACK_ROWS = 1;

function tradeGridRowUnit(): number {
  return GRID_ROW_HEIGHT + GRID_MARGIN_Y;
}

export function tradeGridRowsToPx(rows: number): number {
  if (rows <= 0) {
    return 0;
  }
  return rows * GRID_ROW_HEIGHT + (rows - 1) * GRID_MARGIN_Y;
}

function pxToTradeGridRows(px: number): number {
  const unit = tradeGridRowUnit();
  return Math.max(1, Math.floor((px + GRID_MARGIN_Y) / unit));
}

function pxToTradeGridRowsCeil(px: number): number {
  const unit = tradeGridRowUnit();
  return Math.max(1, Math.ceil(px / unit));
}

/**
 * Chart rows for xs/xxs — fills the shell viewport minus ticker, fixed footer band,
 * and one mobile tab-toolbar strip peek (slot 5 / desktop slot 4 toolbar).
 */
export function computeTradeMobileChartRows(
  viewportHeight: number,
  tickerRows: number,
  menubarHeight = TRADE_MENUBAR_HEIGHT,
  footerPx = TRADE_MOBILE_FOOTER_PX,
  tabToolbarPx = TRADE_MOBILE_TAB_TOOLBAR_PX,
): number {
  const visibleStackPx =
    viewportHeight - menubarHeight - footerPx - TRADE_VIEWPORT_FUDGE_PX;
  const tickerPx = tradeGridRowsToPx(tickerRows);
  const chartPx = Math.max(
    tradeGridRowUnit(),
    visibleStackPx - tickerPx - tabToolbarPx,
  );
  const rows = pxToTradeGridRowsCeil(chartPx);
  return Math.max(
    TRADE_MOBILE_CHART_ROWS_MIN,
    Math.min(TRADE_MOBILE_CHART_ROWS_MAX, rows),
  );
}

/**
 * Tab rows for xs/xxs — ~one viewport of panel height below the sticky tab strip.
 */
export function computeTradeMobileTabRows(
  viewportHeight: number,
  menubarHeight = TRADE_MENUBAR_HEIGHT,
  footerPx = TRADE_MOBILE_FOOTER_PX,
): number {
  const available =
    viewportHeight - menubarHeight - footerPx - TRADE_VIEWPORT_FUDGE_PX;
  const rows = pxToTradeGridRows(available);
  return (
    Math.max(
      TRADE_MOBILE_TAB_ROWS_MIN,
      Math.min(TRADE_MOBILE_TAB_ROWS_MAX, rows),
    ) + TRADE_MOBILE_SCROLL_SLACK_ROWS
  );
}

function patchTradeMobileViewportLayout(
  layout: LayoutConfigLest,
  viewportHeight: number,
): LayoutConfigLest {
  const tickerSlot = layout[TICKER_SLOT_INDEX];
  const chartSlot = layout[CHART_SLOT_INDEX];
  const tabSlot = layout[TRADE_MOBILE_TAB_SLOT_INDEX];
  if (
    !tickerSlot ||
    !chartSlot ||
    !tabSlot ||
    chartSlot[2] === 0 ||
    chartSlot[3] === 0 ||
    tabSlot[2] === 0
  ) {
    return layout;
  }

  const tickerEndY = tickerSlot[1] + tickerSlot[3];
  const tickerRows = tickerSlot[3];
  const chartRows = computeTradeMobileChartRows(viewportHeight, tickerRows);
  const tabRows = computeTradeMobileTabRows(viewportHeight);
  const tabStartY = tickerEndY + chartRows;

  return layout.map(([x, y, w, h], index) => {
    if (index === CHART_SLOT_INDEX) {
      return [x, tickerEndY, w, chartRows];
    }
    if (index === TRADE_MOBILE_TAB_SLOT_INDEX) {
      return [x, tabStartY, w, tabRows];
    }
    return [x, y, w, h];
  });
}

/** xs/xxs only — chart fills viewport with tab-toolbar peek; mobile TabSection ~1 viewport tall. */
export function applyTradeMobileLayoutSizing(
  config: ResponsiveLayoutConfig,
  viewportHeight: number,
): ResponsiveLayoutConfig {
  const patchMobile = (layout: LayoutConfigLest) =>
    patchTradeMobileViewportLayout(layout, viewportHeight);

  return {
    ...config,
    xs: patchMobile(config.xs),
    xxs: patchMobile(config.xxs),
  };
}

// ============================================================================
// SLOT CONSTANTS
// ============================================================================

/**
 * EXTERNAL_SLOT_START
 *
 * Type: number (literal type: 0)
 * Purpose: Defines the starting index for external component slots
 *
 * Usage Context:
 *   - Used in GridViewer to determine which grid items are "external slots"
 *   - External slots can receive React components via slotContent prop
 *   - Range: EXTERNAL_SLOT_START (0) to EXTERNAL_SLOT_END (7) inclusive
 *
 * Type Breakdown:
 *   - Literal type: TypeScript infers this as type `0`, not `number`
 *   - Can be used in type-level operations
 *   - Provides compile-time safety for slot indexing
 */
export const EXTERNAL_SLOT_START = 0; // First external slot index

/**
 * EXTERNAL_SLOT_END
 *
 * Type: number (literal type: 7)
 * Purpose: Defines the ending index for external component slots
 *
 * Usage Context:
 *   - Used with EXTERNAL_SLOT_START to define valid slot range
 *   - GridViewer checks: i >= EXTERNAL_SLOT_START && i <= EXTERNAL_SLOT_END
 *   - This means slots 0-7 (8 total slots) can receive external content
 *
 * Type Breakdown:
 *   - Literal type: TypeScript infers this as type `7`, not `number`
 *   - Creates a type-level constraint for slot indexing
 *   - Both constants together define a closed interval [0, 7]
 *
 * Relationship:
 *   - Total slots: EXTERNAL_SLOT_END - EXTERNAL_SLOT_START + 1 = 8 slots
 *   - Matches the length of defaultPredefinedLayouts array (8 items)
 */
export const EXTERNAL_SLOT_END = 8; // Last external slot index

// ============================================================================
// TYPE RELATIONSHIPS
// ============================================================================

/**
 * Type Flow:
 *
 * LayoutConfigLest (Array of tuples)
 *     ↓
 * defaultPredefinedLayouts / widthfit (concrete instances)
 *     ↓
 * generateLayout() function (util.ts)
 *     ↓
 * LayoutItem[] (extends react-grid-layout's Layout)
 *     ↓
 * ResponsiveLayouts (react-grid-layout type)
 *     ↓
 * GridViewer component state
 *
 * Type Safety Chain:
 *   1. LayoutConfigLest ensures tuple structure [x, y, w, h]
 *   2. createLayoutItemFromConfig() converts tuple to LayoutItem
 *   3. LayoutItem extends Layout with optional static property
 *   4. ResponsiveLayouts maps breakpoint names to LayoutItem[]
 *   5. GridViewer uses ResponsiveLayouts in state management
 */
