import type { ResponsiveLayouts } from "react-grid-layout";
import type { LayoutItem } from "./type";
import type { LayoutConfigLest, LayoutDefinition } from "../../configs/terminalLayoutConfig";
import {
  MOBILE_BREAKPOINTS,
  MOBILE_HIDDEN_SLOTS,
} from "../../configs/terminalLayoutConfig";

/**
 * Capitalizes the first letter of a string
 */
export function capitalize(str: string | null | undefined): string {
  if (!str) return "";
  return str.charAt(0).toUpperCase() + str.slice(1).toLowerCase();
}

/**
 * Generates a random integer between min and max (inclusive)
 */
export function randomInt(min: number, max: number): number {
  return Math.floor(Math.random() * (max - min + 1)) + min;
}

/**
 * Generates a random layout item
 */
export function generateRandomLayoutItem(i: number): LayoutItem {
  const y = Math.ceil(Math.random() * 4) + 1;
  return {
    x: (randomInt(0, 5) * 2) % 12,
    y: Math.floor(i / 6) * y,
    w: 2,
    h: y,
    i: i.toString(),
    static: Math.random() < 0.05,
  };
}

/**
 * Creates a layout item from configuration [x, y, w, h]
 */
export function createLayoutItemFromConfig(
  i: number,
  config: LayoutDefinition,
): LayoutItem {
  const [x, y, w, h] = config;
  return {
    x,
    y,
    w,
    h,
    i: i.toString(),
    static: true,
  };
}

/**
 * Generates a layout with predefined configurations for initial items
 * and random configurations for the rest
 */
export function generateLayout(
  layouts: LayoutConfigLest,
  totalItems: number,
): LayoutItem[] {
  const totalShows = totalItems === 0 ? layouts.length : totalItems;
  const result: LayoutItem[] = [];
  for (let i = 0; i < totalShows; i++) {
    // Use predefined layout for items with configurations
    if (i < layouts.length) {
      result.push(createLayoutItemFromConfig(i, layouts[i]));
    } else {
      // Generate random layout for the rest
      result.push(generateRandomLayoutItem(i));
    }
  }
  return result;
}

export const GRID_BREAKPOINTS = ["lg", "md", "sm", "xs", "xxs"] as const;
export type GridBreakpoint = (typeof GRID_BREAKPOINTS)[number];

/** Minimum widths — must match react-grid-layout defaults used by GridViewerLayout. */
export const GRID_BREAKPOINT_MIN_WIDTH: Record<GridBreakpoint, number> = {
  lg: 1200,
  md: 996,
  sm: 768,
  xs: 480,
  xxs: 0,
};

/** Resolve the active grid breakpoint from viewport width (same order as RGL). */
export function resolveGridBreakpoint(width: number): GridBreakpoint {
  if (width >= GRID_BREAKPOINT_MIN_WIDTH.lg) return "lg";
  if (width >= GRID_BREAKPOINT_MIN_WIDTH.md) return "md";
  if (width >= GRID_BREAKPOINT_MIN_WIDTH.sm) return "sm";
  if (width >= GRID_BREAKPOINT_MIN_WIDTH.xs) return "xs";
  return "xxs";
}

/**
 * Collapses grid items for slots that are hidden on the current breakpoint.
 */
export function applyHiddenSlots(
  layout: LayoutItem[],
  hiddenSlots: readonly number[],
): LayoutItem[] {
  return layout.map((item, index) => {
    if (!hiddenSlots.includes(index)) return item;
    return {
      ...item,
      x: 0,
      y: 0,
      w: 0,
      h: 0,
      minW: 0,
      minH: 0,
      static: true,
      isDraggable: false,
      isResizable: false,
    };
  });
}

/**
 * Builds a ResponsiveLayouts map from per-breakpoint layout configs.
 */
export function generateResponsiveLayouts(
  configs: Record<GridBreakpoint, LayoutConfigLest>,
  totalItems = 0,
): ResponsiveLayouts {
  const result: ResponsiveLayouts = {};
  for (const bp of GRID_BREAKPOINTS) {
    let layout = generateLayout(configs[bp], totalItems);
    if ((MOBILE_BREAKPOINTS as readonly string[]).includes(bp)) {
      layout = applyHiddenSlots(layout, MOBILE_HIDDEN_SLOTS);
    }
    result[bp] = layout;
  }
  return result;
}

/**
 * Returns the layout array for a breakpoint, falling back to lg.
 */
export function getLayoutForBreakpoint(
  layouts: ResponsiveLayouts,
  breakpoint: string,
): LayoutItem[] {
  const layout = layouts[breakpoint] ?? layouts.lg;
  return (layout ?? []) as LayoutItem[];
}

/**
 * Efficiently compares layout positions without JSON.stringify
 */
export function layoutsEqual(
  current: ResponsiveLayouts,
  updated: ResponsiveLayouts,
): boolean {
  const currentKeys = Object.keys(current);
  const updatedKeys = Object.keys(updated);

  if (currentKeys.length !== updatedKeys.length) {
    return false;
  }

  for (const key of currentKeys) {
    const currentLayout = current[key];
    const updatedLayout = updated[key];

    if (!currentLayout || !updatedLayout) {
      if (currentLayout !== updatedLayout) return false;
      continue;
    }

    if (currentLayout.length !== updatedLayout.length) {
      return false;
    }

    for (let i = 0; i < currentLayout.length; i++) {
      const curr = currentLayout[i];
      const upd = updatedLayout[i];
      if (
        curr.x !== upd.x ||
        curr.y !== upd.y ||
        curr.w !== upd.w ||
        curr.h !== upd.h
      ) {
        return false;
      }
    }
  }

  return true;
}

/**
 * Updates layouts with static property - extracted helper to avoid duplication
 */
export function updateLayoutsWithStatic(
  layouts: ResponsiveLayouts,
  allStatic: boolean,
): ResponsiveLayouts {
  const updatedLayouts: ResponsiveLayouts = {};
  for (const breakpoint in layouts) {
    const breakpointLayout = layouts[breakpoint];
    if (breakpointLayout) {
      updatedLayouts[breakpoint] = breakpointLayout.map((item) => ({
        ...item,
        static: allStatic,
      })) as LayoutItem[];
    }
  }
  return updatedLayouts;
}
