export interface CrossChainOption {
  value: string;
  label: string;
}

export type CrossChainAssetId = "MORM" | "USDC" | "USDT" | "BTC";

export const DEFAULT_CROSS_CHAIN = "ethereum";

/** External chains allowed for deposit source and withdraw destination. */
export const EXTERNAL_CROSS_CHAIN_ALLOWLIST: CrossChainOption[] = [
  { value: "ethereum", label: "Ethereum" },
  { value: "solana", label: "Solana" },
  { value: "bitcoin", label: "Bitcoin" },
  { value: "arbitrum", label: "Arbitrum" },
  { value: "base", label: "Base" },
  { value: "bsc", label: "BSC" },
];

/** @deprecated Use EXTERNAL_CROSS_CHAIN_ALLOWLIST */
export const DEFAULT_CROSS_CHAINS = EXTERNAL_CROSS_CHAIN_ALLOWLIST;

/** Allowed chains per asset (deposit source and withdraw destination). */
export const ASSET_CHAIN_MATRIX: Record<CrossChainAssetId, string[]> = {
  USDC: ["ethereum", "arbitrum", "base", "bsc", "solana"],
  USDT: ["ethereum", "arbitrum", "base", "bsc", "solana"],
  BTC: ["bitcoin"],
  MORM: ["ethereum", "arbitrum", "base", "bsc"],
};

const ALLOWED_CHAIN_VALUES = new Set(
  EXTERNAL_CROSS_CHAIN_ALLOWLIST.map((option) => option.value),
);

const CHAIN_LABEL_BY_VALUE = new Map(
  EXTERNAL_CROSS_CHAIN_ALLOWLIST.map((option) => [option.value, option.label]),
);

function normalizeAssetId(assetId: string): CrossChainAssetId | null {
  const upper = assetId.trim().toUpperCase();
  if (upper === "USDC" || upper === "USDT" || upper === "BTC" || upper === "MORM") {
    return upper;
  }
  return null;
}

export function getExternalCrossChainOptions(): CrossChainOption[] {
  return EXTERNAL_CROSS_CHAIN_ALLOWLIST;
}

export function isAllowedExternalCrossChain(value: string): boolean {
  return ALLOWED_CHAIN_VALUES.has(value.trim().toLowerCase());
}

export function getChainsForAsset(assetId: string): CrossChainOption[] {
  const normalizedAsset = normalizeAssetId(assetId);
  if (!normalizedAsset) return [];
  const chainValues = ASSET_CHAIN_MATRIX[normalizedAsset];
  return chainValues.map((value) => ({
    value,
    label: CHAIN_LABEL_BY_VALUE.get(value) ?? value,
  }));
}

export function getDefaultChainForAsset(assetId: string): string {
  const chains = getChainsForAsset(assetId);
  return chains[0]?.value ?? DEFAULT_CROSS_CHAIN;
}

export function isAllowedAssetChainPair(assetId: string, chain: string): boolean {
  const normalizedAsset = normalizeAssetId(assetId);
  if (!normalizedAsset) return false;
  const normalizedChain = chain.trim().toLowerCase();
  return ASSET_CHAIN_MATRIX[normalizedAsset].includes(normalizedChain);
}

export function normalizeAssetChainSelection(assetId: string, chain: string): string {
  const normalizedChain = chain.trim().toLowerCase();
  if (isAllowedAssetChainPair(assetId, normalizedChain)) {
    return normalizedChain;
  }
  return getDefaultChainForAsset(assetId);
}

export function normalizeCrossChainSelection(value: string): string {
  const normalized = value.trim().toLowerCase();
  return isAllowedExternalCrossChain(normalized) ? normalized : DEFAULT_CROSS_CHAIN;
}

/** Returns the fixed external chain allowlist (no dynamic API discovery). */
export async function fetchCrossChainOptions(): Promise<CrossChainOption[]> {
  return getExternalCrossChainOptions();
}
