export type VaultGrade = "A" | "B" | "C" | "D";
export type VaultKind = "protocol" | "user";
export type BucketMarginMode = "cross" | "isolated";
export type VaultRiskHealth = "healthy" | "watch" | "critical";

export interface VaultAnalystVerdict {
  grade: VaultGrade | null;
  score: number | null;
  verified: boolean;
  percentileLabel: string | null;
  confidence: "High" | "Medium" | "Low" | null;
  /** Full analyst tab copy when score is unavailable — one human paragraph. */
  insufficientPassage?: string | null;
  summary: string;
  spotlightSummary: string;
  verificationReason: string;
  flags: string[];
  metrics: {
    return90dPct: number | null;
    sharpe: number | null;
    maxDrawdownPct: number | null;
    trackRecordDays: number;
    tvlUsd: number;
  };
  hasFlags: boolean;
}

export interface VaultBucketSummary {
  id: string;
  name: string;
  mode: BucketMarginMode;
  /** Top traded symbols; UI shows first 2 + +N */
  markets: string[];
  equityUsd: number;
  riskRatio: number;
  riskHealth: VaultRiskHealth;
  longNotionalUsd: number;
  shortNotionalUsd: number;
  netExposureLabel: string;
  marginUsagePct: number;
  /** Total bucket PnL (alias totalPnlUsd) */
  pnlUsd: number;
  pricePnlUsd: number;
  fundingPnlUsd: number;
  fundingAprPct: number;
  roiPct: number;
  openPositionCount: number;
  /** Isolated-only: liq price + distance pct */
  liqPriceUsd?: number;
  liqDistancePct?: number;
}

export interface VaultPositionRow {
  id: string;
  market: string;
  leverage: number;
  side: "long" | "short";
  size: number;
  positionValueUsd: number;
  entryPrice: number;
  markPrice: number;
  liqPrice: number;
  unrealizedPnlUsd: number;
  roePct: number;
  marginUsd: number;
  fundingUsd8h?: number;
}

export interface VaultRecord {
  id: string;
  name: string;
  kind: VaultKind;
  leader: string;
  leaderAddress: string;
  strategyType: string;
  strategyLabel: string;
  description: string;
  grade: VaultGrade | null;
  aprPct: number | null;
  tvlUsd: number;
  ageDays: number;
  isFlagship: boolean;
  isPinned: boolean;
  protocolNote?: string;
  snapshotSparkline: number[];
  spotlightSparkline90d: number[];
  analystVerdict: VaultAnalystVerdict;
  pastMonthReturnPct: number | null;
  buckets: VaultBucketSummary[];
  feeModel?: VaultFeeModel;
  visibility?: VaultVisibility;
}

