function verdict(
  partial: Partial<VaultAnalystVerdict> & Pick<VaultAnalystVerdict, "summary" | "spotlightSummary">,
): VaultAnalystVerdict {
  return {
    grade: null,
    score: null,
    verified: false,
    percentileLabel: null,
    confidence: null,
    verificationReason: "",
    flags: [],
    metrics: {
      return90dPct: null,
      sharpe: null,
      maxDrawdownPct: null,
      trackRecordDays: 0,
      tvlUsd: 0,
    },
    hasFlags: false,
    ...partial,
  };
}

