function getUserCreatedVaults(): VaultRecord[] {
  ensureVaultRegistryHydrated();
  return getPersistedVaults();
}

function mergeCatalogVaults(): VaultRecord[] {
  const persistedById = new Map(
    getUserCreatedVaults().map((vault) => [vault.id, vault]),
  );
  const staticVaults = VAULT_CATALOG.filter((v) => !persistedById.has(v.id));
  return [...staticVaults, ...persistedById.values()];
}

function findVaultRecord(id: string): VaultRecord | undefined {
  return getPersistedVaultById(id) ?? VAULT_CATALOG.find((v) => v.id === id);
}

/** Whether a vault id is taken in static catalog or persisted registry. */
export function isVaultIdTaken(id: string): boolean {
  return findVaultRecord(id) != null;
}

function resolveVaultBuckets(vault: VaultRecord): VaultBucketSummary[] {
  const cached = getCachedVaultActivityById(vault.id)?.buckets;
  if (cached?.length) return cached;
  return vault.buckets;
}

function withGeneratedBuckets(vault: VaultRecord): VaultRecord {
  const buckets = resolveVaultBuckets(vault);
  if (buckets === vault.buckets) return vault;
  return { ...vault, buckets };
}

export function addVaultToCatalog(vault: VaultRecord): void {
  if (VAULT_CATALOG.some((v) => v.id === vault.id)) {
    return;
  }
  upsertVaultRecord(vault);
}

export function updateVaultInCatalog(
  id: string,
  patch: Partial<VaultRecord> & { buckets?: VaultBucketSummary[] },
): VaultRecord | undefined {
  if (VAULT_CATALOG.some((v) => v.id === id)) {
    return undefined;
  }
  return patchVaultRecord(id, patch);
}

export function getAllVaults(): VaultRecord[] {
  return mergeCatalogVaults().map(withGeneratedBuckets);
}

export function getVaultById(id: string): VaultRecord | undefined {
  const vault = findVaultRecord(id);
  return vault ? withGeneratedBuckets(vault) : undefined;
}

export function getVaultBuckets(vaultId: string): VaultBucketSummary[] {
  const vault = findVaultRecord(vaultId);
  if (!vault) return [];
  return resolveVaultBuckets(vault);
}

export function getVaultLinkedBucketIds(): Set<string> {
  return new Set(
    mergeCatalogVaults()
      .filter((vault) => vault.kind === "user")
      .flatMap((vault) => vault.buckets.map((bucket) => bucket.id)),
  );
}

export { ensureVaultRegistryHydrated } from "./vaultRegistryStorage";

export function getVaultBucket(
  vaultId: string,
  bucketId: string,
): VaultBucketSummary | undefined {
  return getVaultBuckets(vaultId).find((b) => b.id === bucketId);
}

export function getBucketPositions(
  vaultId: string,
  bucketId: string,
): VaultPositionRow[] {
  return getCachedVaultActivityById(vaultId)?.positionsByKey[`${vaultId}:${bucketId}`] ?? [];
}

export function getTotalVaultTvl(): number {
  return getAllVaults().reduce((sum, v) => sum + v.tvlUsd, 0);
}

export function getTopVaultThisWeek(): VaultRecord {
  const ranked = [...getAllVaults()]
    .filter((v) => v.kind === "user" && v.analystVerdict.score != null)
    .sort((a, b) => (b.analystVerdict.score ?? 0) - (a.analystVerdict.score ?? 0));
  return ranked[0] ?? getVaultById("delta-neutral-mm-1") ?? VAULT_CATALOG[2];
}

export function formatVaultApr(apr: number | null): string {
  if (apr == null) return "—";
  return `${apr >= 0 ? "" : ""}${apr.toFixed(1)}%`;
}

export function formatVaultGrade(grade: VaultGrade | null): string {
  return grade ?? "—";
}

export function formatVaultTvl(usd: number): string {
  if (usd >= 1_000_000) return `$${(usd / 1_000_000).toFixed(1)}M`;
  if (usd >= 1_000) return `$${Math.round(usd / 1_000)}K`;
  return `$${usd.toFixed(0)}`;
}
