import { MOCK_FLEET_IDS, MOCK_SUPERVISOR_IDS } from "../../offline/mock_data/fleetSupervisors";
import type {
  AgentMemoryCapacity,
  AgentPermissionMode,
  AgentRole,
  MintCustodyMode,
  TradingAgent,
} from "../store/types";
import { BASE_AGENT_ALLOCATION_MB } from "../store/memoryPoolStore";

export const MINT_AGENT_DRAFT_KEY = "morpheum:mint-agent-draft";

export type MintWizardStep =
  | "role"
  | "identity"
  | "memory"
  | "review"
  | "express";

export interface MintAgentWizardState {
  step: MintWizardStep;
  role: AgentRole;
  permissionMode: AgentPermissionMode;
  supervisorId: string;
  fleetId: string;
  displayName: string;
  handle: string;
  custodyMode: MintCustodyMode;
  linkedWalletAddress: string;
  duplicateFromAgentId?: string;
  /** Stable id reserved for this mint session (preview + confirm). */
  pendingAgentId: string;
}

const ROLE_SHORT_NAMES: Record<AgentRole, string> = {
  supervisor: "supervisor",
  regime_detector: "regime",
  risk_officer: "risk",
  optimizer: "optimizer",
  executor: "executor",
  auditor: "auditor",
  intent_router: "router",
  vault_allocator: "vault",
};

const WALLET_ROLES = new Set<AgentRole>(["executor", "vault_allocator"]);

const HIL_PERMISSION_ROLES = new Set<AgentRole>(["executor", "vault_allocator"]);

export function defaultCustodyForRole(role: AgentRole): MintCustodyMode {
  return WALLET_ROLES.has(role) ? "generate_wallet" : "did_only";
}

/** Role-suggested permission at mint — never auto-selects high_agency. */
export function defaultPermissionForRole(role: AgentRole): AgentPermissionMode {
  return HIL_PERMISSION_ROLES.has(role) ? "hil" : "watch_only";
}

export function roleAllowsWalletCustody(role: AgentRole): boolean {
  return WALLET_ROLES.has(role);
}

const DEFAULT_MINT_ROLE: AgentRole = "executor";

export const DEFAULT_MINT_WIZARD_STATE: MintAgentWizardState = {
  step: "role",
  role: DEFAULT_MINT_ROLE,
  permissionMode: defaultPermissionForRole(DEFAULT_MINT_ROLE),
  supervisorId: MOCK_SUPERVISOR_IDS.soloDesk,
  fleetId: MOCK_FLEET_IDS.soloDesk,
  displayName: "",
  handle: "",
  custodyMode: defaultCustodyForRole(DEFAULT_MINT_ROLE),
  linkedWalletAddress: "",
  pendingAgentId: "",
};

export function createMintWizardState(
  overrides: Partial<MintAgentWizardState> = {},
): MintAgentWizardState {
  return {
    ...DEFAULT_MINT_WIZARD_STATE,
    pendingAgentId: buildMintAgentId(),
    ...overrides,
  };
}

export function deriveMarketSymbol(seed: string): string {
  let hash = 0;
  for (let i = 0; i < seed.length; i++) {
    hash = (hash * 31 + seed.charCodeAt(i)) >>> 0;
  }
  const hex = hash.toString(16).padStart(8, "0");
  return hex.slice(0, 5).toUpperCase();
}

export function bumpHandleVersion(handle: string): string {
  const match = handle.match(/^(.*)_v(\d+)$/i);
  if (!match) return `${handle}_v2`;
  const base = match[1]!;
  const version = Number.parseInt(match[2]!, 10);
  return `${base}_v${version + 1}`;
}

export function extractVersionTag(handle: string): string {
  const match = handle.match(/_v(\d+)$/i);
  if (!match) return "v1";
  return `v${match[1]}`;
}

export function suggestHandle(displayName: string, role: AgentRole): string {
  const slug = displayName
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "_")
    .replace(/^_|_$/g, "");
  const roleShort = ROLE_SHORT_NAMES[role];
  const base = slug || roleShort;
  return `${roleShort}_${base}_v1`.replace(/__+/g, "_");
}

export function isHandleAvailable(
  handle: string,
  agents: TradingAgent[],
  excludeAgentId?: string,
): boolean {
  const normalized = handle.trim().toLowerCase();
  if (!normalized) return false;
  return !agents.some((agent) => {
    if (excludeAgentId && agent.id === excludeAgentId) return false;
    const agentHandle = (agent.handle ?? agent.displayName).toLowerCase();
    return agentHandle === normalized;
  });
}

export function isValidWalletAddress(value: string): boolean {
  return /^0x[a-fA-F0-9]{40}$/.test(value.trim());
}

export function generateMockWalletAddress(seed: string): string {
  let hash = 0;
  for (let i = 0; i < seed.length; i++) {
    hash = (hash * 31 + seed.charCodeAt(i)) >>> 0;
  }
  const hex = hash.toString(16).padStart(40, "0").slice(0, 40);
  return `0x${hex}`;
}

export function previewDid(agentId: string): string {
  return `kya://0x${agentId.slice(0, 2)}…${agentId.slice(-2)}`;
}

export function buildMintAgentId(): string {
  if (typeof crypto !== "undefined" && crypto.randomUUID) {
    return crypto.randomUUID().replace(/-/g, "").slice(0, 16);
  }
  return `${Date.now().toString(16)}${Math.random().toString(16).slice(2, 10)}`.slice(
    0,
    16,
  );
}

export interface MintAgentPayload {
  id: string;
  displayName: string;
  handle: string;
  versionTag: string;
  role: AgentRole;
  permissionMode: AgentPermissionMode;
  supervisorId: string;
  fleetId: string;
  did: string;
  marketSymbol: string;
  walletAddress?: string;
  paymentState?: "pay_enabled" | "no_payments";
  provisioningStatus: "provisioning";
  gatewayEnabled: false;
  listingStatus: "private";
  status: "idle";
  memoryCapacity: AgentMemoryCapacity;
}

export function buildMintAgentPayload(
  state: MintAgentWizardState,
  agentId: string,
): MintAgentPayload {
  const did = `did:morpheum:agent:${agentId}`;
  const marketSymbol = deriveMarketSymbol(did);
  let walletAddress: string | undefined;

  if (state.custodyMode === "generate_wallet") {
    walletAddress = generateMockWalletAddress(agentId);
  } else if (state.custodyMode === "link_existing") {
    walletAddress = state.linkedWalletAddress.trim();
  }

  return {
    id: agentId,
    displayName: state.displayName.trim(),
    handle: state.handle.trim(),
    versionTag: extractVersionTag(state.handle),
    role: state.role,
    permissionMode: state.permissionMode,
    supervisorId: state.supervisorId,
    fleetId: state.fleetId,
    did,
    marketSymbol,
    walletAddress,
    paymentState: walletAddress ? "pay_enabled" : "no_payments",
    provisioningStatus: "provisioning",
    gatewayEnabled: false,
    listingStatus: "private",
    status: "idle",
    memoryCapacity: {
      allocatedMb: BASE_AGENT_ALLOCATION_MB,
      tier: "base",
    },
  };
}

export function resolveAgentHandle(agent: TradingAgent): string {
  if (agent.handle) return agent.handle;
  const slug = agent.displayName
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "_")
    .replace(/^_|_$/g, "");
  return `${slug || ROLE_SHORT_NAMES[agent.role]}_${agent.versionTag}`;
}

export function buildExpressStateFromAgent(agent: TradingAgent): MintAgentWizardState {
  const currentHandle = resolveAgentHandle(agent);
  const bumpedHandle = bumpHandleVersion(currentHandle);
  const bumpedDisplayName = agent.displayName.match(/\bv\d+\b/i)
    ? agent.displayName.replace(/\bv(\d+)\b/i, (_, n) => `v${Number(n) + 1}`)
    : `${agent.displayName} v2`;
  return createMintWizardState({
    step: "express",
    role: agent.role,
    permissionMode: agent.permissionMode ?? "watch_only",
    supervisorId: agent.supervisorId,
    fleetId: agent.fleetId,
    displayName: bumpedDisplayName,
    handle: bumpedHandle,
    custodyMode: agent.walletAddress
      ? "generate_wallet"
      : defaultCustodyForRole(agent.role),
    linkedWalletAddress: agent.walletAddress ?? "",
    duplicateFromAgentId: agent.id,
  });
}

export function isStepValid(
  step: MintWizardStep,
  state: MintAgentWizardState,
  agents: TradingAgent[],
): boolean {
  switch (step) {
    case "role":
      return Boolean(state.role && state.supervisorId && state.fleetId);
    case "identity": {
      const nameOk = state.displayName.trim().length >= 2;
      const handleOk =
        state.handle.trim().length >= 3 &&
        isHandleAvailable(state.handle, agents, state.duplicateFromAgentId);
      const custodyOk =
        state.custodyMode === "did_only" ||
        state.custodyMode === "generate_wallet" ||
        (state.custodyMode === "link_existing" &&
          isValidWalletAddress(state.linkedWalletAddress));
      return nameOk && handleOk && custodyOk;
    }
    case "memory":
      return true;
    case "review":
      return isStepValid("identity", state, agents);
    case "express":
      return (
        state.handle.trim().length >= 3 &&
        isHandleAvailable(state.handle, agents, state.duplicateFromAgentId)
      );
    default:
      return false;
  }
}

export function nextStep(step: MintWizardStep): MintWizardStep | null {
  if (step === "role") return "identity";
  if (step === "identity") return "memory";
  if (step === "memory") return "review";
  return null;
}

export function prevStep(step: MintWizardStep): MintWizardStep | null {
  if (step === "review") return "memory";
  if (step === "memory") return "identity";
  if (step === "identity") return "role";
  return null;
}

export function goNextStep(
  state: MintAgentWizardState,
): MintAgentWizardState | null {
  const next = nextStep(state.step);
  if (!next) return null;
  return { ...state, step: next };
}

export function goPrevStep(
  state: MintAgentWizardState,
): MintAgentWizardState | null {
  const back = prevStep(state.step);
  if (!back) return null;
  return { ...state, step: back };
}

export function saveMintDraft(state: MintAgentWizardState): void {
  if (typeof localStorage === "undefined") return;
  localStorage.setItem(MINT_AGENT_DRAFT_KEY, JSON.stringify(state));
}

export function loadMintDraft(): MintAgentWizardState | null {
  if (typeof localStorage === "undefined") return null;
  try {
    const raw = localStorage.getItem(MINT_AGENT_DRAFT_KEY);
    if (!raw) return null;
    const parsed = JSON.parse(raw) as Partial<MintAgentWizardState>;
    return createMintWizardState({
      ...parsed,
      pendingAgentId: parsed.pendingAgentId || buildMintAgentId(),
    });
  } catch {
    return null;
  }
}

export function clearMintDraft(): void {
  if (typeof localStorage === "undefined") return;
  localStorage.removeItem(MINT_AGENT_DRAFT_KEY);
}

export function formatMemoryMeter(reservedMb: number, poolMb: number): string {
  return `${reservedMb} / ${poolMb} MB`;
}

export function projectedReservedAfterMint(
  reservedMb: number,
  allocationMb = BASE_AGENT_ALLOCATION_MB,
): number {
  return reservedMb + allocationMb;
}

