import React from "react";

function joinClassNames(
  ...parts: Array<string | false | null | undefined>
): string {
  return parts.filter(Boolean).join(" ");
}

export interface ModalHeaderCloseProps {
  onClick: () => void;
  disabled?: boolean;
  label?: string;
  className?: string;
}

export function ModalHeaderClose({
  onClick,
  disabled = false,
  label = "Close",
  className,
}: ModalHeaderCloseProps): JSX.Element {
  return (
    <button
      type="button"
      className={joinClassNames("modal-header__close", className)}
      onClick={onClick}
      disabled={disabled}
      aria-label={label}
    >
      <svg
        width="14"
        height="14"
        viewBox="0 0 24 24"
        fill="none"
        stroke="currentColor"
        strokeWidth="2"
        strokeLinecap="round"
        strokeLinejoin="round"
        aria-hidden
      >
        <path d="M18 6L6 18M6 6l12 12" />
      </svg>
    </button>
  );
}

export interface ModalHeaderProps {
  /** Plain string renders h3.terminal-panel-title; node renders inside leading. */
  title?: React.ReactNode;
  /** Full leading column; overrides title when set. */
  leading?: React.ReactNode;
  /** Content before the close control (badges, pills, helper actions). */
  trailing?: React.ReactNode;
  onClose?: () => void;
  showClose?: boolean;
  closeDisabled?: boolean;
  closeLabel?: string;
  /** flex-start row alignment for subtitle / breadcrumb / multi-line leading. */
  multiline?: boolean;
  /** Apply modal-header padding and border (default true). */
  chrome?: boolean;
  className?: string;
  as?: "div" | "header";
}

function ModalHeader({
  title,
  leading,
  trailing,
  onClose,
  showClose,
  closeDisabled = false,
  closeLabel = "Close",
  multiline = false,
  chrome = true,
  className,
  as: Tag = "div",
}: ModalHeaderProps): JSX.Element {
  const shouldShowClose = showClose ?? Boolean(onClose);

  const leadingContent =
    leading ??
    (title !== undefined && title !== null ? (
      typeof title === "string" ? (
        <h3 className="terminal-panel-title">{title}</h3>
      ) : (
        title
      )
    ) : null);

  const actions =
    trailing || (shouldShowClose && onClose) ? (
      <div className="modal-header__actions">
        {trailing}
        {shouldShowClose && onClose ? (
          <ModalHeaderClose
            onClick={onClose}
            disabled={closeDisabled}
            label={closeLabel}
          />
        ) : null}
      </div>
    ) : null;

  const row = (
    <div
      className={joinClassNames(
        "modal-header__row",
        multiline && "modal-header__row--multiline",
      )}
    >
      {leadingContent ? (
        <div className="modal-header__leading">{leadingContent}</div>
      ) : null}
      {actions}
    </div>
  );

  if (!chrome) {
    return <Tag className={className}>{row}</Tag>;
  }

  return (
    <Tag className={joinClassNames("modal-header", className)}>{row}</Tag>
  );
}

export default React.memo(ModalHeader);
