interface SettingsMenuButtonProps {
  label: string;
  isActive: boolean;
  onClick: () => void;
}

function SettingsMenuButton({ label, isActive, onClick }: SettingsMenuButtonProps): JSX.Element {
  return (
    <button
      type="button"
      className={`settings-menu-item${isActive ? " active" : ""}`}
      onClick={onClick}
    >
      {label}
    </button>
  );
}

interface OptionsPanelProps {
  title: string;
  children: React.ReactNode;
  titleAction?: { label: string; onClick: () => void };
}

function OptionsPanel({ title, children, titleAction }: OptionsPanelProps): JSX.Element {
  return (
    <div className="settings-options-panel">
      <div className="settings-options-panel-header">
        <h4 className="settings-options-panel-title">{title}</h4>
        {titleAction ? (
          <button
            type="button"
            className="settings-options-panel-action"
            onClick={titleAction.onClick}
          >
            {titleAction.label}
          </button>
        ) : null}
      </div>
      {children}
    </div>
  );
}

interface ChoiceOptionsProps {
  options: readonly { value: string; label: string }[];
  selected: string;
  onSelect: (value: string) => void;
  optionsClassName?: string;
  optionClassName?: string;
}

function ChoiceOptions({
  options,
  selected,
  onSelect,
  optionsClassName,
  optionClassName,
}: ChoiceOptionsProps): JSX.Element {
  const optionsClass = optionsClassName
    ? `settings-options ${optionsClassName}`
    : "settings-options";

  return (
    <div className={optionsClass}>
      {options.map(({ value, label }) => (
        <button
          key={value}
          type="button"
          className={`settings-option${optionClassName ? ` ${optionClassName}` : ""}${selected === value ? " active" : ""}`}
          onClick={() => onSelect(value)}
        >
          {label}
        </button>
      ))}
    </div>
  );
}

interface OrderbookTogglesProps {
  prefs: OrderbookPrefs;
  onToggle: (key: keyof OrderbookPrefs, value: boolean) => void;
}

function OrderbookToggles({ prefs, onToggle }: OrderbookTogglesProps): JSX.Element {
  return (
    <div className="settings-toggles">
      {ORDERBOOK_TOGGLES.map(({ key, label }) => (
        <label key={key} className="settings-toggle">
          <input
            type="checkbox"
            checked={prefs[key]}
            onChange={(e) => onToggle(key, e.target.checked)}
          />
          <span>{label}</span>
        </label>
      ))}
    </div>
  );
}

interface ChartOverlayTogglesProps {
  prefs: ChartOverlayPrefs;
  onToggle: (key: keyof ChartOverlayPrefs, value: boolean) => void;
}

function ChartOverlayToggles({ prefs, onToggle }: ChartOverlayTogglesProps): JSX.Element {
  return (
    <div className="settings-toggles settings-chart-overlay-toggles">
      {CHART_OVERLAY_TOGGLES.map(({ key, label }) => (
        <label key={key} className="settings-toggle">
          <input
            type="checkbox"
            checked={prefs[key]}
            onChange={(e) => onToggle(key, e.target.checked)}
          />
          <span>{label}</span>
        </label>
      ))}
    </div>
  );
}

interface GateIntentTimerSettingsProps {
  prefs: GateIntentTimerPrefs;
  onChange: (patch: Partial<GateIntentTimerPrefs>) => void;
}

function GateIntentTimerSettings({
  prefs,
  onChange,
}: GateIntentTimerSettingsProps): JSX.Element {
  return (
    <>
      <div className="settings-toggles">
        <label className="settings-toggle">
          <input
            type="checkbox"
            checked={prefs.enabled}
            onChange={(e) => onChange({ enabled: e.target.checked })}
          />
          <span>Auto-timer on gated intents</span>
        </label>
      </div>
      <p className="settings-chart-overlay-hint">
        When enabled, Command Deck gated intents in High-Agency queue mode
        count down and auto-approve or auto-reject. Click the clock icon on a
        card to restore manual buttons.
      </p>
      <label className="settings-number-field">
        <span>Wait time (seconds)</span>
        <input
          type="number"
          min={GATE_INTENT_TIMER_MIN_SECONDS}
          max={GATE_INTENT_TIMER_MAX_SECONDS}
          step={1}
          value={prefs.waitSeconds}
          onChange={(e) =>
            onChange({
              waitSeconds: clampGateIntentWaitSeconds(Number(e.target.value)),
            })
          }
        />
      </label>
      <p className="settings-chart-overlay-hint">Action when timer expires</p>
      <ChoiceOptions
        options={GATE_INTENT_TIMEOUT_OPTIONS}
        selected={prefs.onTimeout}
        onSelect={(value) =>
          onChange({ onTimeout: value as GateIntentTimeoutAction })
        }
      />
    </>
  );
}

interface SubmenuContentProps {
  activeSubmenu: SubmenuKey | null;
  state: SettingsModalState;
  onChoiceSelect: (section: ChoiceSectionConfig, value: string) => void;
  onChartProviderSelect: (value: ChartProvider) => void;
  onChartOverlayToggle: (key: keyof ChartOverlayPrefs, value: boolean) => void;
  onOrderbookToggle: (key: keyof OrderbookPrefs, value: boolean) => void;
  onTooltipsToggle: (value: boolean) => void;
  onTooltipGroupToggle: (groupId: TooltipGroupId, enabled: boolean) => void;
  onCompactFavoritesBarToggle: (value: boolean) => void;
  onWalletAccountValueToggle: (value: boolean) => void;
  onKeyboardShortcutsChange: (shortcuts: KeyboardShortcutPrefs) => void;
  onCopytradeChange: (patch: Partial<MarketsPrefs>) => void;
  onIndexChange: (patch: Partial<IndexPrefs>) => void;
  onPortfolioChange: (patch: Partial<PortfolioPrefs>) => void;
  onAgentChange: (patch: Partial<AgentPrefs>) => void;
  onHilSafetyTabsChange: (prefs: HilSafetyTabsPrefs) => void;
  onHighAgencyTabsChange: (prefs: HighAgencyTabsPrefs) => void;
  onHeaderNavChange: (prefs: HeaderNavPrefs) => void;
  onStakingChange: (patch: Partial<StakingPrefs>) => void;
  onVaultListChange: (patch: Partial<VaultListPrefs>) => void;
  onAgentRolesChange: (patch: Partial<AgentRolesPrefs>) => void;
  onGateIntentTimerChange: (patch: Partial<GateIntentTimerPrefs>) => void;
  onLayoutEdit?: () => void;
}

function SubmenuContent({
  activeSubmenu,
  state,
  onChoiceSelect,
  onChartProviderSelect,
  onChartOverlayToggle,
  onOrderbookToggle,
  onTooltipsToggle,
  onTooltipGroupToggle,
  onCompactFavoritesBarToggle,
  onWalletAccountValueToggle,
  onKeyboardShortcutsChange,
  onCopytradeChange,
  onIndexChange,
  onPortfolioChange,
  onAgentChange,
  onHilSafetyTabsChange,
  onHighAgencyTabsChange,
  onHeaderNavChange,
  onStakingChange,
  onVaultListChange,
  onAgentRolesChange,
  onGateIntentTimerChange,
  onLayoutEdit,
}: SubmenuContentProps): JSX.Element | null {
  if (!activeSubmenu) return null;

  if (activeSubmenu === SHORTCUTS_SECTION.key) {
    return (
      <OptionsPanel title={SHORTCUTS_SECTION.title}>
        <KeyboardShortcutsSettingsPanel
          shortcuts={state.keyboardShortcuts}
          onChange={onKeyboardShortcutsChange}
        />
      </OptionsPanel>
    );
  }

  if (activeSubmenu === "walletAccountValue") {
    return (
      <OptionsPanel title="Wallet Account Value">
        <div className="settings-toggles">
          <label className="settings-toggle">
            <input
              type="checkbox"
              checked={state.showWalletAccountValue}
              onChange={(e) => onWalletAccountValueToggle(e.target.checked)}
            />
            <span>Show total account value in wallet</span>
          </label>
        </div>
        <p className="settings-chart-overlay-hint">
          When disabled, the wallet panel still shows the account value row but
          masks the amount (e.g. $*****.**).
        </p>
      </OptionsPanel>
    );
  }

  if (activeSubmenu === TOOLTIPS_SECTION.key) {
    return (
      <OptionsPanel title={TOOLTIPS_SECTION.title}>
        <div className="settings-toggles">
          <label className="settings-toggle">
            <input
              type="checkbox"
              checked={state.tooltipsEnabled}
              onChange={(e) => onTooltipsToggle(e.target.checked)}
            />
            <span>Show hover tooltips</span>
          </label>
        </div>
        <p className="settings-chart-overlay-hint">
          Agent-first explanations when hovering labels across the terminal.
        </p>
        <TooltipInventorySettings
          layout={state.layout}
          tooltipsEnabled={state.tooltipsEnabled}
          tooltipGroups={state.tooltipGroups}
          onTooltipGroupToggle={onTooltipGroupToggle}
        />
      </OptionsPanel>
    );
  }

  if (activeSubmenu === ORDERBOOK_SECTION.key) {
    return (
      <OptionsPanel title={ORDERBOOK_SECTION.title}>
        <OrderbookToggles prefs={state.orderbook} onToggle={onOrderbookToggle} />
      </OptionsPanel>
    );
  }

  if (activeSubmenu === "gateIntentTimer") {
    return (
      <OptionsPanel title="Intent auto-timer">
        <GateIntentTimerSettings
          prefs={state.gateIntentTimer}
          onChange={onGateIntentTimerChange}
        />
      </OptionsPanel>
    );
  }

  if (activeSubmenu === CHART_SECTION.key) {
    return (
      <OptionsPanel title={CHART_SECTION.title}>
        <ChoiceOptions
          options={CHART_PROVIDERS}
          selected={state.chartProvider}
          onSelect={(value) => onChartProviderSelect(value as ChartProvider)}
        />
        <ChartOverlayToggles prefs={state.chartOverlays} onToggle={onChartOverlayToggle} />
        <p className="settings-chart-overlay-hint">Overlays apply to Native Kline Chart only.</p>
      </OptionsPanel>
    );
  }

  if (activeSubmenu === "copytradeDefaultTab") {
    return (
      <OptionsPanel title="Default Tab">
        <ChoiceOptions
          options={MARKETS_TAB_OPTIONS}
          selected={state.copytrade.defaultTab}
          onSelect={(value) =>
            onCopytradeChange({ defaultTab: value as MarketKind })
          }
        />
      </OptionsPanel>
    );
  }

  if (activeSubmenu === "copytradeDefaultSort") {
    return (
      <OptionsPanel title="Default Sort">
        <p className="settings-chart-overlay-hint">Sort column</p>
        <ChoiceOptions
          options={MARKETS_SORT_KEY_OPTIONS}
          selected={state.copytrade.defaultSortKey}
          onSelect={(value) =>
            onCopytradeChange({ defaultSortKey: value as SortKey })
          }
        />
        <p className="settings-chart-overlay-hint">Sort direction</p>
        <ChoiceOptions
          options={MARKETS_SORT_DIR_OPTIONS}
          selected={state.copytrade.defaultSortDir}
          onSelect={(value) =>
            onCopytradeChange({ defaultSortDir: value as "asc" | "desc" })
          }
        />
      </OptionsPanel>
    );
  }

  if (activeSubmenu === "copytradeShowSparklines") {
    return (
      <OptionsPanel title="Sparklines">
        <div className="settings-toggles">
          <label className="settings-toggle">
            <input
              type="checkbox"
              checked={state.copytrade.showSparklines}
              onChange={(e) => onCopytradeChange({ showSparklines: e.target.checked })}
            />
            <span>Show trend sparklines in table</span>
          </label>
        </div>
      </OptionsPanel>
    );
  }

  if (activeSubmenu === "copytradeShowFiltersSidebar") {
    return (
      <OptionsPanel title="Filter sidebar">
        <div className="settings-toggles">
          <label className="settings-toggle">
            <input
              type="checkbox"
              checked={state.copytrade.showFiltersSidebar}
              onChange={(e) =>
                onCopytradeChange({ showFiltersSidebar: e.target.checked })
              }
            />
            <span>Show filter sidebar (chip groups + reset)</span>
          </label>
        </div>
        <p className="settings-chart-overlay-hint">
          Toolbar dropdowns remain available when this is off.
        </p>
      </OptionsPanel>
    );
  }

  if (activeSubmenu === "indexDefaultMode") {
    return (
      <OptionsPanel title="Default Index Mode">
        <ChoiceOptions
          options={INDEX_MODE_OPTIONS}
          selected={state.index.defaultMode}
          onSelect={(value) =>
            onIndexChange({ defaultMode: value as PropertyIndexMode["id"] })
          }
        />
      </OptionsPanel>
    );
  }

  if (activeSubmenu === "indexShowXPulse") {
    return (
      <OptionsPanel title="X Pulse Rail">
        <div className="settings-toggles">
          <label className="settings-toggle">
            <input
              type="checkbox"
              checked={state.index.showXPulse}
              onChange={(e) => onIndexChange({ showXPulse: e.target.checked })}
            />
            <span>Show constituent X pulse rail on desktop/tablet</span>
          </label>
        </div>
      </OptionsPanel>
    );
  }

  if (activeSubmenu === "stakingEnableYield") {
    return (
      <OptionsPanel title="USDC Yield">
        <div className="settings-toggles">
          <label className="settings-toggle">
            <input
              type="checkbox"
              checked={state.staking.enableUsdcYield}
              onChange={(e) =>
                onStakingChange({ enableUsdcYield: e.target.checked })
              }
            />
            <span>Enable USDC yield accrual and claim (trailing paid to date)</span>
          </label>
        </div>
      </OptionsPanel>
    );
  }

  if (activeSubmenu === "stakingEnableDelegation") {
    return (
      <OptionsPanel title="Validator Delegation">
        <div className="settings-toggles">
          <label className="settings-toggle">
            <input
              type="checkbox"
              checked={state.staking.enableDelegation}
              onChange={(e) =>
                onStakingChange({ enableDelegation: e.target.checked })
              }
            />
            <span>Show Delegate tab and validator delegation UI</span>
          </label>
        </div>
      </OptionsPanel>
    );
  }

  if (activeSubmenu === "portfolioDefaultHeroView") {
    return (
      <OptionsPanel title="Default Hero View">
        <ChoiceOptions
          options={PORTFOLIO_HERO_VIEW_OPTIONS}
          selected={state.portfolio.defaultHeroView}
          onSelect={(value) =>
            onPortfolioChange({ defaultHeroView: value as PortfolioHeroView })
          }
        />
      </OptionsPanel>
    );
  }

  if (activeSubmenu === "portfolioDefaultTimeRange") {
    return (
      <OptionsPanel title="Default Time Range">
        <ChoiceOptions
          options={PORTFOLIO_TIME_RANGE_OPTIONS}
          selected={state.portfolio.defaultTimeRange}
          onSelect={(value) =>
            onPortfolioChange({ defaultTimeRange: value as PortfolioTimeRange })
          }
        />
      </OptionsPanel>
    );
  }

  if (activeSubmenu === "portfolioDefaultTab") {
    return (
      <OptionsPanel title="Default Tab">
        <ChoiceOptions
          options={PORTFOLIO_TAB_OPTIONS}
          selected={state.portfolio.defaultTab}
          onSelect={(value) =>
            onPortfolioChange({ defaultTab: value as TabSectionTabId })
          }
        />
      </OptionsPanel>
    );
  }

  if (activeSubmenu === "agentHeroFocus") {
    const agentPrefs = state.agent ?? DEFAULT_AGENT_PREFS;
    return (
      <OptionsPanel title="Hero Focus">
        <p className="settings-chart-overlay-hint">
          Controls how the agent header band presents identity on agent detail
          pages.
        </p>
        <ChoiceOptions
          options={[...AGENT_HERO_FOCUS_OPTIONS]}
          selected={agentPrefs.heroFocus}
          onSelect={(value) =>
            onAgentChange({ heroFocus: value as AgentHeroFocus })
          }
        />
        <div className="settings-toggles">
          <label className="settings-toggle">
            <input
              type="checkbox"
              checked={agentPrefs.heroFocusLoop ?? false}
              onChange={(e) =>
                onAgentChange({ heroFocusLoop: e.target.checked })
              }
            />
            <span>Loop all focus every 5 seconds</span>
          </label>
        </div>
        <p className="settings-chart-overlay-hint">
          While looping, the header and metrics preview cycle automatically.
          Your manual focus choice applies when loop is off.
        </p>
      </OptionsPanel>
    );
  }

  if (activeSubmenu === "headerNav") {
    return (
      <OptionsPanel title="Header Navigation">
        <HeaderNavSettings
          prefs={state.headerNav}
          onChange={onHeaderNavChange}
        />
      </OptionsPanel>
    );
  }

  if (activeSubmenu === "highAgencyTabs") {
    if (state.layout !== "layout3") {
      return (
        <OptionsPanel title="Agent tabs">
          <p className="settings-chart-overlay-hint">
            Switch to the High-Agency layout to customize Agent-mode tab
            tables.
          </p>
        </OptionsPanel>
      );
    }

    return (
      <OptionsPanel title="Agent tabs">
        <HighAgencyTabsSettings
          prefs={state.highAgencyTabs}
          onChange={onHighAgencyTabsChange}
        />
      </OptionsPanel>
    );
  }

  if (activeSubmenu === "fleetNetworkBackground") {
    const agentRolesPrefs = state.agentRoles ?? DEFAULT_AGENT_ROLES_PREFS;
    return (
      <OptionsPanel title="Network background">
        <p className="settings-chart-overlay-hint">
          Background pattern for the fleet relationship map in Network view.
        </p>
        <ChoiceOptions
          options={FLEET_NETWORK_BACKGROUND_OPTIONS}
          selected={agentRolesPrefs.networkBackgroundPattern}
          onSelect={(value) =>
            onAgentRolesChange({
              networkBackgroundPattern: value as FleetNetworkBackgroundPattern,
            })
          }
        />
        <p className="settings-chart-overlay-hint">Pattern size</p>
        <ChoiceOptions
          options={FLEET_NETWORK_BACKGROUND_SIZE_OPTIONS}
          selected={agentRolesPrefs.networkBackgroundSize}
          onSelect={(value) =>
            onAgentRolesChange({
              networkBackgroundSize: value as FleetNetworkBackgroundSize,
            })
          }
        />
      </OptionsPanel>
    );
  }

  if (activeSubmenu === "vaultListLayout") {
    return (
      <OptionsPanel title="Listing Layout">
        <ChoiceOptions
          options={VAULT_LIST_LAYOUT_OPTIONS}
          selected={resolveVaultListLayoutMode(state.vaultList)}
          onSelect={(value) =>
            onVaultListChange({
              layout: value as VaultListLayoutMode,
              explicitChoice: true,
            })
          }
        />
        <p className="settings-chart-overlay-hint">
          Classic shows Protocol and User vault tables stacked. Tablet uses a
          tab strip to switch between Protocol, Community, Invested, and My
          Vaults.
        </p>
      </OptionsPanel>
    );
  }

  if (activeSubmenu === "hilSafetyTabs") {
    if (state.layout !== "layout4") {
      return (
        <OptionsPanel title="Safety tabs">
          <p className="settings-chart-overlay-hint">
            Switch to the Human-in-Loop layout to customize Safety-mode tab
            tables.
          </p>
        </OptionsPanel>
      );
    }

    return (
      <OptionsPanel title="Safety tabs">
        <HilSafetyTabsSettings
          prefs={state.hilSafetyTabs}
          safetyLogLabel={
            state.enableHILPolish ? "Safety Log" : "Memory & Audit"
          }
          onChange={onHilSafetyTabsChange}
        />
      </OptionsPanel>
    );
  }

  const section = CHOICE_SECTIONS.find((s) => s.key === activeSubmenu);
  if (!section) return null;

  return (
    <OptionsPanel
      title={section.title}
      titleAction={
        section.key === "layout" && onLayoutEdit
          ? { label: "Edit", onClick: onLayoutEdit }
          : undefined
      }
    >
      <ChoiceOptions
        options={section.options}
        selected={section.getSelected(state)}
        onSelect={(value) => onChoiceSelect(section, value)}
        optionsClassName={section.optionsClassName}
        optionClassName={section.optionClassName}
      />
      {section.key === "layout" && state.layout === "layout2" ? (
        <>
          <div className="settings-toggles">
            <label className="settings-toggle">
              <input
                type="checkbox"
                checked={state.showCompactFavoritesBar}
                onChange={(e) => onCompactFavoritesBarToggle(e.target.checked)}
              />
              <span>Show favorites ticker bar</span>
            </label>
          </div>
          <p className="settings-chart-overlay-hint">
            24px strip above market metrics in Compact layout.
          </p>
        </>
      ) : null}
      {section.key === "layout" &&
      (state.layout === "layout3" || state.layout === "layout4") ? (
        <p className="settings-chart-overlay-hint">
          Chart-first layout with a narrow command deck on the right. Manual
          trade lives inside the deck accordion. The order book shows a labeled
          mode chip and colored left rail (blue = High-Agency, gold = Guarded).
        </p>
      ) : null}
    </OptionsPanel>
  );
}

function SettingsModal({
  isOpen,
  onClose,
  state,
  onStateChange,
  menuGroups,
  initialSubmenu = null,
  onLayoutEdit,
  onOpenKeyboardShortcuts,
}: SettingsModalProps): JSX.Element | null {
  const resolvedMenuGroups = menuGroups ?? [];
  const [activeSubmenu, setActiveSubmenu] = useState<SubmenuKey | null>(null);
  const [isMobile, setIsMobile] = useState(
    () =>
      typeof window !== "undefined" &&
      window.matchMedia("(max-width: 768px)").matches,
  );

  useEffect(() => {
    const mediaQuery = window.matchMedia("(max-width: 768px)");
    const syncMobile = () => setIsMobile(mediaQuery.matches);
    syncMobile();
    mediaQuery.addEventListener("change", syncMobile);
    return () => mediaQuery.removeEventListener("change", syncMobile);
  }, []);

  const { mounted, panelOpen, backdropVisible, backdropStyle } = useStaggeredOverlay({
    isOpen,
    panelDurationMs: isMobile
      ? OVERLAY_TIMING.mobileSheetMs
      : OVERLAY_TIMING.desktopScaleMs,
  });

  useOverlayEscapeKey(isOpen, onClose);
  useOverlayScrollLock(isOpen && mounted && isMobile);

  useEffect(() => {
    if (!isOpen) {
      setActiveSubmenu(null);
      return;
    }
    if (initialSubmenu) {
      setActiveSubmenu(initialSubmenu);
    }
  }, [isOpen, initialSubmenu]);

  const toggleSubmenu = useCallback((key: SubmenuKey) => {
    setActiveSubmenu((prev) => (prev === key ? null : key));
  }, []);

  const handleChoiceSelect = useCallback(
    (section: ChoiceSectionConfig, value: string) => {
      onStateChange(section.apply(state, value));
      setActiveSubmenu(null);
    },
    [state, onStateChange],
  );

  const handleOrderbookToggle = useCallback(
    (key: keyof OrderbookPrefs, value: boolean) => {
      onStateChange({
        ...state,
        orderbook: { ...state.orderbook, [key]: value },
      });
    },
    [state, onStateChange],
  );

  const handleChartProviderSelect = useCallback(
    (value: ChartProvider) => {
      onStateChange({ ...state, chartProvider: value });
    },
    [state, onStateChange],
  );

  const handleChartOverlayToggle = useCallback(
    (key: keyof ChartOverlayPrefs, value: boolean) => {
      onStateChange({
        ...state,
        chartOverlays: { ...state.chartOverlays, [key]: value },
      });
    },
    [state, onStateChange],
  );

  const handleTooltipsToggle = useCallback(
    (value: boolean) => {
      onStateChange({ ...state, tooltipsEnabled: value });
    },
    [state, onStateChange],
  );

  const handleTooltipGroupToggle = useCallback(
    (groupId: TooltipGroupId, enabled: boolean) => {
      onStateChange({
        ...state,
        tooltipGroups: toggleTooltipGroup(state.tooltipGroups, groupId, enabled),
      });
    },
    [state, onStateChange],
  );

  const handleCompactFavoritesBarToggle = useCallback(
    (value: boolean) => {
      onStateChange({ ...state, showCompactFavoritesBar: value });
    },
    [state, onStateChange],
  );

  const handleWalletAccountValueToggle = useCallback(
    (value: boolean) => {
      onStateChange({ ...state, showWalletAccountValue: value });
    },
    [state, onStateChange],
  );

  const handleKeyboardShortcutsChange = useCallback(
    (keyboardShortcuts: KeyboardShortcutPrefs) => {
      onStateChange({ ...state, keyboardShortcuts });
    },
    [state, onStateChange],
  );

  const handleCopytradeChange = useCallback(
    (patch: Partial<MarketsPrefs>) => {
      onStateChange({ ...state, copytrade: { ...state.copytrade, ...patch } });
    },
    [state, onStateChange],
  );

  const handleIndexChange = useCallback(
    (patch: Partial<IndexPrefs>) => {
      onStateChange({ ...state, index: { ...state.index, ...patch } });
    },
    [state, onStateChange],
  );

  const handlePortfolioChange = useCallback(
    (patch: Partial<PortfolioPrefs>) => {
      onStateChange({ ...state, portfolio: { ...state.portfolio, ...patch } });
    },
    [state, onStateChange],
  );

  const handleAgentChange = useCallback(
    (patch: Partial<AgentPrefs>) => {
      onStateChange({
        ...state,
        agent: { ...DEFAULT_AGENT_PREFS, ...state.agent, ...patch },
      });
    },
    [state, onStateChange],
  );

  const handleHighAgencyTabsChange = useCallback(
    (highAgencyTabs: HighAgencyTabsPrefs) => {
      onStateChange({ ...state, highAgencyTabs });
    },
    [state, onStateChange],
  );

  const handleHeaderNavChange = useCallback(
    (headerNav: HeaderNavPrefs) => {
      onStateChange({ ...state, headerNav });
    },
    [state, onStateChange],
  );

  const handleStakingChange = useCallback(
    (patch: Partial<StakingPrefs>) => {
      onStateChange({ ...state, staking: { ...state.staking, ...patch } });
    },
    [state, onStateChange],
  );

  const handleVaultListChange = useCallback(
    (patch: Partial<VaultListPrefs>) => {
      onStateChange({
        ...state,
        vaultList: normalizeVaultListPrefs({ ...state.vaultList, ...patch }),
      });
    },
    [state, onStateChange],
  );

  const handleAgentRolesChange = useCallback(
    (patch: Partial<AgentRolesPrefs>) => {
      onStateChange({
        ...state,
        agentRoles: { ...DEFAULT_AGENT_ROLES_PREFS, ...state.agentRoles, ...patch },
      });
    },
    [state, onStateChange],
  );

  const handleHilSafetyTabsChange = useCallback(
    (hilSafetyTabs: HilSafetyTabsPrefs) => {
      onStateChange({ ...state, hilSafetyTabs });
    },
    [state, onStateChange],
  );

  const handleGateIntentTimerChange = useCallback(
    (patch: Partial<GateIntentTimerPrefs>) => {
      onStateChange({
        ...state,
        gateIntentTimer: { ...state.gateIntentTimer, ...patch },
      });
    },
    [state, onStateChange],
  );

  if (!mounted) return null;

  const isShortcutsSubmenu =
    !isMobile && activeSubmenu === SHORTCUTS_SECTION.key;

  const modalContent = (
    <StaggeredOverlayRoot className="settings-modal-overlay">
      <StaggeredOverlayBackdrop
        visible={backdropVisible}
        onClose={onClose}
        style={backdropStyle}
        className="staggered-overlay-backdrop--deep"
      />
      <StaggeredOverlayPanel
        open={panelOpen}
        className={`settings-modal-panel terminal-overlay-panel-shell${isMobile ? " settings-modal-panel--mobile" : " settings-modal-panel--desktop staggered-overlay-panel--scale"}${isShortcutsSubmenu ? " settings-modal-panel--shortcuts-wide" : ""}`}
        aria-label="Settings"
      >
        <ModalHeader
          className="settings-modal-header"
          onClose={onClose}
          closeLabel="Close settings"
          title="Settings"
        />

        <div
          className={`settings-modal-body settings-modal-two-column${activeSubmenu ? " has-submenu" : ""}${isShortcutsSubmenu ? " settings-modal-two-column--shortcuts-wide" : ""}`}
        >
          <div className="settings-menu-column">
            {resolvedMenuGroups.map((group) => (
              <div key={group.id} className="settings-menu-group">
                <div className="settings-menu-group-label" aria-hidden="true">
                  {group.label}
                </div>
                {group.items
                  .filter(
                    (item) =>
                      (item.key !== "hilSafetyTabs" ||
                        state.layout === "layout4") &&
                      (item.key !== "highAgencyTabs" ||
                        state.layout === "layout3") &&
                      (item.key !== "gateIntentTimer" ||
                        state.layout === "layout3"),
                  )
                  .map(({ key, label }) => (
                  <SettingsMenuButton
                    key={key}
                    label={label}
                    isActive={activeSubmenu === key}
                    onClick={() => toggleSubmenu(key)}
                  />
                ))}
              </div>
            ))}
          </div>

          <div
            className={`settings-options-column${activeSubmenu ? " visible" : ""}`}
            data-submenu={activeSubmenu ?? undefined}
          >
            <SubmenuContent
              activeSubmenu={activeSubmenu}
              state={state}
              onChoiceSelect={handleChoiceSelect}
              onChartProviderSelect={handleChartProviderSelect}
              onChartOverlayToggle={handleChartOverlayToggle}
              onOrderbookToggle={handleOrderbookToggle}
              onTooltipsToggle={handleTooltipsToggle}
              onTooltipGroupToggle={handleTooltipGroupToggle}
              onCompactFavoritesBarToggle={handleCompactFavoritesBarToggle}
              onWalletAccountValueToggle={handleWalletAccountValueToggle}
              onKeyboardShortcutsChange={handleKeyboardShortcutsChange}
              onCopytradeChange={handleCopytradeChange}
              onIndexChange={handleIndexChange}
              onPortfolioChange={handlePortfolioChange}
              onAgentChange={handleAgentChange}
              onHilSafetyTabsChange={handleHilSafetyTabsChange}
              onHighAgencyTabsChange={handleHighAgencyTabsChange}
              onHeaderNavChange={handleHeaderNavChange}
              onStakingChange={handleStakingChange}
              onVaultListChange={handleVaultListChange}
              onAgentRolesChange={handleAgentRolesChange}
              onGateIntentTimerChange={handleGateIntentTimerChange}
              onLayoutEdit={onLayoutEdit}
            />
          </div>
        </div>

        <div className="settings-modal-footer">
          {onOpenKeyboardShortcuts ? (
            <button
              type="button"
              className="settings-keyboard-shortcuts-link"
              onClick={() => {
                onClose();
                onOpenKeyboardShortcuts();
              }}
            >
              Keyboard shortcuts →
            </button>
          ) : null}
          <span className="settings-version">
            {new Date().toLocaleDateString()}.006a0e1
          </span>
        </div>
      </StaggeredOverlayPanel>
    </StaggeredOverlayRoot>
  );

  return typeof document !== "undefined"
    ? createPortal(modalContent, document.body)
    : null;
}

export default SettingsModal;
