import { useState } from "react";

import { CreditCard } from "@mormlayer/components/ui/credit-card/CreditCard";
import type { CreditCardType } from "@mormlayer/components/ui/credit-card/CreditCard";

import { ALL_DECORATIVE_CARD_TYPES } from "./decorativeCardTypes";
import { ComponentDocPage } from "../layout/ComponentDocPage";
import { DocSection } from "../layout/DocSection";
import { PreviewCanvas } from "../layout/PreviewCanvas";
import { VariantGrid, VariantTile } from "../layout/VariantGrid";

const SIZE_WIDTHS = [316, 280, 220] as const;

export function CreditCardsPage(): JSX.Element {
  const [company, setCompany] = useState("Morpheum.");
  const [cardNumber, setCardNumber] = useState("5678 9012 3456 7890");
  const [cardHolder, setCardHolder] = useState("PEDRO FRANCESCHI");
  const [cardExpiration, setCardExpiration] = useState("12/28");
  const [type, setType] = useState<CreditCardType>("brand-dark");
  const [width, setWidth] = useState(316);

  return (
    <ComponentDocPage
      title="Credit cards"
      description="Decorative credit card component with 13 visual variants and width-based scaling. Ported from Untitled UI and restyled with Morpheum terminal tokens."
    >
      <DocSection
        title="Credit card example"
        description="Default preview on a terminal canvas."
      >
        <PreviewCanvas>
          <CreditCard type="brand-dark" />
        </PreviewCanvas>
      </DocSection>

      <DocSection
        title="Customization"
        description="Edit props live — company, card number, holder, expiration, type, and width."
      >
        <div className="uitest-controls">
          <label className="uitest-field">
            <span className="uitest-field__label">Company</span>
            <input
              className="uitest-input"
              value={company}
              onChange={(e) => setCompany(e.target.value)}
            />
          </label>
          <label className="uitest-field">
            <span className="uitest-field__label">Card number</span>
            <input
              className="uitest-input"
              value={cardNumber}
              onChange={(e) => setCardNumber(e.target.value)}
            />
          </label>
          <label className="uitest-field">
            <span className="uitest-field__label">Card holder</span>
            <input
              className="uitest-input"
              value={cardHolder}
              onChange={(e) => setCardHolder(e.target.value)}
            />
          </label>
          <label className="uitest-field">
            <span className="uitest-field__label">Expiration</span>
            <input
              className="uitest-input"
              value={cardExpiration}
              onChange={(e) => setCardExpiration(e.target.value)}
            />
          </label>
          <label className="uitest-field">
            <span className="uitest-field__label">Type</span>
            <select
              className="uitest-input"
              value={type}
              onChange={(e) => setType(e.target.value as CreditCardType)}
            >
              {ALL_DECORATIVE_CARD_TYPES.map((variant) => (
                <option key={variant} value={variant}>
                  {variant}
                </option>
              ))}
            </select>
          </label>
          <label className="uitest-field">
            <span className="uitest-field__label">Width ({width}px)</span>
            <input
              className="uitest-input"
              type="range"
              min={180}
              max={360}
              step={4}
              value={width}
              onChange={(e) => setWidth(Number(e.target.value))}
            />
          </label>
        </div>
        <PreviewCanvas minHeight={240}>
          <CreditCard
            company={company}
            cardNumber={cardNumber}
            cardHolder={cardHolder}
            cardExpiration={cardExpiration}
            type={type}
            width={width}
          />
        </PreviewCanvas>
      </DocSection>

      <DocSection
        title="Sizes"
        description="The width prop scales the card while preserving the 316×190 aspect ratio."
      >
        <VariantGrid columns={3}>
          {SIZE_WIDTHS.map((size) => (
            <VariantTile key={size} label={`${size}px wide`}>
              <CreditCard type="brand-dark" width={size} />
            </VariantTile>
          ))}
        </VariantGrid>
      </DocSection>

      <DocSection
        title="Credit card types"
        description="All decorative shell variants — normal, strip, and vertical strip layouts."
      >
        <VariantGrid columns={3}>
          {ALL_DECORATIVE_CARD_TYPES.map((variant) => (
            <VariantTile key={variant} label={variant}>
              <CreditCard type={variant} width={260} />
            </VariantTile>
          ))}
        </VariantGrid>
      </DocSection>
    </ComponentDocPage>
  );
}
