import React, {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useRef,
  useState,
  type ReactNode,
} from "react";
import { useNavigate } from "react-router-dom";
import { toast } from "sonner";

import { getEffectiveMockBalance } from "../../../offline/mock_data";
import { subscribeCopyMirrorListeners } from "../../../offline/mock_data/copyMirrorState";
import { APP_ROUTES } from "../../routes";
import { isDesktopTourBreakpoint } from "../welcome-tour/constants";
import {
  COPY_TOUR_AGENT_ID,
  COPY_TOUR_MIN_SPOT_USDC,
  COPY_TOUR_TARGETS,
} from "./constants";
import { resetCopyTourAgentState } from "./copyTourReset";
import {
  inferTourBreakpointFromWidth,
  isCopyTourGateSatisfied,
  resolveMirrorProfitForTour,
} from "./copyTourFlowSync";

export interface StartCopyTourOptions {
  skipBalanceCheck?: boolean;
}

export interface CopyTourGateState {
  confirmComplete: boolean;
  stripVisible: boolean;
  mirrorProfit: boolean;
  pnlVisible: boolean;
}

export interface CopyTourContextValue {
  runTour: boolean;
  stepIndex: number;
  tourBucketId: string | null;
  openStatusModal: boolean;
  showPreflightModal: boolean;
  preflightSpotBalance: number;
  preflightDepositAmount: number;
  gateState: CopyTourGateState;
  currentBreakpoint: string;
  startCopyTour: (options?: StartCopyTourOptions) => void;
  stopTour: () => void;
  onTourComplete: () => void;
  setStepIndex: (index: number | ((prev: number) => number)) => void;
  notifyConfirmComplete: (bucketId: string) => void;
  notifyPnlVisible: () => void;
  dismissPreflight: () => void;
  startPreflightDeposit: () => void;
  onDepositCompleteForCopyTour: () => void;
  cancelDepositHandoff: () => void;
  registerTourMutex: (fn: () => void) => () => void;
  registerOpenDepositForCopyTour: (fn: (amount: number) => void) => () => void;
  registerSpotBalance: (getter: () => number) => () => void;
  registerWallet: (getter: () => string | null) => () => void;
  registerBreakpoint: (getter: () => string) => () => void;
}

const defaultGateState: CopyTourGateState = {
  confirmComplete: false,
  stripVisible: false,
  mirrorProfit: false,
  pnlVisible: false,
};

const CopyTourContext = createContext<CopyTourContextValue | undefined>(undefined);

export interface CopyTourProviderProps {
  children: ReactNode;
  onCopyTourSeen?: () => void;
}

function readSpotBalance(
  wallet: string | null | undefined,
  getter: (() => number) | null,
): number {
  if (getter) return getter();
  if (!wallet?.trim()) return 0;
  return getEffectiveMockBalance(wallet, "USDC");
}

function isStripTargetVisible(): boolean {
  const el = document.querySelector(`[data-tour="${COPY_TOUR_TARGETS.mirroredStrip}"]`);
  return Boolean(el && el.getBoundingClientRect().height > 0);
}

export function CopyTourProvider({
  children,
  onCopyTourSeen,
}: CopyTourProviderProps): JSX.Element {
  const navigate = useNavigate();
  const [runTour, setRunTour] = useState(false);
  const [stepIndex, setStepIndex] = useState(0);
  const [tourBucketId, setTourBucketId] = useState<string | null>(null);
  const [openStatusModal, setOpenStatusModal] = useState(false);
  const [showPreflightModal, setShowPreflightModal] = useState(false);
  const [preflightSpotBalance, setPreflightSpotBalance] = useState(0);
  const [preflightDepositAmount, setPreflightDepositAmount] = useState(0);
  const [gateState, setGateState] = useState<CopyTourGateState>(defaultGateState);
  const [currentBreakpoint, setCurrentBreakpointState] = useState("lg");
  const [resumeAfterDeposit, setResumeAfterDeposit] = useState(false);

  const walletGetterRef = useRef<(() => string | null) | null>(null);
  const spotBalanceRef = useRef<(() => number) | null>(null);

  const resolveWallet = useCallback((): string | null => {
    return walletGetterRef.current?.()?.trim().toLowerCase() ?? null;
  }, []);
  const openDepositRef = useRef<((amount: number) => void) | null>(null);
  const tourMutexRef = useRef<(() => void) | null>(null);
  const breakpointRef = useRef<(() => string) | null>(null);

  const stopTour = useCallback(() => {
    setRunTour(false);
    setStepIndex(0);
    setTourBucketId(null);
    setOpenStatusModal(false);
    setGateState(defaultGateState);
    setResumeAfterDeposit(false);
  }, []);

  const onTourComplete = useCallback(() => {
    setRunTour(false);
    setStepIndex(0);
    setTourBucketId(null);
    setOpenStatusModal(false);
    setGateState(defaultGateState);
    setResumeAfterDeposit(false);
    onCopyTourSeen?.();
  }, [onCopyTourSeen]);

  const launchJoyride = useCallback(
    (wallet: string) => {
      resetCopyTourAgentState(wallet, COPY_TOUR_AGENT_ID);
      setGateState(defaultGateState);
      setTourBucketId(null);
      setOpenStatusModal(false);
      setStepIndex(0);
      setRunTour(true);
      navigate(`/agents/${COPY_TOUR_AGENT_ID}?tab=action`);
    },
    [navigate],
  );

  const startCopyTour = useCallback(
    (options?: StartCopyTourOptions) => {
      const wallet = resolveWallet();
      if (!wallet) {
        toast.error("Connect wallet first", {
          description: "Connect your wallet before starting the copy tour.",
        });
        return;
      }

      const breakpoint = breakpointRef.current?.() ?? currentBreakpoint;
      if (!isDesktopTourBreakpoint(breakpoint)) {
        toast.info(
          "Copy tour is available on desktop and tablet view. Widen your window to explore step-by-step.",
        );
        return;
      }

      tourMutexRef.current?.();

      const balance = readSpotBalance(wallet, spotBalanceRef.current);
      if (!options?.skipBalanceCheck && balance < COPY_TOUR_MIN_SPOT_USDC) {
        const topUp = Math.max(1, Math.ceil(COPY_TOUR_MIN_SPOT_USDC - balance));
        setPreflightSpotBalance(balance);
        setPreflightDepositAmount(topUp);
        setShowPreflightModal(true);
        return;
      }

      setShowPreflightModal(false);
      launchJoyride(wallet);
    },
    [currentBreakpoint, launchJoyride, resolveWallet],
  );

  const dismissPreflight = useCallback(() => {
    setShowPreflightModal(false);
    setResumeAfterDeposit(false);
  }, []);

  const startPreflightDeposit = useCallback(() => {
    if (!openDepositRef.current) {
      toast.error("Deposit flow unavailable", {
        description: "Open the app shell and retry the copy tour.",
      });
      return;
    }
    setShowPreflightModal(false);
    setResumeAfterDeposit(true);
    openDepositRef.current(preflightDepositAmount);
  }, [preflightDepositAmount]);

  const onDepositCompleteForCopyTour = useCallback(() => {
    if (!resumeAfterDeposit) return;
    setResumeAfterDeposit(false);
    const wallet = resolveWallet();
    if (!wallet) return;
    const balance = readSpotBalance(wallet, spotBalanceRef.current);
    if (balance < COPY_TOUR_MIN_SPOT_USDC) {
      toast.error("Deposit incomplete", {
        description: `Spot USDC is still below ${COPY_TOUR_MIN_SPOT_USDC.toLocaleString()}. Try the deposit again.`,
      });
      setPreflightSpotBalance(balance);
      setPreflightDepositAmount(
        Math.max(1, Math.ceil(COPY_TOUR_MIN_SPOT_USDC - balance)),
      );
      setShowPreflightModal(true);
      return;
    }
    toast.success("Spot funded — starting copy tour");
    launchJoyride(wallet);
  }, [launchJoyride, resumeAfterDeposit, resolveWallet]);

  const cancelDepositHandoff = useCallback(() => {
    if (!resumeAfterDeposit) return;
    setResumeAfterDeposit(false);
    const wallet = resolveWallet();
    const balance = readSpotBalance(wallet, spotBalanceRef.current);
    setPreflightSpotBalance(balance);
    setPreflightDepositAmount(
      Math.max(1, Math.ceil(COPY_TOUR_MIN_SPOT_USDC - balance)),
    );
    setShowPreflightModal(true);
  }, [resolveWallet, resumeAfterDeposit]);

  const notifyConfirmComplete = useCallback(
    (bucketId: string) => {
      setTourBucketId(bucketId);
      setGateState((prev) => ({ ...prev, confirmComplete: true }));
      navigate(APP_ROUTES.portfolio);
    },
    [navigate],
  );

  const notifyPnlVisible = useCallback(() => {
    setGateState((prev) => ({ ...prev, pnlVisible: true }));
  }, []);

  const registerTourMutex = useCallback((fn: () => void) => {
    tourMutexRef.current = fn;
    return () => {
      if (tourMutexRef.current === fn) {
        tourMutexRef.current = null;
      }
    };
  }, []);

  const registerOpenDepositForCopyTour = useCallback((fn: (amount: number) => void) => {
    openDepositRef.current = fn;
    return () => {
      if (openDepositRef.current === fn) {
        openDepositRef.current = null;
      }
    };
  }, []);

  const registerSpotBalance = useCallback((getter: () => number) => {
    spotBalanceRef.current = getter;
    return () => {
      if (spotBalanceRef.current === getter) {
        spotBalanceRef.current = null;
      }
    };
  }, []);

  const registerWallet = useCallback((getter: () => string | null) => {
    walletGetterRef.current = getter;
    return () => {
      if (walletGetterRef.current === getter) {
        walletGetterRef.current = null;
      }
    };
  }, []);

  const registerBreakpoint = useCallback((getter: () => string) => {
    breakpointRef.current = getter;
    setCurrentBreakpointState(getter());
    return () => {
      if (breakpointRef.current === getter) {
        breakpointRef.current = null;
      }
    };
  }, []);

  useEffect(() => {
    if (!runTour) return;
    const wallet = resolveWallet();
    if (!wallet || !tourBucketId) return;

    const syncProfit = () => {
      const profit = resolveMirrorProfitForTour(wallet, tourBucketId);
      if (profit) {
        setGateState((prev) => ({ ...prev, mirrorProfit: true }));
        setOpenStatusModal(true);
      }
    };

    syncProfit();
    return subscribeCopyMirrorListeners(syncProfit);
  }, [runTour, tourBucketId, resolveWallet]);

  useEffect(() => {
    if (!runTour || stepIndex < 7 || !tourBucketId) return;
    setOpenStatusModal(true);
  }, [runTour, stepIndex, tourBucketId]);

  useEffect(() => {
    if (!runTour) return;
    const tick = () => {
      if (isStripTargetVisible()) {
        setGateState((prev) =>
          prev.stripVisible ? prev : { ...prev, stripVisible: true },
        );
      }
    };
    tick();
    const id = window.setInterval(tick, 200);
    return () => window.clearInterval(id);
  }, [runTour, stepIndex]);

  useEffect(() => {
    const onResize = () => {
      const width = window.innerWidth;
      setCurrentBreakpointState(inferTourBreakpointFromWidth(width));
    };
    onResize();
    window.addEventListener("resize", onResize);
    return () => window.removeEventListener("resize", onResize);
  }, []);

  const value = useMemo(
    (): CopyTourContextValue => ({
      runTour,
      stepIndex,
      tourBucketId,
      openStatusModal,
      showPreflightModal,
      preflightSpotBalance,
      preflightDepositAmount,
      gateState,
      currentBreakpoint,
      startCopyTour,
      stopTour,
      onTourComplete,
      setStepIndex,
      notifyConfirmComplete,
      notifyPnlVisible,
      dismissPreflight,
      startPreflightDeposit,
      onDepositCompleteForCopyTour,
      cancelDepositHandoff,
      registerTourMutex,
      registerOpenDepositForCopyTour,
      registerSpotBalance,
      registerWallet,
      registerBreakpoint,
    }),
    [
      runTour,
      stepIndex,
      tourBucketId,
      openStatusModal,
      showPreflightModal,
      preflightSpotBalance,
      preflightDepositAmount,
      gateState,
      currentBreakpoint,
      startCopyTour,
      stopTour,
      onTourComplete,
      notifyConfirmComplete,
      notifyPnlVisible,
      dismissPreflight,
      startPreflightDeposit,
      onDepositCompleteForCopyTour,
      cancelDepositHandoff,
      registerTourMutex,
      registerOpenDepositForCopyTour,
      registerSpotBalance,
      registerWallet,
      registerBreakpoint,
    ],
  );

  return (
    <CopyTourContext.Provider value={value}>{children}</CopyTourContext.Provider>
  );
}

export function useCopyTour(): CopyTourContextValue {
  const ctx = useContext(CopyTourContext);
  if (!ctx) {
    throw new Error("useCopyTour must be used within CopyTourProvider");
  }
  return ctx;
}

export function useOptionalCopyTour(): CopyTourContextValue | null {
  return useContext(CopyTourContext) ?? null;
}
