import { useState } from "react";

import "@mormlayer/components/preference/TerminalSettingsButton.css";
import "@mormlayer/components/tables/TabSection.css";
import TerminalBreadcrumb from "@mormlayer/components/ui/TerminalBreadcrumb";
import TerminalHeroHeader from "@mormlayer/components/ui/TerminalHeroHeader";
import type {
  TerminalHeroLayout,
  TerminalHeroSettingsReveal,
} from "@mormlayer/components/ui/TerminalHeroHeader";

import { ComponentDocPage } from "../layout/ComponentDocPage";
import { DocSection } from "../layout/DocSection";
import { PreviewCanvas } from "../layout/PreviewCanvas";
import { VariantGrid, VariantTile } from "../layout/VariantGrid";

function MockSettingsButton(): JSX.Element {
  return (
    <button
      type="button"
      className="terminal-settings-button terminal-settings-button--compact"
      aria-label="Page settings"
    >
      <svg
        className="terminal-settings-button-icon"
        fill="currentColor"
        viewBox="0 0 256 256"
        xmlns="http://www.w3.org/2000/svg"
        aria-hidden
      >
        <path d="M48,244.8l126-126c0.7-0.7,1.4-1.5,2.1-2.3c20.3,6.8,43.6,2.1,59.8-14.1c17.5-17.5,21.6-43.3,12.2-64.7l-38.5,38.5-30.2-30.2l38.5-38.5c-21.4-9.3-47.2-5.2-64.7,12.2c-16.2,16.2-20.9,39.5-14.1,59.8c-0.8,0.6-1.6,1.3-2.3,2.1l-126,126c-10.2,10.2-10.2,27,0,37.2C21,255,37.7,255,48,244.8z" />
      </svg>
    </button>
  );
}

export function TerminalHeroHeaderPage(): JSX.Element {
  const [title, setTitle] = useState("CopyTrade");
  const [layout, setLayout] = useState<TerminalHeroLayout>("stack");
  const [settingsReveal, setSettingsReveal] =
    useState<TerminalHeroSettingsReveal>("always");
  const [showBreadcrumb, setShowBreadcrumb] = useState(false);
  const [showSubtitle, setShowSubtitle] = useState(false);
  const [showActions, setShowActions] = useState(true);
  const [showTrailing, setShowTrailing] = useState(false);
  const [titleRowSpread, setTitleRowSpread] = useState(false);
  const [gridSingleColumn, setGridSingleColumn] = useState(false);
  const [inlineTrailing, setInlineTrailing] = useState(false);
  const [stackAlignStart, setStackAlignStart] = useState(false);
  const [contentGapMd, setContentGapMd] = useState(false);
  const [settingsPadding, setSettingsPadding] = useState(false);

  const breadcrumb = showBreadcrumb ? (
    <TerminalBreadcrumb
      segments={[
        { label: "CopyTrade", to: "/" },
        { label: "Alpha Arb" },
      ]}
    />
  ) : undefined;

  const subtitle = showSubtitle ? (
    <span className="terminal-label">REGIME_ALPHA_V3 · 24h volume $1.2M</span>
  ) : undefined;

  const trailing =
    showTrailing && layout === "grid" ? (
      <nav className="raw-pro-data-toggle uitest-hero-trailing-nav" aria-label="View">
        <button type="button" className="raw-pro-data-toggle-segment is-active">
          Overview
        </button>
        <button type="button" className="raw-pro-data-toggle-segment">
          Positions
        </button>
      </nav>
    ) : showTrailing && inlineTrailing ? (
      <div className="uitest-hero-inline-actions">
        <button type="button" className="uitest-hero-inline-actions__btn">
          Filters
        </button>
        <button
          type="button"
          className="uitest-hero-inline-actions__btn uitest-hero-inline-actions__btn--primary"
        >
          Create
        </button>
      </div>
    ) : null;

  const titleTrailing =
    titleRowSpread && !showTrailing ? (
      <span className="terminal-price">$12,480.00</span>
    ) : null;

  return (
    <ComponentDocPage
      title="Terminal hero header"
      description="Shared page title band for terminal slots — stack and grid layouts, breadcrumbs, settings chrome, and trailing actions."
    >
      <DocSection
        title="Default preview"
        description="Simple stack layout with title and settings gear, as used on CopyTrade."
      >
        <PreviewCanvas minHeight={88}>
          <TerminalHeroHeader
            className="uitest-hero-band"
            height="72px"
            title="CopyTrade"
            actions={<MockSettingsButton />}
          />
        </PreviewCanvas>
      </DocSection>

      <DocSection
        title="Customization"
        description="Toggle layout, breadcrumb, subtitle, settings reveal, and trailing slots."
      >
        <div className="uitest-controls">
          <label className="uitest-field">
            <span className="uitest-field__label">Title</span>
            <input
              className="uitest-input"
              value={title}
              onChange={(e) => setTitle(e.target.value)}
            />
          </label>
          <label className="uitest-field">
            <span className="uitest-field__label">Layout</span>
            <select
              className="uitest-input"
              value={layout}
              onChange={(e) =>
                setLayout(e.target.value as TerminalHeroLayout)
              }
            >
              <option value="stack">Stack</option>
              <option value="grid">Grid</option>
            </select>
          </label>
          <label className="uitest-field">
            <span className="uitest-field__label">Settings reveal</span>
            <select
              className="uitest-input"
              value={settingsReveal}
              onChange={(e) =>
                setSettingsReveal(e.target.value as TerminalHeroSettingsReveal)
              }
            >
              <option value="always">Always</option>
              <option value="hover">Hover</option>
            </select>
          </label>
          <label className="uitest-field uitest-field--checkbox">
            <input
              type="checkbox"
              checked={showBreadcrumb}
              onChange={(e) => setShowBreadcrumb(e.target.checked)}
            />
            <span className="uitest-field__label">Breadcrumb</span>
          </label>
          <label className="uitest-field uitest-field--checkbox">
            <input
              type="checkbox"
              checked={showSubtitle}
              onChange={(e) => setShowSubtitle(e.target.checked)}
            />
            <span className="uitest-field__label">Subtitle</span>
          </label>
          <label className="uitest-field uitest-field--checkbox">
            <input
              type="checkbox"
              checked={showActions}
              onChange={(e) => setShowActions(e.target.checked)}
            />
            <span className="uitest-field__label">Settings actions</span>
          </label>
          <label className="uitest-field uitest-field--checkbox">
            <input
              type="checkbox"
              checked={showTrailing}
              onChange={(e) => setShowTrailing(e.target.checked)}
            />
            <span className="uitest-field__label">Trailing slot</span>
          </label>
          <label className="uitest-field uitest-field--checkbox">
            <input
              type="checkbox"
              checked={titleRowSpread}
              onChange={(e) => setTitleRowSpread(e.target.checked)}
            />
            <span className="uitest-field__label">Title row spread</span>
          </label>
          <label className="uitest-field uitest-field--checkbox">
            <input
              type="checkbox"
              checked={gridSingleColumn}
              onChange={(e) => setGridSingleColumn(e.target.checked)}
              disabled={layout !== "grid"}
            />
            <span className="uitest-field__label">Grid single column</span>
          </label>
          <label className="uitest-field uitest-field--checkbox">
            <input
              type="checkbox"
              checked={inlineTrailing}
              onChange={(e) => setInlineTrailing(e.target.checked)}
              disabled={layout !== "stack"}
            />
            <span className="uitest-field__label">Inline trailing</span>
          </label>
          <label className="uitest-field uitest-field--checkbox">
            <input
              type="checkbox"
              checked={stackAlignStart}
              onChange={(e) => setStackAlignStart(e.target.checked)}
              disabled={layout !== "stack"}
            />
            <span className="uitest-field__label">Stack align start</span>
          </label>
          <label className="uitest-field uitest-field--checkbox">
            <input
              type="checkbox"
              checked={contentGapMd}
              onChange={(e) => setContentGapMd(e.target.checked)}
            />
            <span className="uitest-field__label">Content gap md</span>
          </label>
          <label className="uitest-field uitest-field--checkbox">
            <input
              type="checkbox"
              checked={settingsPadding}
              onChange={(e) => setSettingsPadding(e.target.checked)}
            />
            <span className="uitest-field__label">Settings padding</span>
          </label>
        </div>
        <PreviewCanvas minHeight={layout === "grid" ? 96 : 88}>
          <TerminalHeroHeader
            className="uitest-hero-band"
            height={layout === "grid" ? "80px" : "72px"}
            layout={layout}
            stackAlign={stackAlignStart ? "start" : "center"}
            settingsReveal={settingsReveal}
            settingsPadding={settingsPadding}
            gridSingleColumn={gridSingleColumn}
            inlineTrailing={inlineTrailing}
            contentGap={contentGapMd ? "md" : "sm"}
            breadcrumb={breadcrumb}
            title={title}
            subtitle={subtitle}
            titleRowSpread={titleRowSpread}
            titleTrailing={titleTrailing}
            actions={showActions ? <MockSettingsButton /> : undefined}
            trailing={trailing}
          />
        </PreviewCanvas>
      </DocSection>

      <DocSection
        title="Variants"
        description="Common hero band configurations across terminal pages."
      >
        <VariantGrid columns={1}>
          <VariantTile label="Stack — title + settings">
            <TerminalHeroHeader
              className="uitest-hero-band"
              height="72px"
              title="CopyTrade"
              actions={<MockSettingsButton />}
            />
          </VariantTile>
          <VariantTile label="Grid — title + view nav">
            <TerminalHeroHeader
              className="uitest-hero-band"
              height="80px"
              layout="grid"
              settingsReveal="hover"
              title="Staking"
              actions={<MockSettingsButton />}
              trailing={
                <nav
                  className="raw-pro-data-toggle uitest-hero-trailing-nav"
                  aria-label="Staking view"
                >
                  <button
                    type="button"
                    className="raw-pro-data-toggle-segment is-active"
                  >
                    Stake
                  </button>
                  <button type="button" className="raw-pro-data-toggle-segment">
                    Rewards
                  </button>
                </nav>
              }
            />
          </VariantTile>
          <VariantTile label="Grid — disconnected (single column)">
            <TerminalHeroHeader
              className="uitest-hero-band"
              height="72px"
              layout="grid"
              gridSingleColumn
              title="Staking"
              actions={<MockSettingsButton />}
            />
          </VariantTile>
          <VariantTile label="Stack — breadcrumb + price spread">
            <TerminalHeroHeader
              className="uitest-hero-band"
              height="88px"
              settingsPadding
              settingsReveal="hover"
              breadcrumb={
                <TerminalBreadcrumb
                  segments={[
                    { label: "Index", to: "/" },
                    { label: "Property Alpha" },
                  ]}
                />
              }
              title="Property Alpha"
              titleRowSpread
              titleTrailing={<span className="terminal-price">$12,480.00</span>}
              actions={<MockSettingsButton />}
            />
          </VariantTile>
          <VariantTile label="Stack start — breadcrumb + subtitle">
            <TerminalHeroHeader
              className="uitest-hero-band"
              height="96px"
              stackAlign="start"
              contentGap="md"
              breadcrumb={
                <TerminalBreadcrumb
                  segments={[
                    { label: "CopyTrade", to: "/" },
                    { label: "Alpha Arb" },
                  ]}
                />
              }
              title="Alpha Arb"
              subtitle={
                <span className="terminal-label">REGIME_ALPHA_V3</span>
              }
            />
          </VariantTile>
          <VariantTile label="Stack — inline trailing (mobile vault)">
            <TerminalHeroHeader
              className="uitest-hero-band"
              height="72px"
              inlineTrailing
              title="Vaults"
              trailing={
                <div className="uitest-hero-inline-actions">
                  <button type="button" className="uitest-hero-inline-actions__btn">
                    Filters
                  </button>
                  <button
                    type="button"
                    className="uitest-hero-inline-actions__btn uitest-hero-inline-actions__btn--primary"
                  >
                    Create Vault
                  </button>
                </div>
              }
            />
          </VariantTile>
        </VariantGrid>
      </DocSection>
    </ComponentDocPage>
  );
}
