import React from "react";
import "./presetCardGrid.css";

export type PresetCardTone = "manual" | "guarded" | "high";

export type PresetCardOption<T extends string = string> = {
  value: T;
  label: string;
  description: string;
  tone?: PresetCardTone;
  /** When true, show warn suffix on non-selected cards */
  warn?: boolean;
  disabled?: boolean;
};

export interface PresetCardGridProps<T extends string> {
  options: readonly PresetCardOption<T>[];
  selected: T;
  onSelect: (value: T) => void;
  /** Override per-card active state (bucket uses: preset match AND not custom) */
  isActive?: (option: PresetCardOption<T>) => boolean;
  disabled?: boolean;
  columns?: 2 | 3;
  warnLabel?: string;
  /** Optional contextual hint rendered below the grid */
  hint?: React.ReactNode;
  hintClassName?: string;
  className?: string;
  "aria-label"?: string;
}

const DEFAULT_WARN_LABEL = " needs confirm";

function cardIsActive<T extends string>(
  option: PresetCardOption<T>,
  selected: T,
  isActive?: (option: PresetCardOption<T>) => boolean,
): boolean {
  return isActive ? isActive(option) : selected === option.value;
}

export function PresetCardGrid<T extends string>({
  options,
  selected,
  onSelect,
  isActive,
  disabled = false,
  columns = 3,
  warnLabel = DEFAULT_WARN_LABEL,
  hint,
  hintClassName = "preset-card-hint",
  className,
  "aria-label": ariaLabel,
}: PresetCardGridProps<T>): JSX.Element {
  const gridClassName = [
    "preset-card-grid",
    `preset-card-grid--cols-${columns}`,
    className,
  ]
    .filter(Boolean)
    .join(" ");

  return (
    <>
      <div className={gridClassName} aria-label={ariaLabel}>
        {options.map((option) => {
          const active = cardIsActive(option, selected, isActive);
          const cardClassName = [
            "preset-card",
            active ? "is-active" : "",
            option.tone ? `preset-card--${option.tone}` : "",
          ]
            .filter(Boolean)
            .join(" ");

          return (
            <button
              key={option.value}
              type="button"
              className={cardClassName}
              onClick={() => onSelect(option.value)}
              disabled={disabled || option.disabled}
              aria-pressed={active}
            >
              <span className="preset-card-label">
                {option.label}
                {option.warn && !active ? (
                  <span className="preset-card-warn">{warnLabel}</span>
                ) : null}
              </span>
              <span className="preset-card-desc">{option.description}</span>
            </button>
          );
        })}
      </div>
      {hint != null && hint !== "" ? (
        <p className={hintClassName}>{hint}</p>
      ) : null}
    </>
  );
}
