import { useMemo, useState } from "react";

import { PresetCardGrid } from "@mormlayer/components/ui/PresetCardGrid";
import type { PresetCardOption } from "@mormlayer/components/ui/PresetCardGrid";

import { ComponentDocPage } from "../layout/ComponentDocPage";
import { DocSection } from "../layout/DocSection";
import { PreviewCanvas } from "../layout/PreviewCanvas";
import { VariantGrid, VariantTile } from "../layout/VariantGrid";

type PresetValue = "manual" | "guarded" | "high";

const BASE_OPTIONS: PresetCardOption<PresetValue>[] = [
  {
    value: "manual",
    label: "Manual",
    description: "Mirror signals; copied intents wait for you.",
    tone: "manual",
  },
  {
    value: "guarded",
    label: "Guarded",
    description: "More trades surface for approval; longer gate window.",
    tone: "guarded",
  },
  {
    value: "high",
    label: "High-Agency",
    description: "Silent execution when confidence and risk stay in band.",
    tone: "high",
    warn: true,
  },
];

export function PresetCardGridPage(): JSX.Element {
  const [selected, setSelected] = useState<PresetValue>("guarded");
  const [columns, setColumns] = useState<2 | 3>(3);
  const [showWarn, setShowWarn] = useState(true);
  const [hint, setHint] = useState(
    "Guarded preset — copied trades need approval above the silent band.",
  );

  const options = useMemo(
    () =>
      BASE_OPTIONS.map((option) => ({
        ...option,
        warn: option.value === "high" ? showWarn : option.warn,
      })),
    [showWarn],
  );

  return (
    <ComponentDocPage
      title="Preset card grid"
      description="Selectable preset cards with tone modifiers, optional warn suffix on non-selected options, and contextual hint text."
    >
      <DocSection
        title="Default preview"
        description="Three-column grid with manual, guarded, and high-agency tones."
      >
        <PreviewCanvas>
          <PresetCardGrid
            options={BASE_OPTIONS}
            selected="guarded"
            onSelect={() => {}}
            columns={3}
            hint="How much can agents do without your confirmation?"
            aria-label="Autonomy preset"
          />
        </PreviewCanvas>
      </DocSection>

      <DocSection
        title="Customization"
        description="Toggle columns, warn flags, and hint copy — select cards to see active state."
      >
        <div className="uitest-controls">
          <label className="uitest-field">
            <span className="uitest-field__label">Columns</span>
            <select
              className="uitest-input"
              value={columns}
              onChange={(e) => setColumns(Number(e.target.value) as 2 | 3)}
            >
              <option value={2}>2</option>
              <option value={3}>3</option>
            </select>
          </label>
          <label className="uitest-field uitest-field--checkbox">
            <input
              type="checkbox"
              checked={showWarn}
              onChange={(e) => setShowWarn(e.target.checked)}
            />
            <span className="uitest-field__label">Warn on high-agency (non-selected)</span>
          </label>
          <label className="uitest-field">
            <span className="uitest-field__label">Hint text</span>
            <input
              className="uitest-input"
              value={hint}
              onChange={(e) => setHint(e.target.value)}
            />
          </label>
        </div>
        <PreviewCanvas minHeight={200}>
          <PresetCardGrid
            options={options}
            selected={selected}
            onSelect={setSelected}
            columns={columns}
            hint={hint}
            aria-label="Autonomy preset"
          />
        </PreviewCanvas>
      </DocSection>

      <DocSection
        title="Column layouts"
        description="Two- and three-column grids with the same options."
      >
        <VariantGrid columns={2}>
          <VariantTile label="2 columns">
            <PresetCardGrid
              options={BASE_OPTIONS}
              selected="manual"
              onSelect={() => {}}
              columns={2}
              hint="Two-up layout for narrow surfaces."
            />
          </VariantTile>
          <VariantTile label="3 columns">
            <PresetCardGrid
              options={BASE_OPTIONS}
              selected="high"
              onSelect={() => {}}
              columns={3}
              hint="Three-up layout for modal width."
            />
          </VariantTile>
        </VariantGrid>
      </DocSection>

      <DocSection
        title="Tone modifiers"
        description="Manual, guarded, and high-agency card treatments."
      >
        <VariantGrid columns={3}>
          {BASE_OPTIONS.map((option) => (
            <VariantTile key={option.value} label={option.tone ?? option.value}>
              <PresetCardGrid
                options={[option]}
                selected={option.value}
                onSelect={() => {}}
                columns={3}
              />
            </VariantTile>
          ))}
        </VariantGrid>
      </DocSection>
    </ComponentDocPage>
  );
}
