import React, { type ReactNode } from "react";
import "./animatedCollapse.css";

export type AnimatedCollapseTiming = "normal" | "deck";

export interface AnimatedCollapseProps {
  open: boolean;
  children: ReactNode;
  className?: string;
  innerClassName?: string;
  timing?: AnimatedCollapseTiming;
  hiddenWhenClosed?: boolean;
  blockInteractionWhenClosed?: boolean;
}

export function AnimatedCollapse({
  open,
  children,
  className,
  innerClassName,
  timing = "normal",
  hiddenWhenClosed = true,
  blockInteractionWhenClosed = true,
}: AnimatedCollapseProps): JSX.Element {
  const outerClassName = [
    "animated-collapse",
    open ? "is-open" : "",
    `animated-collapse--${timing}`,
    blockInteractionWhenClosed ? "animated-collapse--block-closed" : "",
    className,
  ]
    .filter(Boolean)
    .join(" ");

  const innerClass = ["animated-collapse__inner", innerClassName]
    .filter(Boolean)
    .join(" ");

  return (
    <div
      className={outerClassName}
      aria-hidden={hiddenWhenClosed ? !open : undefined}
    >
      <div className={innerClass}>{children}</div>
    </div>
  );
}
