import { useMemo, useState } from "react";

import {
  AgentIdentityBadge,
  type AgentIdentityBadgePresentation,
  type AgentIdentityBadgeType,
} from "@mormlayer/components/ui/organization-badge/OrganizationNameBadge";
import type { AgentListingStatus, TradingAgentStatus } from "@mormlayer/store/types";

import { ALL_DECORATIVE_CARD_TYPES } from "./decorativeCardTypes";
import { ComponentDocPage } from "../layout/ComponentDocPage";
import { DocSection } from "../layout/DocSection";
import { PreviewCanvas } from "../layout/PreviewCanvas";
import { VariantGrid, VariantTile } from "../layout/VariantGrid";

const DEMO_DID = "did:morpheum:agent:0xf8a2c91e4b7d6035";

const DEMO_TIER5 = {
  displayName: "Alpha Arb",
  role: "Regime Detector",
  did: DEMO_DID,
};

const SIZE_WIDTHS = [316, 280, 220] as const;

export function OrganizationBadgesPage(): JSX.Element {
  const [displayName, setDisplayName] = useState(DEMO_TIER5.displayName);
  const [role, setRole] = useState(DEMO_TIER5.role);
  const [did, setDid] = useState(DEMO_TIER5.did);
  const [handle, setHandle] = useState("regime_alpha_v3");
  const [versionTag, setVersionTag] = useState("v3");
  const [custodyKind, setCustodyKind] = useState<"wallet" | "vault" | "did_only">(
    "did_only",
  );
  const [fleetName, setFleetName] = useState("LP Guardian Swarm");
  const [status, setStatus] = useState<TradingAgentStatus>("active");
  const [permissionMode, setPermissionMode] = useState<
    "watch_only" | "hil" | "high_agency"
  >("watch_only");
  const [listingStatus, setListingStatus] = useState<AgentListingStatus>("listed");
  const [showTier4, setShowTier4] = useState(true);
  const [showTier3, setShowTier3] = useState(true);
  const [type, setType] = useState<AgentIdentityBadgeType>("brand-dark");
  const [width, setWidth] = useState(316);
  const [presentation, setPresentation] = useState<
    AgentIdentityBadgePresentation | "auto"
  >("auto");

  const sharedProps = useMemo(
    () => ({
      displayName,
      role,
      did,
      ...(showTier4
        ? { handle, versionTag, custodyKind }
        : {}),
      ...(showTier3
        ? { fleetName, status, permissionMode, listingStatus }
        : {}),
      type,
      width,
      presentation: presentation === "auto" ? undefined : presentation,
    }),
    [
      custodyKind,
      did,
      displayName,
      fleetName,
      handle,
      listingStatus,
      permissionMode,
      presentation,
      role,
      showTier3,
      showTier4,
      status,
      type,
      versionTag,
      width,
    ],
  );

  const compactProps = {
    displayName,
    role,
    did,
    status: showTier3 ? status : undefined,
    listingStatus: showTier3 ? listingStatus : undefined,
  };

  const cardProps = {
    displayName,
    role,
    did,
    ...(showTier4 ? { handle, versionTag, custodyKind } : {}),
    fleetName: showTier3 ? fleetName : undefined,
    listingStatus: showTier3 ? listingStatus : undefined,
    width: 280,
  };

  const passportProps = {
    ...sharedProps,
    presentation: "passport" as const,
    width: 316,
  };

  return (
    <ComponentDocPage
      title="Agent identity badges"
      description="Worker-tag identity badges for fleet agents. Tier 5 fields are required; tier 4 and 3 are optional and drive compact, card, or passport presentation."
    >
      <DocSection
        title="Compact — tier 5"
        description="Recognition chip for dense surfaces. Morpheum logo by default; listed agents show a DID-derived character SVG."
      >
        <PreviewCanvas>
          <AgentIdentityBadge {...compactProps} presentation="compact" />
        </PreviewCanvas>
      </DocSection>

      <DocSection
        title="Card — tier 5 + tier 4"
        description="Standard worker tag on the decorative card shell."
      >
        <PreviewCanvas minHeight={220}>
          <AgentIdentityBadge {...cardProps} presentation="card" />
        </PreviewCanvas>
      </DocSection>

      <DocSection
        title="Passport — full identity"
        description="Verification tag with fleet scope, status, permission, handle, and KYA DID."
      >
        <PreviewCanvas minHeight={280}>
          <AgentIdentityBadge {...passportProps} />
        </PreviewCanvas>
      </DocSection>

      <DocSection
        title="Customization"
        description="Toggle optional tiers and listing state to see emblem swap and auto presentation."
      >
        <div className="uitest-controls">
          <label className="uitest-field">
            <span className="uitest-field__label">Display name</span>
            <input
              className="uitest-input"
              value={displayName}
              onChange={(e) => setDisplayName(e.target.value)}
            />
          </label>
          <label className="uitest-field">
            <span className="uitest-field__label">Role</span>
            <input
              className="uitest-input"
              value={role}
              onChange={(e) => setRole(e.target.value)}
            />
          </label>
          <label className="uitest-field">
            <span className="uitest-field__label">KYA DID</span>
            <input
              className="uitest-input"
              value={did}
              onChange={(e) => setDid(e.target.value)}
            />
          </label>
          <label className="uitest-field uitest-field--checkbox">
            <input
              type="checkbox"
              checked={showTier4}
              onChange={(e) => setShowTier4(e.target.checked)}
            />
            <span className="uitest-field__label">Tier 4 (handle, version, custody)</span>
          </label>
          {showTier4 ? (
            <>
              <label className="uitest-field">
                <span className="uitest-field__label">Handle</span>
                <input
                  className="uitest-input"
                  value={handle}
                  onChange={(e) => setHandle(e.target.value)}
                />
              </label>
              <label className="uitest-field">
                <span className="uitest-field__label">Version</span>
                <input
                  className="uitest-input"
                  value={versionTag}
                  onChange={(e) => setVersionTag(e.target.value)}
                />
              </label>
              <label className="uitest-field">
                <span className="uitest-field__label">Custody</span>
                <select
                  className="uitest-input"
                  value={custodyKind}
                  onChange={(e) =>
                    setCustodyKind(e.target.value as typeof custodyKind)
                  }
                >
                  <option value="did_only">DID only</option>
                  <option value="wallet">Wallet</option>
                  <option value="vault">Vault</option>
                </select>
              </label>
            </>
          ) : null}
          <label className="uitest-field uitest-field--checkbox">
            <input
              type="checkbox"
              checked={showTier3}
              onChange={(e) => setShowTier3(e.target.checked)}
            />
            <span className="uitest-field__label">Tier 3 (fleet, status, permission, listing)</span>
          </label>
          {showTier3 ? (
            <>
              <label className="uitest-field">
                <span className="uitest-field__label">Fleet</span>
                <input
                  className="uitest-input"
                  value={fleetName}
                  onChange={(e) => setFleetName(e.target.value)}
                />
              </label>
              <label className="uitest-field">
                <span className="uitest-field__label">Status</span>
                <select
                  className="uitest-input"
                  value={status}
                  onChange={(e) => setStatus(e.target.value as TradingAgentStatus)}
                >
                  <option value="active">Online</option>
                  <option value="idle">Idle</option>
                  <option value="paused">Paused</option>
                </select>
              </label>
              <label className="uitest-field">
                <span className="uitest-field__label">Permission</span>
                <select
                  className="uitest-input"
                  value={permissionMode}
                  onChange={(e) =>
                    setPermissionMode(e.target.value as typeof permissionMode)
                  }
                >
                  <option value="watch_only">Watch-only</option>
                  <option value="hil">HIL</option>
                  <option value="high_agency">High-Agency</option>
                </select>
              </label>
              <label className="uitest-field">
                <span className="uitest-field__label">Listing</span>
                <select
                  className="uitest-input"
                  value={listingStatus}
                  onChange={(e) =>
                    setListingStatus(e.target.value as AgentListingStatus)
                  }
                >
                  <option value="private">Private</option>
                  <option value="staged">Staged</option>
                  <option value="listed">Listed</option>
                  <option value="delisted">Delisted</option>
                </select>
              </label>
            </>
          ) : null}
          <label className="uitest-field">
            <span className="uitest-field__label">Presentation</span>
            <select
              className="uitest-input"
              value={presentation}
              onChange={(e) =>
                setPresentation(e.target.value as typeof presentation)
              }
            >
              <option value="auto">Auto</option>
              <option value="compact">Compact</option>
              <option value="card">Card</option>
              <option value="passport">Passport</option>
            </select>
          </label>
          <label className="uitest-field">
            <span className="uitest-field__label">Shell type</span>
            <select
              className="uitest-input"
              value={type}
              onChange={(e) => setType(e.target.value as AgentIdentityBadgeType)}
            >
              {ALL_DECORATIVE_CARD_TYPES.map((variant) => (
                <option key={variant} value={variant}>
                  {variant}
                </option>
              ))}
            </select>
          </label>
          <label className="uitest-field">
            <span className="uitest-field__label">Width ({width}px)</span>
            <input
              className="uitest-input"
              type="range"
              min={180}
              max={360}
              step={4}
              value={width}
              onChange={(e) => setWidth(Number(e.target.value))}
            />
          </label>
        </div>
        <PreviewCanvas minHeight={280}>
          <AgentIdentityBadge {...sharedProps} />
        </PreviewCanvas>
      </DocSection>

      <DocSection
        title="Sizes"
        description="Card presentation at common widths."
      >
        <VariantGrid columns={3}>
          {SIZE_WIDTHS.map((size) => (
            <VariantTile key={size} label={`${size}px wide`}>
              <AgentIdentityBadge
                {...cardProps}
                presentation="card"
                width={size}
              />
            </VariantTile>
          ))}
        </VariantGrid>
      </DocSection>

      <DocSection
        title="Shell variants"
        description="Passport presentation across decorative card types."
      >
        <VariantGrid columns={3}>
          {ALL_DECORATIVE_CARD_TYPES.map((variant) => (
            <VariantTile key={variant} label={variant}>
              <AgentIdentityBadge
                {...passportProps}
                type={variant}
                width={260}
              />
            </VariantTile>
          ))}
        </VariantGrid>
      </DocSection>

      <DocSection
        title="Listed vs private emblem"
        description="Listed agents resolve a character SVG from the KYA DID; private agents show the Morpheum logo."
      >
        <VariantGrid columns={2}>
          <VariantTile label="Private — Morpheum logo">
            <AgentIdentityBadge
              {...passportProps}
              listingStatus="private"
              width={260}
            />
          </VariantTile>
          <VariantTile label="Listed — DID avatar SVG">
            <AgentIdentityBadge
              {...passportProps}
              listingStatus="listed"
              width={260}
            />
          </VariantTile>
        </VariantGrid>
      </DocSection>
    </ComponentDocPage>
  );
}
