import { useState } from "react";

import { FilledRangeSlider } from "@mormlayer/components/ui/FilledRangeSlider";
import type {
  FilledRangeSize,
  FilledRangeVariant,
} from "@mormlayer/components/ui/FilledRangeSlider";

import { ComponentDocPage } from "../layout/ComponentDocPage";
import { DocSection } from "../layout/DocSection";
import { PreviewCanvas } from "../layout/PreviewCanvas";
import { VariantGrid, VariantTile } from "../layout/VariantGrid";

export function FilledRangeSliderPage(): JSX.Element {
  const [value, setValue] = useState(50);
  const [variant, setVariant] = useState<FilledRangeVariant>("brand");
  const [size, setSize] = useState<FilledRangeSize>("md");
  const [min, setMin] = useState(0);
  const [max, setMax] = useState(100);
  const [step, setStep] = useState(1);

  return (
    <ComponentDocPage
      title="Filled range slider"
      description="Terminal-styled range input with filled progress track. Supports brand and info variants, md/sm sizes, and configurable min, max, and step."
    >
      <DocSection
        title="Default preview"
        description="Brand variant at medium size on a terminal canvas."
      >
        <PreviewCanvas>
          <FilledRangeSlider
            min={0}
            max={100}
            value={50}
            onChange={() => {}}
            style={{ width: "100%", maxWidth: 320 }}
          />
        </PreviewCanvas>
      </DocSection>

      <DocSection
        title="Customization"
        description="Edit variant, size, min, max, step, and value live."
      >
        <div className="uitest-controls">
          <label className="uitest-field">
            <span className="uitest-field__label">Variant</span>
            <select
              className="uitest-input"
              value={variant}
              onChange={(e) => setVariant(e.target.value as FilledRangeVariant)}
            >
              <option value="brand">brand</option>
              <option value="info">info</option>
            </select>
          </label>
          <label className="uitest-field">
            <span className="uitest-field__label">Size</span>
            <select
              className="uitest-input"
              value={size}
              onChange={(e) => setSize(e.target.value as FilledRangeSize)}
            >
              <option value="md">md</option>
              <option value="sm">sm</option>
            </select>
          </label>
          <label className="uitest-field">
            <span className="uitest-field__label">Min</span>
            <input
              className="uitest-input"
              type="number"
              value={min}
              onChange={(e) => setMin(Number(e.target.value))}
            />
          </label>
          <label className="uitest-field">
            <span className="uitest-field__label">Max</span>
            <input
              className="uitest-input"
              type="number"
              value={max}
              onChange={(e) => setMax(Number(e.target.value))}
            />
          </label>
          <label className="uitest-field">
            <span className="uitest-field__label">Step</span>
            <input
              className="uitest-input"
              type="number"
              min={1}
              value={step}
              onChange={(e) => setStep(Number(e.target.value))}
            />
          </label>
          <label className="uitest-field">
            <span className="uitest-field__label">Value ({value})</span>
            <input
              className="uitest-input"
              type="range"
              min={min}
              max={max}
              step={step}
              value={Math.min(Math.max(value, min), max)}
              onChange={(e) => setValue(Number(e.target.value))}
            />
          </label>
        </div>
        <PreviewCanvas minHeight={120}>
          <FilledRangeSlider
            min={min}
            max={max}
            step={step}
            value={Math.min(Math.max(value, min), max)}
            onChange={setValue}
            variant={variant}
            size={size}
            style={{ width: "100%", maxWidth: 320 }}
          />
          <p className="uitest-field__label" style={{ marginTop: 12 }}>
            Live value: {value}
          </p>
        </PreviewCanvas>
      </DocSection>

      <DocSection
        title="Variants"
        description="Brand and info color treatments."
      >
        <VariantGrid columns={2}>
          <VariantTile label="brand">
            <FilledRangeSlider
              min={0}
              max={100}
              value={65}
              onChange={() => {}}
              variant="brand"
              style={{ width: "100%" }}
            />
          </VariantTile>
          <VariantTile label="info">
            <FilledRangeSlider
              min={0}
              max={100}
              value={65}
              onChange={() => {}}
              variant="info"
              style={{ width: "100%" }}
            />
          </VariantTile>
        </VariantGrid>
      </DocSection>

      <DocSection
        title="Sizes"
        description="Medium and small track heights."
      >
        <VariantGrid columns={2}>
          <VariantTile label="md">
            <FilledRangeSlider
              min={0}
              max={100}
              value={40}
              onChange={() => {}}
              size="md"
              style={{ width: "100%" }}
            />
          </VariantTile>
          <VariantTile label="sm">
            <FilledRangeSlider
              min={0}
              max={100}
              value={40}
              onChange={() => {}}
              size="sm"
              style={{ width: "100%" }}
            />
          </VariantTile>
        </VariantGrid>
      </DocSection>
    </ComponentDocPage>
  );
}
