function strategyToSector(strategy: string): string {
  const normalized = strategy.toLowerCase();
  if (normalized.includes("yield") || normalized.includes("carry")) return "Yield";
  if (normalized.includes("arb") || normalized.includes("spread")) return "Arbitrage";
  return "Trading";
}

function slugify(name: string): string {
  return name.toLowerCase().replace(/\s+/g, "-");
}

function buildSparkline(seed: string): number[] {
  const hash = mockHashId(seed);
  return Array.from({ length: 7 }, (_, index) => {
    const part = Number.parseInt(hash.slice(index * 3, index * 3 + 3), 16);
    return 45 + (part % 40);
  });
}

function buildExtendedCatalogSeed(index: number): CatalogAgentSeedInput {
  const descriptor = DESCRIPTORS[index]!;
  const animal = ANIMALS[index]!;
  const name = `${descriptor}${animal}`;
  const id = `ext-${slugify(`${descriptor}-${animal}`)}`;
  const seedKey = `extended-agent-token:${id}`;
  const strategy = STRATEGIES[index % STRATEGIES.length]!;

  const tickerSuffix = mockHashId(`${seedKey}:ticker`).slice(0, 4).toUpperCase();
  const ticker = `$${tickerSuffix}`;

  return {
    id,
    name,
    ticker,
    sector: strategyToSector(strategy),
    strategy,
    avatar: EXTENDED_AVATARS[index] ?? "🤖",
    sparkline: buildSparkline(seedKey),
    strategySummary: `${strategy} agent executing ${sectorToSummary(strategy)} on liquid perp markets.`,
    policyBadge: index % 5 === 0 ? "Risk-sim ✓" : undefined,
    walletProofAge: `${2 + (Number.parseInt(mockHashId(seedKey).slice(28, 30), 16) % 16)}m ago`,
  };
}

function sectorToSummary(strategy: string): string {
  const normalized = strategy.toLowerCase();
  if (normalized.includes("arb")) return "cross-venue dislocations";
  if (normalized.includes("yield") || normalized.includes("carry")) return "funding-positive carry";
  if (normalized.includes("grid")) return "range-bound micro-edges";
  if (normalized.includes("macro")) return "regime-shift signals";
  if (normalized.includes("volatility")) return "volatility regime shifts";
  if (normalized.includes("meme")) return "social momentum bursts";
  return "short-horizon signal models";
}

export const EXTENDED_CATALOG_AGENT_SEEDS: CatalogAgentSeedInput[] = Array.from(
  { length: EXTENDED_CATALOG_AGENT_COUNT },
  (_, index) => buildExtendedCatalogSeed(index),
);

function enrichCatalogSeedWithDid(seed: CatalogAgentSeedInput): CatalogAgentSeed {
  const did = mockCatalogAgentDid(seed.id);
  registerCatalogAgentIdentity(seed.id, did);
  return { ...seed, did };
}

export const ALL_CATALOG_AGENT_SEEDS: CatalogAgentSeed[] = [
  ...CORE_CATALOG_AGENT_SEEDS,
  ...EXTENDED_CATALOG_AGENT_SEEDS,
]
  .sort((a, b) => a.id.localeCompare(b.id))
  .map((seed) => enrichCatalogSeedWithDid(seed));

export const CORE_CATALOG_AGENT_IDS = CORE_CATALOG_AGENT_SEEDS.map((seed) => seed.id);
export const EXTENDED_CATALOG_AGENT_IDS = EXTENDED_CATALOG_AGENT_SEEDS.map((seed) => seed.id);

const catalogSeedById = new Map(
  ALL_CATALOG_AGENT_SEEDS.map((seed) => [seed.id.toLowerCase(), seed]),
);
const catalogSeedByDid = new Map(
  ALL_CATALOG_AGENT_SEEDS.map((seed) => [seed.did, seed]),
);

export function getCatalogSeedById(id: string): CatalogAgentSeed | undefined {
  return catalogSeedById.get(id.trim().toLowerCase());
}

export function getCatalogSeedByDid(did: string): CatalogAgentSeed | undefined {
  return catalogSeedByDid.get(did.trim());
}

export function parseCatalogAumM(aum: string): number {
  const match = aum.match(/\$?\s*([\d.]+)\s*([MmKk])?/);
  if (!match) return 1;
  let value = Number.parseFloat(match[1]!);
  const unit = match[2]?.toUpperCase();
  if (unit === "K") value /= 1000;
  if (unit === "M") return value;
  return value;
}

export type FleetCatalogSeedMinimal = {
  seedKey: string;
  did: string;
  strategy: string;
  winRatePct: number;
  aumM: number;
};

export function catalogSeedToFleetMinimal(
  seed: CatalogAgentSeed,
  winRatePct: number,
  aumM: number,
): FleetCatalogSeedMinimal {
  return {
    seedKey: seed.id,
    did: seed.did,
    strategy: seed.strategy,
    winRatePct,
    aumM,
  };
}
