import { useMemo, useState } from "react";

import { StackTransition } from "@mormlayer/components/ui/StackTransition";
import type { StackTransitionAxis } from "@mormlayer/components/ui/StackTransition";

import { ComponentDocPage } from "../layout/ComponentDocPage";
import { DocSection } from "../layout/DocSection";
import { PreviewCanvas } from "../layout/PreviewCanvas";
import { VariantGrid, VariantTile } from "../layout/VariantGrid";

type StackKey = "overview" | "details" | "settings";

const STACK_LABELS: Record<StackKey, string> = {
  overview: "Overview",
  details: "Details",
  settings: "Settings",
};

const STACK_KEYS: StackKey[] = ["overview", "details", "settings"];

function StackPanel({
  label,
  tone,
}: {
  label: string;
  tone: string;
}): JSX.Element {
  return (
    <div
      style={{
        padding: "var(--terminal-space-5)",
        background: tone,
        border: "1px solid var(--terminal-border-strong)",
        borderRadius: "var(--terminal-radius-sm)",
        minHeight: 120,
      }}
    >
      <h4 className="terminal-panel-title" style={{ margin: 0 }}>
        {label}
      </h4>
      <p className="terminal-label" style={{ marginTop: 8, marginBottom: 0 }}>
        Slide transition panel content.
      </p>
    </div>
  );
}

function buildStacks(): Record<StackKey, JSX.Element> {
  return {
    overview: <StackPanel label="Overview" tone="var(--terminal-panel)" />,
    details: <StackPanel label="Details" tone="var(--terminal-panel-strong)" />,
    settings: <StackPanel label="Settings" tone="var(--terminal-panel-soft)" />,
  };
}

export function StackTransitionPage(): JSX.Element {
  const [focusKey, setFocusKey] = useState<StackKey>("overview");
  const [axis, setAxis] = useState<StackTransitionAxis>("vertical");
  const [animate, setAnimate] = useState(true);

  const stacks = useMemo(() => buildStacks(), []);

  return (
    <ComponentDocPage
      title="Stack transition"
      description="Animated stack switcher for modal and menubar surfaces. Panels slide vertically or horizontally when focusKey changes."
    >
      <DocSection
        title="Default preview"
        description="Vertical slide between three stack panels."
      >
        <PreviewCanvas minHeight={180}>
          <div style={{ maxWidth: 360, width: "100%", height: 140 }}>
            <StackTransition focusKey="overview" stacks={stacks} axis="vertical" />
          </div>
        </PreviewCanvas>
      </DocSection>

      <DocSection
        title="Customization"
        description="Switch focusKey, axis, and animation — remount when animation is off to skip transitions."
      >
        <div className="uitest-controls">
          <div className="uitest-field">
            <span className="uitest-field__label">Focus key</span>
            <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
              {STACK_KEYS.map((key) => (
                <button
                  key={key}
                  type="button"
                  className="uitest-input"
                  aria-pressed={focusKey === key}
                  onClick={() => setFocusKey(key)}
                >
                  {STACK_LABELS[key]}
                </button>
              ))}
            </div>
          </div>
          <label className="uitest-field">
            <span className="uitest-field__label">Axis</span>
            <select
              className="uitest-input"
              value={axis}
              onChange={(e) => setAxis(e.target.value as StackTransitionAxis)}
            >
              <option value="vertical">vertical</option>
              <option value="horizontal">horizontal</option>
            </select>
          </label>
          <label className="uitest-field uitest-field--checkbox">
            <input
              type="checkbox"
              checked={animate}
              onChange={(e) => setAnimate(e.target.checked)}
            />
            <span className="uitest-field__label">Show slide animation</span>
          </label>
        </div>
        <PreviewCanvas minHeight={180}>
          <div style={{ maxWidth: 360, width: "100%", height: 140 }}>
            {animate ? (
              <StackTransition focusKey={focusKey} stacks={stacks} axis={axis} />
            ) : (
              stacks[focusKey]
            )}
          </div>
          <p className="uitest-field__label" style={{ marginTop: 12 }}>
            Active stack: {STACK_LABELS[focusKey]}
          </p>
        </PreviewCanvas>
      </DocSection>

      <DocSection
        title="Axis variants"
        description="Vertical and horizontal slide directions."
      >
        <VariantGrid columns={2}>
          <VariantTile label="vertical">
            <div style={{ width: "100%", height: 120 }}>
              <StackTransition
                focusKey="details"
                stacks={stacks}
                axis="vertical"
              />
            </div>
          </VariantTile>
          <VariantTile label="horizontal">
            <div style={{ width: "100%", height: 120 }}>
              <StackTransition
                focusKey="settings"
                stacks={stacks}
                axis="horizontal"
              />
            </div>
          </VariantTile>
        </VariantGrid>
      </DocSection>
    </ComponentDocPage>
  );
}
