import {
  ALL_CATALOG_AGENT_SEEDS,
  type CatalogAgentSeed,
} from "./agentCatalogSeeds";
import {
  agentDidToRouteParam,
  resolveAgentDid,
  resolveCatalogSeedKey,
} from "./agentIdentity";
import { getAgentKpiSummaryByAgentDid } from "./agentKpiLookup";
import type { AgentKpiSummary } from "./agentKpiHistory.types";
import { getFleetDeployerForAgentDid } from "./fleetCatalog";
import type { PropertyProfile } from "./types";

export function parsePerpBaseAsset(ticker: string): string {
  return ticker.replace(/^\$/, "").toUpperCase();
}

export function getAgentProfileByPerpBaseAsset(
  baseAsset: string,
): PropertyProfile | undefined {
  const normalized = baseAsset.toUpperCase();
  return mockAgentProfiles.find(
    (profile) => profile.perpBaseAsset.toUpperCase() === normalized,
  );
}

export function getAgentProfileByDid(did: string): PropertyProfile | undefined {
  const resolved = resolveAgentDid(did);
  if (!resolved) return undefined;
  return mockAgentProfiles.find((profile) => profile.did === resolved);
}

/** Resolve by DID, storage route key, or legacy catalog seed key. */
export function getAgentProfileById(id: string): PropertyProfile | undefined {
  const byDid = getAgentProfileByDid(id);
  if (byDid) return byDid;

  const seedKey = resolveCatalogSeedKey(id);
  if (!seedKey) return undefined;
  return mockAgentProfiles.find(
    (profile) => profile.seedKey.toLowerCase() === seedKey,
  );
}

function formatRevenueUsd(usd: number): string {
  return `$${(usd / 1000).toFixed(1)}k`;
}

function formatMarketCapLabel(usd: number): string {
  if (usd >= 1_000_000_000) return `$${(usd / 1_000_000_000).toFixed(1)}B`;
  if (usd >= 1_000_000) return `$${(usd / 1_000_000).toFixed(1)}M`;
  return `$${Math.round(usd / 1000)}k`;
}

function formatVolumeLabel(numeric: number): string {
  if (numeric >= 1_000_000_000) return `$${(numeric / 1_000_000_000).toFixed(1)}B`;
  if (numeric >= 1_000_000) return `$${(numeric / 1_000_000).toFixed(1)}M`;
  return `$${Math.round(numeric / 1000)}k`;
}

function formatAumLabel(usd: number): string {
  return `$${(usd / 1_000_000).toFixed(1)}M`;
}

function formatNetExposure(netExposureX: number): string {
  const sign = netExposureX >= 0 ? "+" : "";
  return `${sign}${netExposureX.toFixed(1)}x long`;
}

function formatPnlUsd(usd: number): string {
  const sign = usd >= 0 ? "+" : "";
  const absK = Math.abs(usd) / 1000;
  return `${sign}$${absK.toFixed(1)}k`;
}

function makeAgentProfile(seed: CatalogAgentSeed, summary: AgentKpiSummary): PropertyProfile {
  const perpBaseAsset = parsePerpBaseAsset(seed.ticker);
  const policyBadge = seed.policyBadge ?? "Loss-cap ✓";
  const walletProofAge = seed.walletProofAge ?? "8m ago";
  const pnlTone = summary.pnl30dUsd >= 0 ? "positive" : "negative";

  return {
    did: seed.did,
    seedKey: seed.id,
    id: agentDidToRouteParam(seed.did),
    name: seed.name,
    ticker: seed.ticker,
    perpBaseAsset,
    leverage: summary.leverage ?? seed.leverage ?? 20,
    annFunding: summary.annFundingPct,
    openInterest: summary.openInterestUsd,
    volume24hNumeric: summary.volume24hUsd,
    deployer: getFleetDeployerForAgentDid(seed.did),
    verifiedLabel: "DID Verified",
    avatar: seed.avatar,
    price: summary.price,
    change24h: summary.change24h,
    volume24h: formatVolumeLabel(summary.volume24hUsd),
    marketCap: formatMarketCapLabel(summary.marketCapUsd),
    strategy: seed.strategy,
    riskScore: `${summary.riskLabel} · ${summary.riskScoreSuffix}`,
    sector: seed.sector,
    product: "Perp",
    sparkline: seed.sparkline,
    badges: ["Wallet ✓", "Mandate ✓", "KYT ✓", policyBadge, "Receipts ✓"],
    stats: [
      { label: "30d PnL", value: formatPnlUsd(summary.pnl30dUsd), tone: pnlTone },
      {
        label: "All-time PnL",
        value: formatPnlUsd(summary.pnlAllTimeUsd),
        tone: summary.pnlAllTimeUsd >= 0 ? "positive" : "negative",
      },
      { label: "Sharpe", value: summary.sharpe30d.toFixed(1), tone: "positive" },
      { label: "Max DD", value: `-${summary.maxDdPct}%`, tone: "negative" },
      { label: "Win rate", value: `${summary.winRatePct}%`, tone: "neutral" },
      { label: "AUM", value: formatAumLabel(summary.aumUsd), tone: "neutral" },
      {
        label: "Net exposure",
        value: formatNetExposure(summary.netExposureX),
        tone: "neutral",
      },
    ],
    quickStats: [
      { label: "Market cap", value: formatMarketCapLabel(summary.marketCapUsd) },
      { label: "30d revenue", value: formatRevenueUsd(summary.revenue30dUsd) },
      { label: "Risk", value: summary.riskLabel },
      { label: "Strategy", value: seed.strategy },
      {
        label: "Net exposure",
        value: formatNetExposure(summary.netExposureX),
      },
    ],
    riskInputs: [
      `Drawdown: controlled at -${summary.maxDdPct}%`,
      `Revenue stability: ${summary.revenueStability.toFixed(2)} coefficient`,
      `Mandate caps: ${summary.mandateCap ?? seed.mandateCap ?? "1.5x gross cap"}`,
      `Time-live: ${summary.timeLivePct}% of target window`,
    ],
    receipts: [
      `Wallet proof signed ${walletProofAge}`,
      "KYT clearance received",
      `${policyBadge.replace(" ✓", "")} policy active`,
    ],
    strategySummary: seed.strategySummary,
    links: [`X / ${seed.name.replace(/\s+/g, "")}`, "Website", "MAEX profile"],
  };
}

export const mockAgentProfiles: PropertyProfile[] = ALL_CATALOG_AGENT_SEEDS.map(
  (seed) => makeAgentProfile(seed, getAgentKpiSummaryByAgentDid(seed.did)),
);

export const mockAgentProfile = mockAgentProfiles[0];

export const AGENT_PERP_BASE_ASSETS = mockAgentProfiles.map(
  (profile) => profile.perpBaseAsset,
);
