import React, { type JSX } from "react";
import { Responsive, WidthProvider } from "react-grid-layout/legacy";
import type { Layout, ResponsiveLayouts } from "react-grid-layout";
import "react-grid-layout/css/styles.css";
import "react-resizable/css/styles.css";
import "./grid-editor.css";
import {
  generateLayout,
  generateResponsiveLayouts,
  getLayoutForBreakpoint,
  layoutsEqual,
  updateLayoutsWithStatic,
} from "./util";
import {
  defaultPredefinedLayouts,
  designatedResponsiveLayouts,
  EXTERNAL_SLOT_START,
  EXTERNAL_SLOT_END,
  MOBILE_BREAKPOINTS,
  MOBILE_HIDDEN_SLOTS,
} from "../../configs/terminalLayoutConfig";
import type { GridViewerLayoutProps, GridViewerLayoutState } from "./type";
const ResponsiveReactGridLayout = WidthProvider(Responsive);

function isSlotVisibleForBreakpoint(
  breakpoint: string,
  slotIndex: number,
  mobileHiddenSlots: readonly number[],
): boolean {
  if ((MOBILE_BREAKPOINTS as readonly string[]).includes(breakpoint)) {
    return !mobileHiddenSlots.includes(slotIndex);
  }
  return true;
}

function resolveInitialLayouts(
  props: GridViewerLayoutProps,
): ResponsiveLayouts {
  if (props.initialLayouts) {
    return props.initialLayouts;
  }
  const lg =
    props.initialLayout || generateLayout(defaultPredefinedLayouts, 0);
  return { lg };
}

export default class GridViewerLayout extends React.Component<
  GridViewerLayoutProps,
  GridViewerLayoutState
> {
  static defaultProps: Partial<GridViewerLayoutProps> = {
    className: "layout",
    rowHeight: 30,
    onLayoutChange: function () {},
    cols: { lg: 12, md: 10, sm: 6, xs: 4, xxs: 2 },
    initialLayout: generateLayout(defaultPredefinedLayouts, 0),
  };

  private isUpdatingLayout = false;
  private domCache: React.ReactNode[] | null = null;
  private lastLayoutKey: string = "";
  private lastSlotContentRef: React.ReactNode[] | undefined = undefined;

  constructor(props: GridViewerLayoutProps) {
    super(props);
    this.state = {
      currentBreakpoint: "lg",
      compactType: props.compactType ?? "vertical",
      mounted: false,
      layouts: resolveInitialLayouts(props),
      allStatic: props.allStatic ?? true,
    };

    this.onBreakpointChange = this.onBreakpointChange.bind(this);
    this.onCompactTypeChange = this.onCompactTypeChange.bind(this);
    this.onLayoutChange = this.onLayoutChange.bind(this);
    this.onNewLayout = this.onNewLayout.bind(this);
    this.onToggleStatic = this.onToggleStatic.bind(this);
  }

  componentDidMount() {
    this.setState({ mounted: true }, () => {
      // Notify parent that layout is mounted and ready
      if (this.props.onMount) {
        this.props.onMount();
      }
    });
  }

  generateDOM() {
    const { currentBreakpoint } = this.state;
    const layout = getLayoutForBreakpoint(
      this.state.layouts,
      currentBreakpoint,
    );
    const { slotContent = [] } = this.props;
    const allStatic = this.props.allStatic ?? this.state.allStatic;

    const slotContentKey = slotContent.map((slot) => (slot ? "1" : "0")).join("");

    if (this.props.slotContent !== this.lastSlotContentRef) {
      this.domCache = null;
      this.lastLayoutKey = "";
      this.lastSlotContentRef = this.props.slotContent;
    }

    // Create a cache key based on layout and props
    const layoutKey = `${currentBreakpoint}-${layout.length}-${allStatic}-${slotContentKey}`;

    // Check if we can reuse cached DOM
    if (this.domCache && this.lastLayoutKey === layoutKey) {
      return this.domCache;
    }

    const result: React.ReactNode[] = [];
    for (let i = 0; i < layout.length; i++) {
      const l = layout[i];
      // Check if this is an external component slot (1-5)
      const isExternalSlot = i >= EXTERNAL_SLOT_START && i <= EXTERNAL_SLOT_END;
      const slotContentIndex = i - EXTERNAL_SLOT_START; // Convert slot index to array index
      const externalContent =
        isExternalSlot && slotContent[slotContentIndex]
          ? slotContent[slotContentIndex]
          : null;
      const isEditing = !allStatic;
      const mobileHiddenSlots =
        this.props.mobileHiddenSlots ?? MOBILE_HIDDEN_SLOTS;
      const slotVisible = isSlotVisibleForBreakpoint(
        currentBreakpoint,
        i,
        mobileHiddenSlots,
      );
      const isCollapsed = (l.w ?? 0) === 0 && (l.h ?? 0) === 0;
      const hasContent = Boolean(externalContent);
      const shouldHide =
        isCollapsed ||
        (!slotVisible && !isEditing) ||
        (!isEditing && !hasContent);
      const wrapperClass = shouldHide ? "grid-slot--hidden" : undefined;

      result.push(
        <div key={l.i || i.toString()} className={wrapperClass}>
          {externalContent ? (
            <div
              className={
                isEditing
                  ? "external-slot-content external-slot-content--hidden"
                  : "external-slot-content"
              }
            >
              {externalContent}
            </div>
          ) : null}
          {isEditing ? (
            <span className="grid-slot-label">{i}</span>
          ) : null}
        </div>,
      );
    }

    // Cache the result
    this.domCache = result;
    this.lastLayoutKey = layoutKey;
    return result;
  }

  onBreakpointChange(breakpoint: string) {
    this.domCache = null;
    this.lastLayoutKey = "";
    this.setState({
      currentBreakpoint: breakpoint,
    });
    this.props.onBreakpointChange?.(breakpoint);
  }

  onCompactTypeChange() {
    if (this.props.onCompactTypeChange) {
      // Controlled: let parent handle the change
      this.props.onCompactTypeChange();
    } else {
      // Uncontrolled: handle internally
      const { compactType: oldCompactType } = this.state;
      const compactType =
        oldCompactType === "horizontal"
          ? "vertical"
          : oldCompactType === "vertical"
            ? null
            : "horizontal";
      this.setState({ compactType });
    }
  }

  onLayoutChange(layout: Layout[], layouts: ResponsiveLayouts) {
    // Prevent recursive calls - if we're already updating, just call parent callback
    if (this.isUpdatingLayout) {
      this.props.onLayoutChange(layout, layouts);
      return;
    }

    // Preserve static state based on allStatic when layouts change
    const allStatic = this.props.allStatic ?? this.state.allStatic;

    // Conditional detection: Only process layout changes when NOT in static mode
    // This prevents unnecessary updates and infinite loops in static mode
    if (allStatic) {
      // In static mode, just call parent callback without processing
      // This prevents the infinite loop while still allowing parent to track changes if needed
      this.props.onLayoutChange(layout, layouts);
      return;
    }

    // Create updated layouts with static property
    const updatedLayouts = updateLayoutsWithStatic(layouts, allStatic);

    // Check if layouts actually changed using efficient comparison
    const layoutsChanged = !layoutsEqual(this.state.layouts, updatedLayouts);

    // Only update state if layouts actually changed (positions/sizes, not just static property)
    if (layoutsChanged) {
      // Invalidate DOM cache when layout changes
      this.domCache = null;
      this.lastLayoutKey = "";

      this.isUpdatingLayout = true;
      this.setState({ layouts: updatedLayouts }, () => {
        this.isUpdatingLayout = false;
      });
    }

    // Always call parent's onLayoutChange with the layout array
    this.props.onLayoutChange(layout, updatedLayouts);
  }

  // Adapter for ResponsiveReactGridLayout's onLayoutChange signature
  // Note: ResponsiveReactGridLayout actually passes Layout[] but types expect Layout
  handleResponsiveLayoutChange = (
    layout: Layout[] | Layout,
    layouts: ResponsiveLayouts | Partial<Record<string, Layout>>,
  ) => {
    // ResponsiveReactGridLayout actually passes an array, but types are incorrect
    const layoutArray = Array.isArray(layout) ? layout : [layout];
    const responsiveLayouts = layouts as ResponsiveLayouts;
    this.onLayoutChange(layoutArray, responsiveLayouts);
  };

  onNewLayout() {
    if (this.props.onNewLayout) {
      // Controlled: let parent handle the change
      this.props.onNewLayout();
    } else {
      // Uncontrolled: handle internally
      this.generateNewLayout();
    }
  }

  /**
   * Public method to apply responsive layouts at runtime (e.g. mobile ticker expand).
   */
  applyLayouts = (layouts: ResponsiveLayouts) => {
    const allStatic = this.props.allStatic ?? this.state.allStatic;
    const updatedLayouts = updateLayoutsWithStatic(layouts, allStatic);

    this.domCache = null;
    this.lastLayoutKey = "";

    this.setState({ layouts: updatedLayouts });
  };

  /**
   * Public method to generate a new layout. Can be called via ref.
   */
  generateNewLayout = () => {
    const newLayouts = generateResponsiveLayouts(
      designatedResponsiveLayouts,
      0,
    );
    const allStatic = this.props.allStatic ?? this.state.allStatic;
    const updatedLayouts = updateLayoutsWithStatic(newLayouts, allStatic);

    this.domCache = null;
    this.lastLayoutKey = "";

    this.setState({
      layouts: updatedLayouts,
    });
  };

  onToggleStatic() {
    if (this.props.onToggleStatic) {
      // Controlled: let parent handle the change
      this.props.onToggleStatic();
    } else {
      // Uncontrolled: handle internally
      const newStaticState = !this.state.allStatic;

      // Update all breakpoints with the new static state
      const updatedLayouts = updateLayoutsWithStatic(
        this.state.layouts,
        newStaticState,
      );

      // Invalidate DOM cache
      this.domCache = null;
      this.lastLayoutKey = "";

      this.setState({
        allStatic: newStaticState,
        layouts: updatedLayouts,
      });
    }
  }

  componentDidUpdate(prevProps: GridViewerLayoutProps) {
    // Sync controlled props to state
    if (
      prevProps.compactType !== this.props.compactType &&
      this.props.compactType !== undefined
    ) {
      this.setState({ compactType: this.props.compactType });
    }
    if (
      prevProps.allStatic !== this.props.allStatic &&
      this.props.allStatic !== undefined
    ) {
      // Update layouts when allStatic changes
      const updatedLayouts = updateLayoutsWithStatic(
        this.state.layouts,
        this.props.allStatic,
      );

      // Invalidate DOM cache
      this.domCache = null;
      this.lastLayoutKey = "";

      this.setState({
        allStatic: this.props.allStatic,
        layouts: updatedLayouts,
      });
    }

    // Invalidate cache if slotContent changes
    if (prevProps.slotContent !== this.props.slotContent) {
      this.domCache = null;
      this.lastLayoutKey = "";
    }

    if (
      prevProps.initialLayouts !== this.props.initialLayouts &&
      this.props.initialLayouts
    ) {
      const updatedLayouts = updateLayoutsWithStatic(
        this.props.initialLayouts,
        this.props.allStatic ?? this.state.allStatic,
      );
      this.domCache = null;
      this.lastLayoutKey = "";
      this.setState({ layouts: updatedLayouts });
    }
  }

  render() {
    // Use controlled props if provided, otherwise use state
    const compactType = this.props.compactType ?? this.state.compactType;
    return (
      <div>
        <ResponsiveReactGridLayout
          {...this.props}
          layouts={this.state.layouts}
          onBreakpointChange={this.onBreakpointChange}
          onLayoutChange={this.handleResponsiveLayoutChange as any}
          // WidthProvider option
          measureBeforeMount={false}
          // I like to have it animate on mount. If you don't, delete `useCSSTransforms` (it's default `true`)
          // and set `measureBeforeMount={true}`.
          useCSSTransforms={this.state.mounted}
          compactType={compactType}
          preventCollision={!compactType}
        >
          {this.generateDOM()}
        </ResponsiveReactGridLayout>
      </div>
    );
  }
}
