/** Force layout on closed overlay panels so enter transitions run (Firefox cold mount). */
export function flushPendingOverlayPanelStyles(): void {
  if (typeof document === "undefined") return;

  document
    .querySelectorAll<HTMLElement>(".staggered-overlay-panel:not(.is-open)")
    .forEach((panel) => {
      void panel.offsetHeight;
    });
}

/** After closed panel is painted, flush styles then signal open on the next frame. */
export function scheduleOverlayPanelOpen(onOpen: () => void): () => void {
  let cancelled = false;
  let outerFrame = 0;
  let innerFrame = 0;

  outerFrame = requestAnimationFrame(() => {
    flushPendingOverlayPanelStyles();
    innerFrame = requestAnimationFrame(() => {
      if (!cancelled) onOpen();
    });
  });

  return () => {
    cancelled = true;
    cancelAnimationFrame(outerFrame);
    cancelAnimationFrame(innerFrame);
  };
}
