/** Per-bucket / layout autonomy threshold presets for report-tier routing. */

export type AutonomyPreset = "manual" | "guarded" | "highAgency";

export type AutonomyPresetCardTone = "manual" | "guarded" | "high";

export const AUTONOMY_PRESET_TONE: Record<AutonomyPreset, AutonomyPresetCardTone> = {
  manual: "manual",
  guarded: "guarded",
  highAgency: "high",
};

export interface AutonomyPolicy {
  preset: AutonomyPreset;
  /** Confidence at or above → T0 when risk is low and intent is gateable. */
  silentMinConfidence: number;
  /** Below this on a gateable intent → T3 (or T4 on breach). */
  gateMinConfidence: number;
  /** T3 approval deadline length (minutes). */
  t3ApproveByMinutes: number;
}

export const MANUAL_AUTONOMY: AutonomyPolicy = {
  preset: "manual",
  silentMinConfidence: 95,
  gateMinConfidence: 95,
  t3ApproveByMinutes: 10,
};

export const HIGH_AGENCY_AUTONOMY: AutonomyPolicy = {
  preset: "highAgency",
  silentMinConfidence: 72,
  gateMinConfidence: 55,
  t3ApproveByMinutes: 3,
};

export const GUARDED_AUTONOMY: AutonomyPolicy = {
  preset: "guarded",
  silentMinConfidence: 85,
  gateMinConfidence: 70,
  t3ApproveByMinutes: 5,
};

export function autonomyPolicyForTradingMode(
  mode: "proTerminal" | "highAgency" | "humanInLoop",
): AutonomyPolicy {
  if (mode === "humanInLoop") return GUARDED_AUTONOMY;
  if (mode === "highAgency") return HIGH_AGENCY_AUTONOMY;
  return HIGH_AGENCY_AUTONOMY;
}

export function autonomyPolicyForPreset(preset: AutonomyPreset): AutonomyPolicy {
  if (preset === "manual") return { ...MANUAL_AUTONOMY };
  if (preset === "guarded") return { ...GUARDED_AUTONOMY };
  return { ...HIGH_AGENCY_AUTONOMY };
}

export function autonomyLevelRank(preset: AutonomyPreset): number {
  switch (preset) {
    case "manual":
      return 0;
    case "guarded":
      return 1;
    case "highAgency":
      return 2;
  }
}

/** True when moving toward more autonomous execution (preset rank or looser sliders). */
export function isRaisingAutonomy(
  before: AutonomyPolicy,
  after: AutonomyPolicy,
): boolean {
  const rankBefore = autonomyLevelRank(before.preset);
  const rankAfter = autonomyLevelRank(after.preset);
  if (rankAfter > rankBefore) return true;
  if (rankAfter < rankBefore) return false;
  if (after.preset === "manual") return false;
  if (after.silentMinConfidence < before.silentMinConfidence) return true;
  if (after.gateMinConfidence < before.gateMinConfidence) return true;
  return false;
}

export type AutonomyBadgeTone = "manual" | "guarded" | "highAgency";

export interface AutonomyBadgeCopy {
  tone: AutonomyBadgeTone;
  icon: string;
  headline: string;
  subline: string;
}

export function autonomyBadgeCopy(policy: AutonomyPolicy): AutonomyBadgeCopy {
  if (policy.preset === "manual") {
    return {
      tone: "manual",
      icon: "●",
      headline: "Manual — agents off",
      subline: "No agent will trade this bucket without you",
    };
  }
  if (policy.preset === "guarded") {
    return {
      tone: "guarded",
      icon: "◐",
      headline: "Guarded — agents ask first",
      subline: "Agents propose; risky moves wait for your approval",
    };
  }
  return {
    tone: "highAgency",
    icon: "⚡",
    headline: "High-Agency — hands-off",
    subline: "Agents can trade without asking",
  };
}

export function cloneAutonomyPolicy(policy: AutonomyPolicy): AutonomyPolicy {
  return { ...policy };
}

export function policiesEqual(a: AutonomyPolicy, b: AutonomyPolicy): boolean {
  return (
    a.preset === b.preset &&
    a.silentMinConfidence === b.silentMinConfidence &&
    a.gateMinConfidence === b.gateMinConfidence &&
    a.t3ApproveByMinutes === b.t3ApproveByMinutes
  );
}

export function isCustomAutonomyPolicy(policy: AutonomyPolicy): boolean {
  const presetDefaults = autonomyPolicyForPreset(policy.preset);
  return !policiesEqual(policy, presetDefaults);
}

export type AutonomyPolicyLabel = "Manual" | "High" | "Guarded" | "Custom";

export function autonomyPolicyLabel(policy: AutonomyPolicy): AutonomyPolicyLabel {
  if (policy.preset === "manual") return "Manual";
  if (isCustomAutonomyPolicy(policy)) return "Custom";
  return policy.preset === "guarded" ? "Guarded" : "High";
}

/** Demo seed: default Manual for new buckets (safe by default). */
export const SEED_BUCKET_AUTONOMY_POLICIES: readonly AutonomyPolicy[] = [
  MANUAL_AUTONOMY,
  MANUAL_AUTONOMY,
  GUARDED_AUTONOMY,
  MANUAL_AUTONOMY,
  HIGH_AGENCY_AUTONOMY,
  MANUAL_AUTONOMY,
  GUARDED_AUTONOMY,
  MANUAL_AUTONOMY,
  MANUAL_AUTONOMY,
  MANUAL_AUTONOMY,
];

export function seedAutonomyPolicyForBucketIndex(index: number): AutonomyPolicy {
  const seed =
    SEED_BUCKET_AUTONOMY_POLICIES[
      ((index % SEED_BUCKET_AUTONOMY_POLICIES.length) +
        SEED_BUCKET_AUTONOMY_POLICIES.length) %
        SEED_BUCKET_AUTONOMY_POLICIES.length
    ]!;
  return cloneAutonomyPolicy(seed);
}

export function clampAutonomyThreshold(value: number, min = 40, max = 95): number {
  return Math.min(max, Math.max(min, Math.round(value)));
}

export function validateAutonomyPolicy(policy: AutonomyPolicy): string | null {
  if (policy.preset === "manual") return null;
  if (policy.gateMinConfidence >= policy.silentMinConfidence) {
    return "Gate threshold must be below the silent band.";
  }
  if (policy.t3ApproveByMinutes < 1 || policy.t3ApproveByMinutes > 30) {
    return "Approve-by window must be between 1 and 30 minutes.";
  }
  return null;
}
