export function cloneMockOrders(): MockOrder[] {
  return mockOrders.map((order) => ({
    ...order,
    childOrders: order.childOrders?.map((leg) => ({ ...leg })),
  }));
}

/** Parent-order agent vs manual counts for demo validation. */
export const MOCK_OPEN_ORDER_ATTRIBUTION = {
  total: mockOrders.length,
  agent: mockOrders.filter((o) => o.agentTaskId).length,
  manual: mockOrders.filter((o) => !o.agentTaskId).length,
} as const;
