/** Normalized status (after ORDER_STATUS_ prefix removed) -> display config + pending flag */
export const ORDER_STATUS_CONFIG = {
  PENDING: { isPending: true, short: "P", full: "Pending", color: "#ffc107" },
  OPEN: { isPending: true, short: "O", full: "Open", color: "#17a2b8" },
  ACTIVE: { isPending: true, short: "A", full: "Active", color: "#17a2b8" },
  PARTIAL: { isPending: true, short: "PF", full: "Partially Filled", color: "#ffc107" },
  NEW: { isPending: true, short: "N", full: "New", color: "#ffc107" },
  PARTIALLY_FILLED: { isPending: true, short: "PF", full: "Partially Filled", color: "#ffc107" },
  FILLED: { isPending: false, short: "F", full: "Filled", color: "#28a745" },
  CANCELLED: { isPending: false, short: "C", full: "Canceled", color: "#dc3545" },
  REJECTED: { isPending: false, short: "R", full: "Rejected", color: "#dc3545" },
} as const;

/** Derived: pending statuses for filtering (both normalized and ORDER_STATUS_ prefixed) */
export const ORDER_PENDING_STATUSES: readonly string[] = (
  Object.entries(ORDER_STATUS_CONFIG) as [
    keyof typeof ORDER_STATUS_CONFIG,
    (typeof ORDER_STATUS_CONFIG)[keyof typeof ORDER_STATUS_CONFIG],
  ][]
)
  .filter(([, cfg]) => cfg.isPending)
  .flatMap(([norm]) => [norm, `ORDER_STATUS_${norm}`]);

