import { useMemo } from "react";

import {
  calculateDecorativeCardScale,
  DECORATIVE_CARD_HEIGHT,
  DECORATIVE_CARD_WIDTH,
} from "../decorative-card/decorativeCardScale";
import {
  type DecorativeCardType,
  isGradientDiffusorType,
  isStripType,
  isVerticalStripType,
} from "../decorative-card/decorativeCardTypes";
import "../decorative-card/decorativeCardShell.css";
import {
  MastercardIcon,
  MastercardIconWhite,
  PaypassIcon,
} from "./credit-card-icons";
import "./credit-card.css";

const CARD_WITH_COLOR_LOGO = [
  "brand-dark",
  "brand-light",
  "gray-dark",
  "gray-light",
] as const;

export type CreditCardType = DecorativeCardType;

export interface CreditCardProps {
  company?: string;
  cardNumber?: string;
  cardHolder?: string;
  cardExpiration?: string;
  type?: CreditCardType;
  className?: string;
  width?: number;
}

export function CreditCard({
  company = "Untitled.",
  cardNumber = "1234 1234 1234 1234",
  cardHolder = "OLIVIA RHYE",
  cardExpiration = "06/28",
  type = "brand-dark",
  className,
  width,
}: CreditCardProps): JSX.Element {
  const { scale, scaledWidth, scaledHeight } = useMemo(
    () => calculateDecorativeCardScale(width),
    [width],
  );

  const shellClassName = [
    "decorative-card-shell",
    `decorative-card-shell--${type}`,
  ].join(" ");

  const hostClassName = ["decorative-card-host", className].filter(Boolean).join(" ");

  const useColorLogo = (CARD_WITH_COLOR_LOGO as readonly string[]).includes(type);

  return (
    <div
      className={hostClassName}
      style={{
        width: `${scaledWidth}px`,
        height: `${scaledHeight}px`,
      }}
    >
      <div
        className={shellClassName}
        style={{
          transform: `scale(${scale})`,
          width: `${DECORATIVE_CARD_WIDTH}px`,
          height: `${DECORATIVE_CARD_HEIGHT}px`,
        }}
      >
        {isStripType(type) ? (
          <div className="decorative-card-shell__strip-h" aria-hidden />
        ) : null}
        {isVerticalStripType(type) ? (
          <div className="decorative-card-shell__strip-v" aria-hidden />
        ) : null}
        {isGradientDiffusorType(type) ? (
          <div className="decorative-card-shell__gradient-diffusor" aria-hidden>
            <div />
            <div />
            <div />
            <div />
          </div>
        ) : null}

        <div className="credit-card__header">
          <div className="credit-card__company decorative-card-tone-light">
            {company}
          </div>
          <PaypassIcon className="credit-card__paypass decorative-card-tone-light" />
        </div>

        <div className="credit-card__footer">
          <div className="credit-card__details">
            <div className="credit-card__holder-row">
              <p className="credit-card__holder decorative-card-tone-light">
                {cardHolder}
              </p>
              <p className="credit-card__expiration decorative-card-tone-light">
                {cardExpiration}
              </p>
            </div>
            <div className="credit-card__number decorative-card-tone-light">
              {cardNumber}
              <span className="credit-card__number-placeholder">1</span>
            </div>
          </div>

          <div className="decorative-card-emblem-slot">
            {useColorLogo ? <MastercardIcon /> : <MastercardIconWhite />}
          </div>
        </div>
      </div>
    </div>
  );
}

export default CreditCard;
