import { useState } from "react";

import { MorpheumLoadingOverlay } from "@mormlayer/components/ui/MorpheumLoadingOverlay";
import type { MorpheumLoadingOverlayLayout } from "@mormlayer/components/ui/MorpheumLoadingOverlay";

import { ComponentDocPage } from "../layout/ComponentDocPage";
import { DocSection } from "../layout/DocSection";
import { PreviewCanvas } from "../layout/PreviewCanvas";
import { VariantGrid, VariantTile } from "../layout/VariantGrid";

const POSITIONED_CANVAS_STYLE = {
  position: "relative" as const,
  minHeight: 200,
  width: "100%",
};

const PLACEHOLDER_CONTENT = (
  <div style={{ padding: 16, opacity: 0.5, fontSize: 13 }}>
    <p style={{ margin: 0 }}>Background content behind the overlay</p>
    <p style={{ margin: "8px 0 0" }}>Charts, tables, or panel body render here.</p>
  </div>
);

export function LoadingOverlayPage(): JSX.Element {
  const [label, setLabel] = useState("Loading fleet data...");
  const [layout, setLayout] = useState<MorpheumLoadingOverlayLayout>("absolute");
  const [matrixText, setMatrixText] = useState(false);

  return (
    <ComponentDocPage
      title="Loading overlay"
      description="Full-area Morpheum loading overlay with animated logo. Supports absolute positioning within a container or fixed viewport layout."
    >
      <DocSection
        title="Absolute overlay"
        description="Overlay anchored to a relatively positioned preview canvas."
      >
        <PreviewCanvas minHeight={200}>
          <div style={POSITIONED_CANVAS_STYLE}>
            {PLACEHOLDER_CONTENT}
            <MorpheumLoadingOverlay label="Loading..." layout="absolute" />
          </div>
        </PreviewCanvas>
      </DocSection>

      <DocSection
        title="Customization"
        description="Edit label, layout, and matrix text. Absolute layout requires a positioned parent."
      >
        <div className="uitest-controls">
          <label className="uitest-field">
            <span className="uitest-field__label">Label</span>
            <input
              className="uitest-input"
              value={label}
              onChange={(e) => setLabel(e.target.value)}
            />
          </label>
          <label className="uitest-field">
            <span className="uitest-field__label">Layout</span>
            <select
              className="uitest-input"
              value={layout}
              onChange={(e) =>
                setLayout(e.target.value as MorpheumLoadingOverlayLayout)
              }
            >
              <option value="absolute">absolute</option>
              <option value="fixed">fixed</option>
            </select>
          </label>
          <label className="uitest-field uitest-field--checkbox">
            <input
              type="checkbox"
              checked={matrixText}
              onChange={(e) => setMatrixText(e.target.checked)}
            />
            <span className="uitest-field__label">Matrix text</span>
          </label>
        </div>
        <PreviewCanvas minHeight={layout === "fixed" ? 240 : 200}>
          {layout === "absolute" ? (
            <div style={POSITIONED_CANVAS_STYLE}>
              {PLACEHOLDER_CONTENT}
              <MorpheumLoadingOverlay
                label={label}
                layout="absolute"
                matrixText={matrixText}
              />
            </div>
          ) : (
            <>
              {PLACEHOLDER_CONTENT}
              <MorpheumLoadingOverlay
                label={label}
                layout="fixed"
                matrixText={matrixText}
              />
            </>
          )}
        </PreviewCanvas>
      </DocSection>

      <DocSection
        title="Layout variants"
        description="Absolute overlay inside a positioned container vs fixed viewport overlay."
      >
        <VariantGrid columns={2}>
          <VariantTile label="absolute">
            <div style={{ ...POSITIONED_CANVAS_STYLE, minHeight: 160 }}>
              {PLACEHOLDER_CONTENT}
              <MorpheumLoadingOverlay
                label="Loading panel..."
                layout="absolute"
              />
            </div>
          </VariantTile>
          <VariantTile label="fixed">
            <MorpheumLoadingOverlay
              label="Loading viewport..."
              layout="fixed"
            />
          </VariantTile>
        </VariantGrid>
      </DocSection>

      <DocSection
        title="Matrix text"
        description="Matrix scramble on vs static label."
      >
        <VariantGrid columns={2}>
          <VariantTile label="matrixText on">
            <div style={{ ...POSITIONED_CANVAS_STYLE, minHeight: 140 }}>
              <MorpheumLoadingOverlay
                label="Decrypting vault..."
                layout="absolute"
                matrixText
              />
            </div>
          </VariantTile>
          <VariantTile label="matrixText off">
            <div style={{ ...POSITIONED_CANVAS_STYLE, minHeight: 140 }}>
              <MorpheumLoadingOverlay
                label="Decrypting vault..."
                layout="absolute"
                matrixText={false}
              />
            </div>
          </VariantTile>
        </VariantGrid>
      </DocSection>
    </ComponentDocPage>
  );
}
