const WEIGHTING_METHOD_BY_SLUG: Record<MaexIndexSlug, string> = {
  MAEXGEN: "Deployed capital × confidence × integrity",
  MAEXALP: "Shrunk Sortino × confidence × integrity × capacity",
  MAEXSOC: "Credible skill × saturating social attention",
};

const PRODUCT_WEIGHTING_BY_SLUG: Record<MaexIndexSlug, string> = {
  MAEXGEN: "Weighting: Capital × confidence × integrity",
  MAEXALP: "Weighting: Risk-adjusted skill score",
  MAEXSOC: "Weighting: Skill × social saturation",
};

function buildConstituentsFromSnapshot(
  snapshot: MaexIndexSnapshot,
): PropertyIndexConstituent[] {
  const seedKeys = Object.keys(snapshot.weights);

  return seedKeys.map((seedKey) => {
    const seed = ALL_CATALOG_AGENT_SEEDS.find((entry) => entry.id === seedKey);
    const summary = getAgentKpiSummaryBySeedKey(seedKey);
    const weight = snapshot.weights[seedKey] ?? 0;
    const breakdown = snapshot.scoreBreakdown[seedKey];

    const rationaleParts = [
      breakdown
        ? `κ ${(breakdown.kappa * 100).toFixed(0)}% · integrity ${(breakdown.integrity * 100).toFixed(0)}%`
        : null,
      breakdown?.social != null
        ? `social ${(breakdown.social * 100).toFixed(0)}%`
        : null,
      seed?.strategySummary.slice(0, 48),
    ].filter(Boolean);

    return {
      agentId: seedKey,
      name: seed?.name ?? seedKey,
      ticker: seed?.ticker ?? `$${seedKey.toUpperCase()}`,
      icon: seed?.avatar ?? "🤖",
      sector: seed?.sector ?? "Trading",
      weight,
      revenue30d: summary.revenue30dUsd,
      liquidityScore: Math.round(summary.revenueStability * 100),
      navContribution: snapshot.navContributions[seedKey] ?? 0,
      rationale: rationaleParts.join(" · ") || `${seed?.name ?? seedKey} index constituent.`,
    };
  });
}

function applySnapshotToProfile(
  profile: PropertyIndexProfile,
  slug: MaexIndexSlug,
  row: PropertyIndexRow,
): PropertyIndexProfile {
  const snapshot = getMaexIndexSnapshotBySlug(slug);
  const seedKeys = getIndexConstituentSeedKeys(slug);
  const nav = snapshot.nav;
  const price = row.price;
  const premiumDiscountBasis = Math.round(((price - nav) / nav) * 10000);

  return {
    ...profile,
    constituents: buildConstituentsFromSnapshot(snapshot),
    chartSeries: snapshot.chartSeries,
    weightingMethod: WEIGHTING_METHOD_BY_SLUG[slug],
    methodology: METHODOLOGY_BY_SLUG[slug],
    pricing: {
      ...profile.pricing,
      price,
      nav,
      premiumDiscountBasis,
      basisLabel: buildBasisLabel(price, nav),
    },
    schedule: {
      ...profile.schedule,
      lastRebalance: new Date(snapshot.rebalance.lastAt).toLocaleDateString("en-US", {
        month: "short",
        day: "numeric",
      }),
      nextRebalance: snapshot.rebalance.nextWindow,
    },
    productElements: [
      `Constituents: ${seedKeys.length}`,
      PRODUCT_WEIGHTING_BY_SLUG[slug],
      "Rebalance: Monthly, PoR on-chain mock",
      "NAV oracle: 1h TWAP",
    ],
    modes: profile.modes.map((mode) => ({
      ...mode,
      constituentIds: [...seedKeys],
    })),
    portfolioMock: {
      mint: {
        ...profile.portfolioMock.mint,
        outputMultiplier: 1 / nav,
      },
      redeem: {
        ...profile.portfolioMock.redeem,
        outputMultiplier: nav,
      },
    },
  };
}

