export const DECORATIVE_CARD_WIDTH = 316;
export const DECORATIVE_CARD_HEIGHT = 190;
export const AGENT_ID_BADGE_PASSPORT_HEIGHT = 240;

export interface DecorativeCardScale {
  scale: number | string;
  scaledWidth: number | string;
  scaledHeight: number | string;
}

export function calculateDecorativeCardScale(
  desiredWidth: number | undefined,
  originalWidth = DECORATIVE_CARD_WIDTH,
  originalHeight = DECORATIVE_CARD_HEIGHT,
): DecorativeCardScale {
  if (!desiredWidth) {
    return {
      scale: 1,
      scaledWidth: originalWidth,
      scaledHeight: originalHeight,
    };
  }

  const scale = desiredWidth / originalWidth;
  return {
    scale: scale.toFixed(4),
    scaledWidth: (originalWidth * scale).toFixed(2),
    scaledHeight: (originalHeight * scale).toFixed(2),
  };
}
