import React, {
  useCallback,
  useLayoutEffect,
  useRef,
  useState,
} from "react";
import { flushSync } from "react-dom";
import { measureWrappedText } from "./detectWrappedLines";
import "./typewriter.css";

const DEFAULT_SPEED = 40;
const DEFAULT_CURSOR_WIDTH = 5;
const REVEAL_ANIMATION_NAME = "typewriter-reveal";
const CURSOR_HOLD_MIN_MS = 1_000;
const CURSOR_HOLD_MAX_MS = 4_000;

function randomCursorHoldMs(): number {
  return (
    CURSOR_HOLD_MIN_MS +
    Math.random() * (CURSOR_HOLD_MAX_MS - CURSOR_HOLD_MIN_MS)
  );
}

function prefersReducedMotion(): boolean {
  if (typeof window === "undefined") return false;
  return window.matchMedia("(prefers-reduced-motion: reduce)").matches;
}

export interface TypewriterProps {
  text: string;
  className?: string;
  speed?: number;
  cursorWidth?: number;
  fontSize?: string;
  multiline?: "auto" | boolean;
  /** When false, layout is measured and reserved but typing does not start. */
  active?: boolean;
  /** Pause on the final line before onComplete (default true). */
  holdCursor?: boolean;
  onComplete?: () => void;
}

interface TypewriterLineProps {
  text: string;
  speed: number;
  cursorWidth: number;
  fontSize?: string;
  active: boolean;
  waiting: boolean;
  completed: boolean;
  holdCursor?: boolean;
  onComplete?: () => void;
}

function TypewriterLine({
  text,
  speed,
  cursorWidth,
  fontSize,
  active,
  waiting,
  completed,
  holdCursor = false,
  onComplete,
}: TypewriterLineProps): JSX.Element {
  const ref = useRef<HTMLSpanElement>(null);
  const onCompleteRef = useRef(onComplete);
  const holdTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const holdEndTimeRef = useRef<number | null>(null);
  const holdRemainingRef = useRef<number | null>(null);
  const phaseRef = useRef<"idle" | "animating" | "cursor-hold" | "complete">("idle");
  const [phase, setPhase] = useState<"idle" | "animating" | "cursor-hold" | "complete">("idle");

  onCompleteRef.current = onComplete;

  const clearHoldTimeout = useCallback(() => {
    if (holdTimeoutRef.current) {
      clearTimeout(holdTimeoutRef.current);
      holdTimeoutRef.current = null;
    }
  }, []);

  const finishLine = useCallback(() => {
    clearHoldTimeout();
    holdEndTimeRef.current = null;
    holdRemainingRef.current = null;
    phaseRef.current = "complete";
    setPhase("complete");
    onCompleteRef.current?.();
  }, [clearHoldTimeout]);

  const scheduleHoldFinish = useCallback(
    (delayMs: number) => {
      clearHoldTimeout();
      holdEndTimeRef.current = Date.now() + delayMs;
      holdTimeoutRef.current = setTimeout(finishLine, delayMs);
    },
    [clearHoldTimeout, finishLine],
  );

  useLayoutEffect(() => {
    phaseRef.current = "idle";
    setPhase("idle");
    holdRemainingRef.current = null;
    holdEndTimeRef.current = null;
    clearHoldTimeout();
  }, [text, speed, cursorWidth, clearHoldTimeout]);

  useLayoutEffect(() => {
    if (waiting || completed || phaseRef.current === "complete") return;

    if (!active) {
      if (
        phaseRef.current === "cursor-hold" &&
        holdTimeoutRef.current &&
        holdEndTimeRef.current != null
      ) {
        clearHoldTimeout();
        holdRemainingRef.current = Math.max(0, holdEndTimeRef.current - Date.now());
        holdEndTimeRef.current = null;
      }
      return;
    }

    if (phaseRef.current === "cursor-hold" && !holdTimeoutRef.current) {
      const delayMs = holdRemainingRef.current ?? randomCursorHoldMs();
      holdRemainingRef.current = null;
      scheduleHoldFinish(delayMs);
      return;
    }

    if (phaseRef.current === "animating" || phaseRef.current === "cursor-hold") return;

    if (prefersReducedMotion()) {
      onCompleteRef.current?.();
      return;
    }

    const el = ref.current;
    if (!el || !text) {
      onCompleteRef.current?.();
      return;
    }

    el.style.width = "";
    void el.offsetWidth;

    const durationMs = Math.max((text.length / speed) * 1000, 120);
    const steps = Math.max(text.length, 1);

    const blockEl = el.closest(".typewriter-block");
    const maxWidth = blockEl?.clientWidth ?? el.parentElement?.clientWidth ?? 0;

    el.style.whiteSpace = "nowrap";
    el.style.width = "auto";
    const rawWidth = el.scrollWidth;
    const targetWidth = maxWidth > 0 ? Math.min(rawWidth, maxWidth) : rawWidth;
    el.style.width = "0";

    el.style.setProperty("--tw-duration", `${durationMs}ms`);
    el.style.setProperty("--tw-target-width", `${targetWidth}px`);
    el.style.setProperty("--tw-steps", String(steps));
    el.style.setProperty("--tw-cursor-width", `${cursorWidth}px`);

    void el.offsetWidth;
    phaseRef.current = "animating";
    setPhase("animating");

    const handleAnimationEnd = (event: AnimationEvent) => {
      if (event.animationName !== REVEAL_ANIMATION_NAME) return;

      if (holdCursor) {
        el.style.width = `${targetWidth}px`;
        phaseRef.current = "cursor-hold";
        setPhase("cursor-hold");
        scheduleHoldFinish(randomCursorHoldMs());
        return;
      }

      el.style.width = "";
      finishLine();
    };

    el.addEventListener("animationend", handleAnimationEnd);

    return () => {
      el.removeEventListener("animationend", handleAnimationEnd);
    };
  }, [
    active,
    completed,
    finishLine,
    holdCursor,
    scheduleHoldFinish,
    speed,
    text,
    waiting,
    clearHoldTimeout,
  ]);

  const isAnimating = phase === "animating";
  const isCursorHold = phase === "cursor-hold";
  const isLineComplete = phase === "complete";
  const isPaused =
    !active && !waiting && !completed && !isLineComplete && (isAnimating || isCursorHold);

  const classes = [
    "typewriter",
    "typewriter-line",
    waiting ? "is-waiting" : "",
    isAnimating ? "is-animating" : "",
    isCursorHold ? "is-cursor-hold" : "",
    completed || isLineComplete ? "is-complete" : "",
    isPaused ? "is-paused" : "",
  ]
    .filter(Boolean)
    .join(" ");

  return (
    <span
      ref={ref}
      className={classes}
      style={fontSize ? { fontSize } : undefined}
    >
      {text}
    </span>
  );
}

export function Typewriter({
  text,
  className,
  speed = DEFAULT_SPEED,
  cursorWidth = DEFAULT_CURSOR_WIDTH,
  fontSize,
  multiline = "auto",
  active: animating = true,
  holdCursor = true,
  onComplete,
}: TypewriterProps): JSX.Element {
  const containerRef = useRef<HTMLSpanElement>(null);
  const onCompleteRef = useRef(onComplete);
  const [lines, setLines] = useState<string[]>([]);
  const [blockHeight, setBlockHeight] = useState(0);
  const [activeLineIndex, setActiveLineIndex] = useState(0);
  const [allComplete, setAllComplete] = useState(false);
  const [isMeasured, setIsMeasured] = useState(false);
  const reducedMotion = prefersReducedMotion();

  onCompleteRef.current = onComplete;

  const runDetection = useCallback(() => {
    const el = containerRef.current;
    if (!el || !text) {
      setLines([]);
      setBlockHeight(0);
      setIsMeasured(true);
      return true;
    }

    const width = el.clientWidth;
    if (width < 1) return false;

    const shouldSplit = multiline === "auto" || multiline === true;
    const { lines: detected, blockHeight: measuredHeight } = measureWrappedText(
      text,
      width,
      el,
      shouldSplit && !reducedMotion,
    );

    setLines(detected);
    setBlockHeight(measuredHeight);
    setIsMeasured(true);
    return true;
  }, [text, multiline, reducedMotion]);

  useLayoutEffect(() => {
    setActiveLineIndex(0);
    setAllComplete(false);
    setIsMeasured(false);
    setLines([]);
    setBlockHeight(0);

    if (reducedMotion) {
      onCompleteRef.current?.();
      setIsMeasured(true);
      return;
    }

    if (!text) {
      onCompleteRef.current?.();
      setIsMeasured(true);
      return;
    }

    if (!runDetection()) {
      const observer = new ResizeObserver(() => {
        if (runDetection()) observer.disconnect();
      });
      if (containerRef.current) observer.observe(containerRef.current);
      return () => observer.disconnect();
    }
  }, [text, multiline, runDetection, reducedMotion]);

  const handleLineComplete = useCallback(
    (lineIndex: number) => {
      const isLastLine = lineIndex >= lines.length - 1;
      flushSync(() => {
        if (!isLastLine) {
          setActiveLineIndex(lineIndex + 1);
          return;
        }
        setAllComplete(true);
      });
      if (isLastLine) {
        onCompleteRef.current?.();
      }
    },
    [lines],
  );

  const isMultiline = lines.length > 1;
  const blockClasses = [
    "typewriter-block",
    isMultiline ? "typewriter-lines" : "typewriter-host",
    className ?? "",
    allComplete ? "is-complete" : "",
    !isMeasured ? "is-measuring" : "",
    reducedMotion ? "is-static" : "",
  ]
    .filter(Boolean)
    .join(" ");

  const blockStyle = {
    ...(fontSize ? { fontSize } : undefined),
    ...(!allComplete && !reducedMotion && blockHeight > 0
      ? { height: blockHeight, minHeight: blockHeight }
      : undefined),
  } as React.CSSProperties;

  if (!isMeasured) {
    return (
      <span ref={containerRef} className={blockClasses} style={blockStyle}>
        {text}
      </span>
    );
  }

  if (reducedMotion || !text) {
    return (
      <span
        ref={containerRef}
        className={["typewriter", "is-static", className ?? ""]
          .filter(Boolean)
          .join(" ")}
        style={fontSize ? { fontSize } : undefined}
      >
        {text}
      </span>
    );
  }

  if (allComplete) {
    return (
      <span
        ref={containerRef}
        className={[
          "typewriter-block",
          "typewriter-host",
          "is-complete",
          className ?? "",
        ]
          .filter(Boolean)
          .join(" ")}
        style={{
          ...(fontSize ? { fontSize } : undefined),
          ...(blockHeight > 0
            ? { height: blockHeight, minHeight: blockHeight }
            : undefined),
        }}
      >
        {text}
      </span>
    );
  }

  const renderLines = lines.length > 0 ? lines : [text];

  return (
    <span ref={containerRef} className={blockClasses} style={blockStyle}>
      <span className="typewriter-ghost" aria-hidden>
        {text}
      </span>
      <span className="typewriter-overlay">
        {renderLines.map((line, index) => (
          <TypewriterLine
            key={`${index}-${line}`}
            text={line}
            speed={speed}
            cursorWidth={cursorWidth}
            fontSize={fontSize}
            waiting={index > activeLineIndex}
            active={animating && index === activeLineIndex}
            completed={index < activeLineIndex}
            holdCursor={holdCursor && index === renderLines.length - 1}
            onComplete={
              index === activeLineIndex
                ? () => handleLineComplete(index)
                : undefined
            }
          />
        ))}
      </span>
    </span>
  );
}
