function applyProbeTypography(
  probe: HTMLDivElement,
  style: CSSStyleDeclaration,
  nowrap = false,
): void {
  probe.style.fontFamily = style.fontFamily;
  probe.style.fontSize = style.fontSize;
  probe.style.fontWeight = style.fontWeight;
  probe.style.letterSpacing = style.letterSpacing;
  probe.style.lineHeight = style.lineHeight;
  probe.style.textTransform = style.textTransform;
  probe.style.whiteSpace = nowrap ? "nowrap" : "normal";
  probe.style.wordBreak = nowrap ? "normal" : "break-word";
}

export interface WrappedTextMeasure {
  lines: string[];
  blockHeight: number;
}

function createMeasureProbe(
  text: string,
  maxWidth: number,
  styleSource: HTMLElement,
  splitLines: boolean,
): { probe: HTMLDivElement; textNode: Text } {
  const style = getComputedStyle(styleSource);
  const probe = document.createElement("div");
  probe.style.position = "fixed";
  probe.style.left = "-99999px";
  probe.style.top = "0";
  probe.style.visibility = "hidden";
  probe.style.pointerEvents = "none";
  probe.style.width = `${maxWidth}px`;
  applyProbeTypography(probe, style, !splitLines);

  const textNode = document.createTextNode(text);
  probe.appendChild(textNode);
  document.body.appendChild(probe);

  return { probe, textNode };
}

export function measureWrappedText(
  text: string,
  maxWidth: number,
  styleSource: HTMLElement,
  splitLines = true,
): WrappedTextMeasure {
  if (!text) return { lines: [], blockHeight: 0 };
  if (maxWidth <= 0) return { lines: [text], blockHeight: 0 };

  const { probe, textNode } = createMeasureProbe(
    text,
    maxWidth,
    styleSource,
    splitLines,
  );
  const blockHeight = probe.offsetHeight;

  if (!splitLines) {
    document.body.removeChild(probe);
    return { lines: [text], blockHeight };
  }

  const range = document.createRange();
  const lines: string[] = [];
  let lineStart = 0;
  let previousRectCount = 0;

  for (let i = 1; i <= text.length; i++) {
    range.setStart(textNode, 0);
    range.setEnd(textNode, i);
    const rectCount = range.getClientRects().length;

    if (rectCount > previousRectCount && previousRectCount > 0) {
      lines.push(text.slice(lineStart, i - 1));
      lineStart = i - 1;
    }

    previousRectCount = rectCount;
  }

  if (lineStart < text.length) {
    lines.push(text.slice(lineStart));
  }

  document.body.removeChild(probe);

  return {
    lines: lines.length > 0 ? lines : [text],
    blockHeight,
  };
}

/** @deprecated Prefer measureWrappedText */
export function detectWrappedLines(
  text: string,
  maxWidth: number,
  styleSource: HTMLElement,
): string[] {
  return measureWrappedText(text, maxWidth, styleSource).lines;
}
