import { useState } from "react";

import { MorpheumInlineLoading } from "@mormlayer/components/ui/MorpheumInlineLoading";

import { ComponentDocPage } from "../layout/ComponentDocPage";
import { DocSection } from "../layout/DocSection";
import { PreviewCanvas } from "../layout/PreviewCanvas";
import { VariantGrid, VariantTile } from "../layout/VariantGrid";

export function InlineLoadingPage(): JSX.Element {
  const [message, setMessage] = useState("Loading portfolio...");
  const [matrixText, setMatrixText] = useState(true);

  return (
    <ComponentDocPage
      title="Inline loading"
      description="Inline Morpheum loading indicator with animated logo and optional matrix-style label scramble."
    >
      <DocSection
        title="Default preview"
        description="Default message with matrix text enabled."
      >
        <PreviewCanvas>
          <MorpheumInlineLoading />
        </PreviewCanvas>
      </DocSection>

      <DocSection
        title="Customization"
        description="Edit message text and toggle matrix label animation."
      >
        <div className="uitest-controls">
          <label className="uitest-field">
            <span className="uitest-field__label">Message</span>
            <input
              className="uitest-input"
              value={message}
              onChange={(e) => setMessage(e.target.value)}
            />
          </label>
          <label className="uitest-field uitest-field--checkbox">
            <input
              type="checkbox"
              checked={matrixText}
              onChange={(e) => setMatrixText(e.target.checked)}
            />
            <span className="uitest-field__label">Matrix text</span>
          </label>
        </div>
        <PreviewCanvas minHeight={120}>
          <MorpheumInlineLoading message={message} matrixText={matrixText} />
        </PreviewCanvas>
      </DocSection>

      <DocSection
        title="Matrix text"
        description="Matrix scramble on vs static label."
      >
        <VariantGrid columns={2}>
          <VariantTile label="matrixText on">
            <MorpheumInlineLoading
              message="Syncing agents..."
              matrixText
            />
          </VariantTile>
          <VariantTile label="matrixText off">
            <MorpheumInlineLoading
              message="Syncing agents..."
              matrixText={false}
            />
          </VariantTile>
        </VariantGrid>
      </DocSection>
    </ComponentDocPage>
  );
}
